/// Lightweight multi-scope container for tracking committed block hashes.
///
/// Unlike the full MVCC cells used throughout the world state, block hashes only ever grow
/// monotonically and can be rolled back deterministically by truncating the tail. To avoid
/// blocking read-only state views during block execution, block-scoped access buffers appended
/// hashes and only applies them under a short write lock at commit time.
#[derive(Default)]
pub struct BlockHashes {
    inner: parking_lot::RwLock<Vec<HashOf<BlockHeader>>>,
    committed_height: AtomicUsize,
}

impl BlockHashes {
    /// Construct a new container from an explicit vector.
    pub fn new(initial: Vec<HashOf<BlockHeader>>) -> Self {
        let committed_height = initial.len();
        Self {
            inner: parking_lot::RwLock::new(initial),
            committed_height: AtomicUsize::new(committed_height),
        }
    }

    /// Obtain a block-scoped mutable view of the hashes.
    pub fn block(&self) -> BlockHashesBlock<'_> {
        BlockHashesBlock::new(self, false)
    }

    /// Obtain a block-scoped mutable view after reverting the latest committed block, if any.
    pub fn block_and_revert(&self) -> BlockHashesBlock<'_> {
        BlockHashesBlock::new(self, true)
    }

    /// Obtain a read-only snapshot of the committed hashes.
    pub fn view(&self) -> BlockHashesView<'_> {
        BlockHashesView {
            guard: self.inner.read(),
        }
    }

    /// Return the latest committed height without taking the block-hash read lock.
    pub fn committed_height(&self) -> usize {
        self.committed_height.load(Ordering::Acquire)
    }
}

/// Block-scoped access to the block hash log with staged updates.
pub struct BlockHashesBlock<'a> {
    inner: &'a BlockHashes,
    guard: Option<parking_lot::RwLockReadGuard<'a, Vec<HashOf<BlockHeader>>>>,
    visible_len: usize,
    pending: Vec<HashOf<BlockHeader>>,
    visible: Vec<HashOf<BlockHeader>>,
}

impl<'a> BlockHashesBlock<'a> {
    fn new(inner: &'a BlockHashes, revert_latest: bool) -> Self {
        let guard = inner.inner.read();
        let visible_len = if revert_latest {
            guard.len().saturating_sub(1)
        } else {
            guard.len()
        };
        let visible = guard[..visible_len].to_vec();
        Self {
            inner,
            guard: Some(guard),
            visible_len,
            pending: Vec::new(),
            visible,
        }
    }

    fn as_slice(&self) -> &[HashOf<BlockHeader>] {
        &self.visible
    }

    /// Begin a transaction-scoped view nested under this block.
    pub(crate) fn transaction(&mut self) -> BlockHashesTransaction<'_> {
        let base = self.visible.as_slice();
        let baseline_len = self.pending.len();
        BlockHashesTransaction {
            base,
            pending: &mut self.pending,
            baseline_len,
            applied: false,
        }
    }

    /// Stage a new hash to be appended on commit.
    pub(crate) fn push(&mut self, hash: HashOf<BlockHeader>) {
        self.pending.push(hash);
        self.visible.push(hash);
    }

    /// Stage a new hash in tests/benches without exposing internals broadly.
    pub fn push_for_tests(&mut self, hash: HashOf<BlockHeader>) {
        self.push(hash);
    }

    /// Drop the long-lived snapshot guard before entering state commit.
    ///
    /// Keeping this guard through block execution preserves deterministic snapshot semantics,
    /// but committing while still holding it can deadlock with `view_lock` contention. Call this
    /// before acquiring `view_lock` in commit paths.
    pub(crate) fn prepare_commit(&mut self) {
        self.guard.take();
    }

    /// Commit all mutations performed in this block scope.
    pub(crate) fn commit(mut self) {
        let pending = std::mem::take(&mut self.pending);
        let visible_len = self.visible_len;
        self.guard.take();
        let mut guard = self.inner.inner.write();
        guard.truncate(visible_len);
        guard.extend(pending);
        self.inner
            .committed_height
            .store(guard.len(), Ordering::Release);
    }

    /// Commit mutations in tests without exposing the block hash log publicly.
    pub fn commit_for_tests(self) {
        self.commit();
    }
}

impl std::ops::Deref for BlockHashesBlock<'_> {
    type Target = [HashOf<BlockHeader>];

    #[allow(clippy::explicit_auto_deref)]
    fn deref(&self) -> &Self::Target {
        self.as_slice()
    }
}

/// Transaction-scoped mutable view of the block hash log.
pub struct BlockHashesTransaction<'block> {
    base: &'block [HashOf<BlockHeader>],
    pending: &'block mut Vec<HashOf<BlockHeader>>,
    baseline_len: usize,
    applied: bool,
}

impl BlockHashesTransaction<'_> {
    /// Apply the accumulated mutations so they persist at the parent block scope.
    pub(crate) fn apply(mut self) {
        self.applied = true;
    }
}

impl Drop for BlockHashesTransaction<'_> {
    fn drop(&mut self) {
        if !self.applied {
            self.pending.truncate(self.baseline_len);
        }
    }
}

impl std::ops::Deref for BlockHashesTransaction<'_> {
    type Target = [HashOf<BlockHeader>];

    #[allow(clippy::explicit_auto_deref)]
    fn deref(&self) -> &Self::Target {
        self.base
    }
}

/// Read-only view of the committed block hashes.
pub struct BlockHashesView<'a> {
    guard: parking_lot::RwLockReadGuard<'a, Vec<HashOf<BlockHeader>>>,
}

impl std::ops::Deref for BlockHashesView<'_> {
    type Target = Vec<HashOf<BlockHeader>>;

    #[allow(clippy::explicit_auto_deref)]
    fn deref(&self) -> &Self::Target {
        &*self.guard
    }
}

/// Small per-transaction cache to speed up hot permission checks
/// (e.g., trigger authorization). Built lazily per account.
#[derive(Default, Debug, Clone)]
pub(crate) struct PermissionCheckCache {
    accounts:
        std::collections::BTreeMap<iroha_data_model::account::AccountId, AccountPermissionSummary>,
}

#[derive(Default, Debug, Clone)]
struct AccountPermissionSummary {
    hydrated: bool,
    reg_trigger_authorities: std::collections::BTreeSet<iroha_data_model::account::AccountId>,
    exec_trigger_ids: std::collections::BTreeSet<iroha_data_model::trigger::TriggerId>,
    fee_sponsors: std::collections::BTreeSet<iroha_data_model::account::AccountId>,
}

fn parse_permission_account_field(
    world: &impl WorldReadOnly,
    dataspace_catalog: &iroha_data_model::nexus::DataSpaceCatalog,
    payload: &iroha_primitives::json::Json,
    field: &str,
) -> Option<iroha_data_model::account::AccountId> {
    let value = norito::json::parse_value(payload.get()).ok()?;
    let map = match value {
        norito::json::Value::Object(map) => map,
        _ => return None,
    };
    let entry = map.get(field)?;
    let literal = match entry {
        norito::json::Value::String(value) => value.as_str(),
        _ => return None,
    };
    crate::block::parse_account_literal_with_world(world, dataspace_catalog, literal)
        .map(Into::into)
}

impl AccountPermissionSummary {
    fn clear(&mut self) {
        self.hydrated = false;
        self.reg_trigger_authorities.clear();
        self.exec_trigger_ids.clear();
        self.fee_sponsors.clear();
    }

    fn apply_grant(
        &mut self,
        world: &impl WorldReadOnly,
        dataspace_catalog: &iroha_data_model::nexus::DataSpaceCatalog,
        permission: &Permission,
    ) {
        match permission.name() {
            "CanRegisterTrigger" => {
                if let Some(authority) = parse_permission_account_field(
                    world,
                    dataspace_catalog,
                    permission.payload(),
                    "authority",
                ) {
                    self.reg_trigger_authorities.insert(authority);
                }
            }
            "CanExecuteTrigger" => {
                if let Ok(decoded) = permission
                    .payload()
                    .try_into_any_norito::<CanExecuteTrigger>()
                {
                    self.exec_trigger_ids.insert(decoded.trigger.clone());
                }
            }
            "CanUseFeeSponsor" => {
                if let Some(sponsor) = parse_permission_account_field(
                    world,
                    dataspace_catalog,
                    permission.payload(),
                    "sponsor",
                ) {
                    self.fee_sponsors.insert(sponsor);
                }
            }
            _ => {}
        }
    }
}

impl PermissionCheckCache {
    fn needs_hydration(&self, account: &iroha_data_model::account::AccountId) -> bool {
        self.accounts
            .get(account)
            .is_none_or(|summary| !summary.hydrated)
    }

    fn insert_summary(
        &mut self,
        account: iroha_data_model::account::AccountId,
        mut summary: AccountPermissionSummary,
    ) {
        summary.hydrated = true;
        self.accounts.insert(account, summary);
    }

    fn summary(
        &self,
        account: &iroha_data_model::account::AccountId,
    ) -> Option<&AccountPermissionSummary> {
        self.accounts.get(account)
    }

    fn mark_dirty(&mut self, account: &iroha_data_model::account::AccountId) {
        if let Some(summary) = self.accounts.get_mut(account) {
            summary.clear();
        }
    }

    fn mark_accounts_dirty<'a, I>(&mut self, accounts: I)
    where
        I: IntoIterator<Item = &'a iroha_data_model::account::AccountId>,
    {
        for account in accounts {
            self.mark_dirty(account);
        }
    }
}

/// In-memory cache tracking recent merge-ledger entries.
///
/// The authoritative merge ledger is persisted by Kura. This cache keeps a
/// small rolling window in memory so queries, telemetry, and view observers can
/// access the latest entries without hitting the storage backend.
#[derive(Debug)]
pub struct MergeLedgerStore {
    entries: parking_lot::RwLock<VecDeque<Arc<MergeLedgerEntry>>>,
    max_cached_entries: AtomicUsize,
}

/// Result of inserting a lane relay envelope into the in-memory cache.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum LaneRelayInsert {
    /// New relay accepted for a lane/height.
    Inserted,
    /// Existing relay updated with additional proof material.
    Replaced,
    /// Relay was already present and identical (or strictly less informative).
    Duplicate,
}

/// In-memory store for lane relay envelopes keyed by `(lane, dataspace, height)`.
#[derive(Debug, Default, Clone)]
pub struct LaneRelayStore {
    entries: BTreeMap<(LaneId, DataSpaceId, u64), LaneRelayEnvelope>,
}

impl LaneRelayStore {
    /// Insert or replace a lane relay envelope.
    ///
    /// # Errors
    /// Returns [`LaneRelayError::StaleRelay`] when the relay height regresses and
    /// [`LaneRelayError::ConflictingRelay`] when a different payload is already recorded for the
    /// same lane/height.
    pub fn insert(
        &mut self,
        envelope: LaneRelayEnvelope,
    ) -> Result<LaneRelayInsert, LaneRelayError> {
        let lane = envelope.lane_id;
        let height = envelope.block_height;
        let key = (lane, envelope.dataspace_id, height);

        if let Some(((_, _, latest_height), _)) = self
            .entries
            .range((lane, envelope.dataspace_id, 0)..=(lane, envelope.dataspace_id, u64::MAX))
            .next_back()
        {
            if height < *latest_height {
                return Err(LaneRelayError::StaleRelay {
                    lane,
                    latest_height: *latest_height,
                    new_height: height,
                });
            }
        }

        if let Some(existing) = self.entries.get(&key) {
            if existing.settlement_hash != envelope.settlement_hash
                || existing.block_header.hash() != envelope.block_header.hash()
            {
                return Err(LaneRelayError::ConflictingRelay { lane, height });
            }

            if existing.qc.is_some() && envelope.qc.is_none() {
                return Ok(LaneRelayInsert::Duplicate);
            }
            if existing.qc.is_none() && envelope.qc.is_some() {
                self.entries.insert(key, envelope);
                return Ok(LaneRelayInsert::Replaced);
            }
            if !existing.has_fastpq_proof_material() && envelope.has_fastpq_proof_material() {
                self.entries.insert(key, envelope);
                return Ok(LaneRelayInsert::Replaced);
            }
            if existing == &envelope {
                return Ok(LaneRelayInsert::Duplicate);
            }
            return Err(LaneRelayError::ConflictingRelay { lane, height });
        }

        self.entries.insert(key, envelope);
        Ok(LaneRelayInsert::Inserted)
    }

    /// Return the relay envelope for a lane/height, if any.
    #[must_use]
    pub fn get(
        &self,
        lane_id: LaneId,
        dataspace_id: DataSpaceId,
        height: u64,
    ) -> Option<&LaneRelayEnvelope> {
        self.entries.get(&(lane_id, dataspace_id, height))
    }

    /// Return the highest relay envelope stored for a lane/dataspace pair.
    #[must_use]
    pub fn latest_for_lane_dataspace(
        &self,
        lane_id: LaneId,
        dataspace_id: DataSpaceId,
    ) -> Option<&LaneRelayEnvelope> {
        self.entries
            .range((lane_id, dataspace_id, 0)..=(lane_id, dataspace_id, u64::MAX))
            .next_back()
            .map(|(_, envelope)| envelope)
    }

    /// Return the highest relay envelope that satisfies merge-admission prerequisites.
    #[must_use]
    pub fn latest_merge_admissible_for_lane_dataspace(
        &self,
        lane_id: LaneId,
        dataspace_id: DataSpaceId,
    ) -> Option<&LaneRelayEnvelope> {
        self.entries
            .range((lane_id, dataspace_id, 0)..=(lane_id, dataspace_id, u64::MAX))
            .rev()
            .map(|(_, envelope)| envelope)
            .find(|envelope| envelope.qc.is_some() && envelope.has_fastpq_proof_material())
    }

    /// Snapshot stored envelopes in deterministic order.
    #[must_use]
    pub fn snapshot(&self) -> Vec<LaneRelayEnvelope> {
        self.entries.values().cloned().collect()
    }

    /// Drop cached relay envelopes belonging to retired lanes.
    pub fn prune_lanes(&mut self, retired: &BTreeSet<LaneId>) {
        self.entries
            .retain(|(lane_id, _, _), _| !retired.contains(lane_id));
    }
}

const LANE_RELAY_SEED_DOMAIN: &[u8] = b"iroha:lane-relay:committee-seed:v1";
const LANE_RELAY_MEMBER_DOMAIN: &[u8] = b"iroha:lane-relay:committee-member:v1";

impl MergeLedgerStore {
    /// Default number of merge entries retained in-memory.
    pub const DEFAULT_CACHE_DEPTH: usize = 256;

    /// Instantiate a cache retaining at most `max_cached_entries` records.
    #[must_use]
    pub fn new(max_cached_entries: usize) -> Self {
        Self {
            entries: parking_lot::RwLock::new(VecDeque::new()),
            max_cached_entries: AtomicUsize::new(Self::sanitize_capacity(max_cached_entries)),
        }
    }

    /// Construct a cache using [`Self::DEFAULT_CACHE_DEPTH`].
    #[must_use]
    pub fn with_default_capacity() -> Self {
        Self::new(Self::DEFAULT_CACHE_DEPTH)
    }

    /// Current cache capacity limit.
    #[must_use]
    pub fn cache_capacity(&self) -> usize {
        self.max_cached_entries.load(Ordering::Relaxed)
    }

    /// Update the cache capacity, trimming the oldest entries if the limit shrinks.
    pub fn reconfigure_cache(&self, new_capacity: usize) {
        let capacity = Self::sanitize_capacity(new_capacity);
        self.max_cached_entries.store(capacity, Ordering::Relaxed);
        let mut guard = self.entries.write();
        Self::trim_excess(capacity, &mut guard);
    }

    /// Append a new entry to the cache, evicting the oldest entry if required.
    pub fn push(&self, entry: MergeLedgerEntry) -> Arc<MergeLedgerEntry> {
        let arc = Arc::new(entry);
        let mut guard = self.entries.write();
        guard.push_back(arc.clone());
        let limit = self.max_cached_entries.load(Ordering::Relaxed).max(1);
        Self::trim_excess(limit, &mut guard);
        arc
    }

    /// Replace cache contents with the supplied iterator (assumed oldest → newest).
    pub fn replace<I>(&self, iter: I)
    where
        I: IntoIterator<Item = MergeLedgerEntry>,
    {
        let mut guard = self.entries.write();
        guard.clear();
        let capacity = self.cache_capacity().max(1);
        for entry in iter {
            guard.push_back(Arc::new(entry));
            if guard.len() > capacity {
                guard.pop_front();
            }
        }
    }

    /// Snapshot the cached entries preserving chronological order (oldest first).
    #[must_use]
    pub fn snapshot(&self) -> Vec<Arc<MergeLedgerEntry>> {
        self.entries.read().iter().map(Arc::clone).collect()
    }

    /// Retrieve the latest merge entry if available.
    #[must_use]
    pub fn latest(&self) -> Option<Arc<MergeLedgerEntry>> {
        self.entries.read().back().cloned()
    }

    /// Number of cached entries currently stored.
    #[must_use]
    pub fn len(&self) -> usize {
        self.entries.read().len()
    }

    /// Check whether the cache currently holds any entries.
    #[must_use]
    pub fn is_empty(&self) -> bool {
        self.entries.read().is_empty()
    }

    fn trim_excess(limit: usize, deque: &mut VecDeque<Arc<MergeLedgerEntry>>) {
        let capacity = limit.max(1);
        while deque.len() > capacity {
            deque.pop_front();
        }
    }

    const fn sanitize_capacity(capacity: usize) -> usize {
        if capacity == 0 {
            Self::DEFAULT_CACHE_DEPTH
        } else {
            capacity
        }
    }
}

/// Errors surfaced when committing merge-ledger entries into state.
#[derive(Debug, ThisError)]
pub enum MergeLedgerCommitError {
    /// The merge entry must reference at least one lane.
    #[error("merge ledger entry must include at least one lane")]
    EmptyEntry,
    /// Lane snapshots must be sorted by `(lane_id, dataspace_id)` and unique.
    #[error(
        "merge ledger lane snapshots must be unique and sorted: previous={previous_lane}:{previous_dataspace}, current={current_lane}:{current_dataspace}"
    )]
    LaneSnapshotOrderViolation {
        /// Previous lane identifier encountered while walking the entry payload.
        previous_lane: LaneId,
        /// Previous dataspace identifier encountered while walking the entry payload.
        previous_dataspace: DataSpaceId,
        /// Current lane identifier that violated strict ordering.
        current_lane: LaneId,
        /// Current dataspace identifier that violated strict ordering.
        current_dataspace: DataSpaceId,
    },
    /// Merge QC epoch does not match the entry epoch.
    #[error("merge ledger qc epoch mismatch: entry={entry_epoch}, qc={qc_epoch}")]
    MergeQCEpochMismatch {
        /// Epoch embedded in the merge entry.
        entry_epoch: u64,
        /// Epoch embedded in the merge QC.
        qc_epoch: u64,
    },
    /// Merge QC digest does not match the entry payload.
    #[error("merge ledger qc digest mismatch: expected={expected}, actual={actual}")]
    MergeQCDigestMismatch {
        /// Expected digest computed from the entry payload.
        expected: iroha_crypto::Hash,
        /// Digest supplied by the merge QC.
        actual: iroha_crypto::Hash,
    },
    /// Merge QC signer bitmap length does not match the roster length.
    #[error("merge ledger qc signer bitmap length mismatch: expected={expected}, actual={actual}")]
    MergeQCBitmapLengthMismatch {
        /// Expected bitmap length in bytes.
        expected: usize,
        /// Actual bitmap length in bytes.
        actual: usize,
    },
    /// Merge QC signer index exceeds the roster length.
    #[error("merge ledger qc signer index {signer} out of bounds for roster {roster_len}")]
    MergeQCSignerOutOfBounds {
        /// Signer index referenced by the bitmap.
        signer: usize,
        /// Length of the merge committee roster.
        roster_len: usize,
    },
    /// Merge QC does not meet the quorum threshold.
    #[error("merge ledger qc quorum not met: observed={observed}, required={required}")]
    MergeQCInsufficientQuorum {
        /// Number of signers observed.
        observed: usize,
        /// Minimum quorum required.
        required: usize,
    },
    /// Merge QC did not include an aggregate signature.
    #[error("merge ledger qc aggregate signature missing")]
    MergeQCAggregateSignatureMissing,
    /// Merge QC aggregate signature failed verification.
    #[error("merge ledger qc aggregate signature invalid")]
    MergeQCAggregateSignatureInvalid,
    /// Merge QC requires a non-empty merge committee roster.
    #[error("merge ledger qc requires a non-empty commit topology roster")]
    MergeQCEmptyRoster,
    /// Persistence failure while appending to Kura.
    #[error("merge ledger persistence failed: {0}")]
    Persistence(#[from] crate::kura::Error),
}

/// Errors surfaced when applying lane lifecycle updates.
#[derive(Debug, ThisError)]
pub enum LaneLifecycleError {
    /// Lane lifecycle updates require Nexus to be enabled.
    #[error("lane lifecycle updates require nexus.enabled=true")]
    NexusDisabled,
    /// Lifecycle plan references a dataspace that is not present in the catalog.
    #[error("lane lifecycle plan references unknown dataspace {0}")]
    UnknownDataspace(DataSpaceId),
    /// Invalid lifecycle plan or catalog transition.
    #[error("failed to apply lane lifecycle plan: {0}")]
    Catalog(#[from] iroha_data_model::nexus::LaneCatalogError),
    /// Storage or shard/topology reconciliation failed while applying the lifecycle update.
    #[error("failed to reconcile lane storage: {0}")]
    Storage(String),
}

/// Errors surfaced when computing block inclusion/execution proofs.
#[derive(Copy, Clone, Debug, ThisError)]
pub enum BlockProofError {
    /// Height must be non-zero.
    #[error("block height must be at least 1")]
    ZeroHeight,
    /// Height exceeds usize conversion on the current platform.
    #[error("block height {0} exceeds host pointer width")]
    HeightOutOfRange(NonZeroU64),
    /// Referenced block not found in storage.
    #[error("block {0} not found in Kura")]
    BlockNotFound(NonZeroU64),
    /// Block does not have entrypoint results attached.
    #[error("block {0} is missing execution results")]
    MissingResults(NonZeroU64),
    /// Target entrypoint not present in the block.
    #[error("entrypoint hash {entry_hash:?} not found in block {block_height}")]
    EntrypointNotFound {
        /// Entrypoint hash requested by the caller.
        entry_hash: HashOf<TransactionEntrypoint>,
        /// Height for which the lookup was performed.
        block_height: NonZeroU64,
    },
    /// Execution result is not available for the given entrypoint.
    #[error("execution result missing for entrypoint {entry_hash:?} in block {block_height}")]
    ExecutionResultMissing {
        /// Entrypoint hash requested by the caller.
        entry_hash: HashOf<TransactionEntrypoint>,
        /// Height for which the lookup was performed.
        block_height: NonZeroU64,
    },
    /// Merkle proof could not be constructed for the entrypoint.
    #[error("merkle proof unavailable for entrypoint {entry_hash:?} in block {block_height}")]
    MerkleProofUnavailable {
        /// Entrypoint hash requested by the caller.
        entry_hash: HashOf<TransactionEntrypoint>,
        /// Height for which the lookup was performed.
        block_height: NonZeroU64,
    },
}

