pub enum GovernanceReferendumStatus {
    /// Referendum proposed but not yet open for voting
    Proposed,
    /// Voting open
    Open,
    /// Voting closed (awaiting enactment or finalized)
    Closed,
}

impl json::FastJsonWrite for GovernanceReferendumStatus {
    fn write_json(&self, out: &mut String) {
        let label = match self {
            GovernanceReferendumStatus::Proposed => "Proposed",
            GovernanceReferendumStatus::Open => "Open",
            GovernanceReferendumStatus::Closed => "Closed",
        };
        json::write_json_string(label, out);
    }
}

impl json::JsonDeserialize for GovernanceReferendumStatus {
    fn json_deserialize(parser: &mut json::Parser<'_>) -> Result<Self, json::Error> {
        let value = parser.parse_string()?;
        match value.as_str() {
            "Proposed" => Ok(GovernanceReferendumStatus::Proposed),
            "Open" => Ok(GovernanceReferendumStatus::Open),
            "Closed" => Ok(GovernanceReferendumStatus::Closed),
            other => Err(json::Error::UnknownField {
                field: other.to_owned(),
            }),
        }
    }
}

