    #[test]
    fn public_lane_snapshot_skips_expired_consensus_keys() {
        let kura = crate::kura::Kura::blank_kura_for_testing();
        let query = crate::query::store::LiveQueryStore::start_test();
        let mut state = State::new(World::default(), std::sync::Arc::clone(&kura), query);
        {
            let nexus = state.nexus.get_mut();
            nexus.staking.min_validator_stake = 100;
        }

        let live_kp = KeyPair::random();
        let expired_kp = KeyPair::random();
        let live_validator = DMAccountId::of(live_kp.public_key().clone());
        let expired_validator = DMAccountId::of(expired_kp.public_key().clone());

        let mut wb = state.world.block();
        let live_peer = PeerId::from(live_kp.public_key().clone());
        let expired_peer = PeerId::from(expired_kp.public_key().clone());
        {
            let peers = wb.peers.get_mut();
            let _ = peers.push(live_peer.clone());
            let _ = peers.push(expired_peer.clone());
        }
        seed_consensus_key(&mut wb, &live_peer, ConsensusKeyStatus::Active, 0);
        // Expiry at height 0 ensures the key is considered stale at the current snapshot height.
        let expired_key_id = expired_peer.public_key().to_string();
        let ident = derive_validator_key_id(expired_peer.public_key());
        let expired_record = ConsensusKeyRecord {
            id: ident,
            public_key: expired_peer.public_key().clone(),
            pop: None,
            activation_height: 0,
            expiry_height: Some(0),
            hsm: None,
            replaces: None,
            status: ConsensusKeyStatus::Active,
        };
        wb.consensus_keys
            .insert(expired_record.id.clone(), expired_record.clone());
        wb.consensus_keys_by_pk
            .insert(expired_key_id, vec![expired_record.id.clone()]);

        wb.public_lane_validators.insert(
            (LaneId::SINGLE, live_validator.clone()),
            PublicLaneValidatorRecord {
                lane_id: LaneId::SINGLE,
                validator: live_validator.clone(),
                stake_account: live_validator.clone(),
                total_stake: Numeric::new(1_000, 0),
                self_stake: Numeric::new(1_000, 0),
                metadata: Metadata::default(),
                status: PublicLaneValidatorStatus::Active,
                activation_epoch: None,
                activation_height: None,
                last_reward_epoch: None,
            },
        );
        wb.public_lane_validators.insert(
            (LaneId::SINGLE, expired_validator.clone()),
            PublicLaneValidatorRecord {
                lane_id: LaneId::SINGLE,
                validator: expired_validator.clone(),
                stake_account: expired_validator,
                total_stake: Numeric::new(2_000, 0),
                self_stake: Numeric::new(2_000, 0),
                metadata: Metadata::default(),
                status: PublicLaneValidatorStatus::Active,
                activation_epoch: None,
                activation_height: None,
                last_reward_epoch: None,
            },
        );
        wb.commit();

        let sv = state.view();
        let roster =
            <StateView as StakeSnapshot>::epoch_validator_peer_ids(&sv, 0).expect("roster");
        assert_eq!(roster.len(), 1);
        assert_eq!(roster[0], live_peer);
    }

