    /// Get `Domain` with an ability to modify it.
    ///
    /// # Errors
    /// Fails if there is no domain
    pub fn domain_mut(&mut self, id: &DomainId) -> Result<&mut Domain, FindError> {
        let domain = self
            .domains
            .get_mut(id)
            .ok_or_else(|| FindError::Domain(id.clone()))?;
        Ok(domain)
    }

    /// Get mutable reference to [`Account`]
    ///
    /// # Errors
    /// Fail if domain or account not found
    pub fn account_mut(&mut self, id: &AccountId) -> Result<&mut AccountValue, FindError> {
        self.accounts
            .get_mut(id)
            .ok_or_else(|| FindError::Account(id.clone()))
    }

    fn rebuild_domain_account_subject_index(&mut self) {
        let mut domain_subjects = BTreeMap::<DomainId, BTreeSet<AccountId>>::new();
        let domains = self.domains.view();
        for (subject, linked_domains) in self.account_subject_domains.view().iter() {
            for domain in linked_domains
                .iter()
                .filter(|domain| domains.get(*domain).is_some())
            {
                domain_subjects
                    .entry(domain.clone())
                    .or_default()
                    .insert(subject.clone());
            }
        }
        let existing_domains: Vec<_> = self
            .domain_account_subjects
            .view()
            .iter()
            .map(|(domain, _)| domain.clone())
            .collect();
        for domain in existing_domains {
            self.domain_account_subjects.remove(domain);
        }
        for (domain, subjects) in domain_subjects {
            self.domain_account_subjects.insert(domain, subjects);
        }
    }

    fn sync_account_value_linked_domains(&mut self, subject: &AccountId) {
        let linked_domains = self
            .account_subject_domains
            .get(subject)
            .cloned()
            .unwrap_or_default()
            .into_iter()
            .filter(|domain| self.domains.get(domain).is_some())
            .collect();
        if let Some(details) = self.accounts.get_mut(subject) {
            details.set_linked_domains(linked_domains);
        }
    }

    /// Insert or replace an account and synchronize subject/domain membership indexes.
    pub fn insert_account_with_links(
        &mut self,
        account_id: AccountId,
        account_value: AccountValue,
    ) -> Option<AccountValue> {
        let subject = account_id.subject_id();
        let replaced = self.accounts.insert(account_id, account_value);
        let mut linked_domains = self
            .account_subject_domains
            .get(&subject)
            .cloned()
            .unwrap_or_default();
        if let Some(details) = self.accounts.get(&subject) {
            linked_domains.extend(
                details
                    .linked_domains()
                    .iter()
                    .filter(|domain| self.domains.get(*domain).is_some())
                    .cloned(),
            );
        }
        self.account_subject_domains
            .insert(subject.clone(), linked_domains.clone());
        self.sync_account_value_linked_domains(&subject);
        self.rebuild_domain_account_subject_index();

        replaced
    }

    /// Remove an account and synchronize subject/domain membership indexes.
    pub fn remove_account_with_links(&mut self, account_id: &AccountId) -> Option<AccountValue> {
        let removed = self.accounts.remove(account_id.clone());
        if removed.is_some() {
            let subject = account_id.subject_id();
            let mut linked_domains = self
                .account_subject_domains
                .get(&subject)
                .cloned()
                .unwrap_or_default();
            if let Some(removed_value) = &removed {
                for domain in removed_value
                    .linked_domains()
                    .iter()
                    .filter(|domain| self.domains.get(*domain).is_some())
                {
                    linked_domains.remove(domain);
                }
            }
            self.account_subject_domains
                .insert(subject.clone(), linked_domains);
            self.sync_account_value_linked_domains(&subject);
            self.rebuild_domain_account_subject_index();
        }
        removed
    }

    /// Link a domain-scoped account subject to its domain membership indexes.
    pub fn link_account_subject_domain(&mut self, account_id: &ScopedAccountId) {
        let subject = account_id.subject_id();
        let domain = account_id.domain().clone();
        let mut domains = self
            .account_subject_domains
            .get(&subject)
            .cloned()
            .unwrap_or_default();
        domains.insert(domain);
        self.account_subject_domains
            .insert(subject.clone(), domains);
        self.sync_account_value_linked_domains(&subject);
        self.rebuild_domain_account_subject_index();
    }

    /// Unlink a domain-scoped account subject from its domain membership indexes.
    pub fn unlink_account_subject_domain(&mut self, account_id: &ScopedAccountId) {
        let subject = account_id.subject_id();
        let domain = account_id.domain().clone();
        let mut domains = self
            .account_subject_domains
            .get(&subject)
            .cloned()
            .unwrap_or_default();
        domains.remove(&domain);
        self.account_subject_domains
            .insert(subject.clone(), domains);
        self.sync_account_value_linked_domains(&subject);
        self.rebuild_domain_account_subject_index();
    }

    /// Add [`permission`](Permission) to the [`Account`] if the account does not have this permission yet.
    ///
    /// Return a Boolean value indicating whether or not the  [`Account`] already had this permission.
    pub fn add_account_permission(&mut self, account: &AccountId, token: Permission) -> bool {
        // `match` here instead of `map_or_else` to avoid cloning token into each closure
        match self.account_permissions.get_mut(account) {
            None => {
                self.account_permissions
                    .insert(account.clone(), BTreeSet::from([token]));
                true
            }
            Some(permissions) => {
                if permissions.contains(&token) {
                    return true;
                }
                permissions.insert(token);
                false
            }
        }
    }

    /// Remove a [`permission`](Permission) from the [`Account`] if the account has this permission.
    /// Return a Boolean value indicating whether the [`Account`] had this permission.
    pub fn remove_account_permission(&mut self, account: &AccountId, token: &Permission) -> bool {
        self.account_permissions
            .get_mut(account)
            .is_some_and(|permissions| permissions.remove(token))
    }

    /// Remove all [`Role`]s from the [`Account`]
    pub fn remove_account_roles(&mut self, account: &AccountId) {
        let roles_to_remove = self
            .account_roles_iter(account)
            .map(|role| RoleIdWithOwner::new(account.clone(), role.clone()))
            .collect::<Vec<_>>();

        for role in roles_to_remove {
            self.account_roles.remove(role);
        }
    }

    /// Get mutable reference to [`Asset`]
    ///
    /// # Errors
    /// If domain, account or asset not found
    pub fn asset_mut(&mut self, id: &AssetId) -> Result<&mut AssetValue, FindError> {
        let resolved_id = self
            .resolve_asset_id_for_current_scope(id)
            .unwrap_or_else(|_| id.clone());
        let _ = self.account(resolved_id.account())?;
        self.assets
            .get_mut(&resolved_id)
            .ok_or_else(|| FindError::Asset(resolved_id.into()))
    }

    /// Resolve the balance partition scope for an asset definition in the current execution context.
    ///
    /// # Errors
    /// Returns an error when the definition is missing or when a dataspace-restricted definition
    /// is accessed without an execution dataspace context.
    pub fn resolve_asset_balance_scope(
        &self,
        definition_id: &AssetDefinitionId,
    ) -> Result<AssetBalanceScope, Error> {
        let definition = self.asset_definition(definition_id).map_err(Error::from)?;
        match definition.balance_scope_policy() {
            AssetBalancePolicy::Global => Ok(AssetBalanceScope::Global),
            AssetBalancePolicy::DataspaceRestricted => self
                .current_dataspace_id
                .map(AssetBalanceScope::Dataspace)
                .ok_or_else(|| {
                    Error::InvariantViolation(
                        "dataspace-restricted asset access requires transaction dataspace context"
                            .into(),
                    )
                }),
        }
    }

    /// Canonicalize an [`AssetId`] into the effective execution scope.
    ///
    /// When `dataspace_hint` is provided for a dataspace-restricted asset, it
    /// overrides the ambient execution dataspace. This is used for transfers
    /// whose destination account is bound to a different dataspace than the
    /// caller's current execution scope.
    ///
    /// # Errors
    /// Returns an error when the requested id contradicts the effective scope
    /// policy (for example, cross-dataspace access for restricted assets).
    pub fn resolve_asset_id_for_scope_hint(
        &self,
        id: &AssetId,
        dataspace_hint: Option<DataSpaceId>,
    ) -> Result<AssetId, Error> {
        let definition = self
            .asset_definition(id.definition())
            .map_err(Error::from)?;
        let expected_scope = match definition.balance_scope_policy() {
            AssetBalancePolicy::Global => AssetBalanceScope::Global,
            AssetBalancePolicy::DataspaceRestricted => dataspace_hint
                .or(self.current_dataspace_id)
                .map(AssetBalanceScope::Dataspace)
                .ok_or_else(|| {
                    Error::InvariantViolation(
                        "dataspace-restricted asset access requires transaction dataspace context"
                            .into(),
                    )
                })?,
        };

        match (id.scope(), &expected_scope) {
            (AssetBalanceScope::Global, AssetBalanceScope::Global) => {}
            (AssetBalanceScope::Global, AssetBalanceScope::Dataspace(_)) => {}
            (AssetBalanceScope::Dataspace(_), AssetBalanceScope::Global) => {
                return Err(Error::InvariantViolation(
                    "global assets cannot be addressed with dataspace scope".into(),
                ));
            }
            (AssetBalanceScope::Dataspace(actual), AssetBalanceScope::Dataspace(expected)) => {
                if actual != expected {
                    return Err(Error::InvariantViolation(
                        "dataspace-restricted assets cannot move across dataspaces in normal transfer/mint paths".into(),
                    ));
                }
            }
        }

        Ok(AssetId::with_scope(
            id.definition().clone(),
            id.account().clone(),
            expected_scope,
        ))
    }

    /// Canonicalize an [`AssetId`] into the current execution scope.
    ///
    /// # Errors
    /// Returns an error when the requested id contradicts the active scope policy
    /// (for example, cross-dataspace access for restricted assets).
    pub fn resolve_asset_id_for_current_scope(&self, id: &AssetId) -> Result<AssetId, Error> {
        self.resolve_asset_id_for_scope_hint(id, None)
    }

    /// Get asset or inserts new with `default_asset_value`.
    ///
    /// # Errors
    /// - There is no account with such name.
    #[allow(clippy::missing_panics_doc)]
    pub fn asset_or_insert(
        &mut self,
        asset_id: &AssetId,
        default_asset_value: impl Into<Numeric>,
    ) -> Result<&mut AssetValue, Error> {
        let resolved_id = self.resolve_asset_id_for_current_scope(asset_id)?;
        self.asset_or_insert_exact(&resolved_id, default_asset_value)
    }

    /// Get asset or inserts new with `default_asset_value` using the exact provided [`AssetId`].
    ///
    /// Callers must only use this with a balance id that has already been canonicalized for the
    /// intended scope. This is required for transfer destinations whose bound account dataspace
    /// differs from the current execution dataspace.
    ///
    /// # Errors
    /// - There is no account with such name.
    #[allow(clippy::missing_panics_doc)]
    pub fn asset_or_insert_exact(
        &mut self,
        asset_id: &AssetId,
        default_asset_value: impl Into<Numeric>,
    ) -> Result<&mut AssetValue, Error> {
        let resolved_id = asset_id.clone();
        self.asset_definition(resolved_id.definition())?;
        self.account(resolved_id.account())?;

        if self.assets.get(&resolved_id).is_none() {
            let asset = Asset::new(resolved_id.clone(), default_asset_value.into());

            self.emit_events(Some(AssetEvent::Created(asset.clone())));
            let (asset_id, asset_value) = asset.into_key_value();
            self.track_asset_holder(&asset_id);
            self.assets.insert(asset_id, asset_value);
        }
        Ok(self
            .assets
            .get_mut(&resolved_id)
            .expect("Just inserted, cannot fail."))
    }

    /// Get mutable reference to [`AssetDefinition`]
    ///
    /// # Errors
    /// If domain or asset definition not found
    pub fn asset_definition_mut(
        &mut self,
        id: &AssetDefinitionId,
    ) -> Result<&mut AssetDefinition, FindError> {
        self.asset_definitions
            .get_mut(id)
            .ok_or_else(|| FindError::AssetDefinition(id.clone()))
    }

    /// Increase [`AssetDefinition::total_quantity`] by `increment`.
    ///
    /// This updates the persisted aggregate without re-scanning storage, so it
    /// must be called only after the corresponding individual asset value has
    /// already been updated.
    ///
    /// # Errors
    /// - Asset definition not found
    /// - Overflow on addition
    pub fn increase_asset_total_amount(
        &mut self,
        definition_id: &AssetDefinitionId,
        increment: &Numeric,
    ) -> Result<(), Error> {
        // Update the aggregate based on the stored value rather than recomputing
        // from the current storage view (which would already include the change)
        // to avoid double-counting.
        // Compute and persist the new total first, then emit events.
        let new_total = {
            let def = self.asset_definition_mut(definition_id)?;
            let new_total = def
                .total_quantity
                .clone()
                .checked_add(increment.clone())
                .ok_or(MathError::Overflow)?;
            def.total_quantity = new_total.clone();
            new_total
        };

        debug!(
            target: "iroha::state::asset_totals",
            "increased total quantity for {} by {} -> {}",
            definition_id,
            increment,
            new_total
        );

        self.emit_events({
            Some(DomainEvent::AssetDefinition(
                AssetDefinitionEvent::TotalQuantityChanged(AssetDefinitionTotalQuantityChanged {
                    asset_definition: definition_id.clone(),
                    total_amount: new_total,
                }),
            ))
        });

        Ok(())
    }

    /// Decrease [`AssetDefinition::total_quantity`] by `decrement`.
    ///
    /// This updates the persisted aggregate without re-scanning storage, so it
    /// must be called only after the corresponding individual asset value has
    /// already been updated.
    ///
    /// # Errors
    /// - Asset definition not found
    /// - Underflow (attempt to burn more than exists)
    pub fn decrease_asset_total_amount(
        &mut self,
        definition_id: &AssetDefinitionId,
        decrement: &Numeric,
    ) -> Result<(), Error> {
        // Update the aggregate directly to avoid double-counting when storage
        // has already been mutated by the caller.
        // Compute and persist the new total first, then emit events.
        let new_total = {
            let def = self.asset_definition_mut(definition_id)?;
            let new_total = def
                .total_quantity
                .clone()
                .checked_sub(decrement.clone())
                .ok_or(MathError::NotEnoughQuantity)?;
            def.total_quantity = new_total.clone();
            new_total
        };

        debug!(
            target: "iroha::state::asset_totals",
            "decreased total quantity for {} by {} -> {}",
            definition_id,
            decrement,
            new_total
        );

        self.emit_events({
            Some(DomainEvent::AssetDefinition(
                AssetDefinitionEvent::TotalQuantityChanged(AssetDefinitionTotalQuantityChanged {
                    asset_definition: definition_id.clone(),
                    total_amount: new_total,
                }),
            ))
        });

        Ok(())
    }

