    fn lane_relay_committee_seed(
        &self,
        dataspace_id: DataSpaceId,
        lane_id: LaneId,
        block_height: u64,
    ) -> [u8; 32] {
        let world_view = self.world.view();
        let epoch_seed = crate::sumeragi::npos_seed_for_height_from_world(
            &world_view,
            &self.chain_id,
            block_height,
        );
        let mut buffer = Vec::with_capacity(LANE_RELAY_SEED_DOMAIN.len() + epoch_seed.len() + 12);
        buffer.extend_from_slice(LANE_RELAY_SEED_DOMAIN);
        buffer.extend_from_slice(&epoch_seed);
        buffer.extend_from_slice(&dataspace_id.as_u64().to_le_bytes());
        buffer.extend_from_slice(&lane_id.as_u32().to_le_bytes());
        Hash::new(buffer).into()
    }

    fn lane_relay_committee_from_pool(
        pool: &[AccountId],
        committee_size: usize,
        seed: [u8; 32],
    ) -> Result<Vec<AccountId>, LaneRelayError> {
        let mut scored = Vec::with_capacity(pool.len());
        for validator in pool {
            let mut buffer = Vec::with_capacity(LANE_RELAY_MEMBER_DOMAIN.len() + seed.len());
            buffer.extend_from_slice(LANE_RELAY_MEMBER_DOMAIN);
            buffer.extend_from_slice(&seed);
            let encoded = norito::to_bytes(validator)?;
            buffer.extend_from_slice(&encoded);
            scored.push((Hash::new(buffer), validator.clone()));
        }
        scored.sort_by(|lhs, rhs| lhs.0.cmp(&rhs.0).then_with(|| lhs.1.cmp(&rhs.1)));
        scored.dedup_by(|lhs, rhs| lhs.1 == rhs.1);
        Ok(scored
            .into_iter()
            .take(committee_size)
            .map(|(_, account)| account)
            .collect())
    }

    fn lane_relay_validator_pool(
        &self,
        lane_id: LaneId,
        validator_mode: iroha_config::parameters::actual::LaneValidatorMode,
        manifest_registry: &LaneManifestRegistry,
        nexus: &iroha_config::parameters::actual::Nexus,
    ) -> Vec<AccountId> {
        if let Some(mut validators) = manifest_registry.lane_validators(lane_id) {
            validators.sort();
            validators.dedup();
            return validators;
        }

        if !matches!(
            validator_mode,
            iroha_config::parameters::actual::LaneValidatorMode::StakeElected
        ) {
            return Vec::new();
        }

        let mut candidates: Vec<(AccountId, Numeric)> = self
            .world
            .public_lane_validators
            .view()
            .iter()
            .filter(|((lane, _), record)| {
                *lane == lane_id && matches!(record.status, PublicLaneValidatorStatus::Active)
            })
            .filter_map(|(_, record)| {
                let Ok(meets_min) = crate::smartcontracts::isi::staking::meets_min_stake(
                    &record.self_stake,
                    nexus.staking.min_validator_stake,
                ) else {
                    return None;
                };
                if !meets_min {
                    return None;
                }
                Some((record.validator.clone(), record.total_stake.clone()))
            })
            .collect();
        candidates.sort_by(|lhs, rhs| rhs.1.cmp(&lhs.1).then_with(|| lhs.0.cmp(&rhs.0)));
        candidates.dedup_by(|lhs, rhs| lhs.0 == rhs.0);

        let max = usize::try_from(nexus.staking.max_validators.get())
            .unwrap_or(usize::MAX)
            .min(candidates.len());
        candidates
            .into_iter()
            .take(max)
            .map(|(account, _)| account)
            .collect()
    }

    fn lane_relay_qc_signers(
        world: &impl WorldReadOnly,
        committee: &[AccountId],
        signers_bitmap: &[u8],
    ) -> Result<(Vec<PublicKey>, Vec<Vec<u8>>), LaneRelayError> {
        let expected_len = committee.len().div_ceil(8);
        if signers_bitmap.len() != expected_len {
            return Err(LaneRelayError::SignerBitmapLengthMismatch {
                expected: expected_len,
                actual: signers_bitmap.len(),
            });
        }
        let validator_count = u32::try_from(committee.len()).unwrap_or(u32::MAX);
        let mut public_keys = Vec::new();
        let mut pops = Vec::new();
        for (byte_index, byte) in signers_bitmap.iter().enumerate() {
            if *byte == 0 {
                continue;
            }
            let base = byte_index * 8;
            for bit in 0..8 {
                if byte & (1 << bit) == 0 {
                    continue;
                }
                let signer_index = base + bit;
                if signer_index >= committee.len() {
                    return Err(LaneRelayError::InvalidSignerIndex {
                        signer: u32::try_from(signer_index).unwrap_or(u32::MAX),
                        validator_count,
                    });
                }
                let Some(signatory) = committee[signer_index].try_signatory() else {
                    return Err(LaneRelayError::AggregateSignatureInvalid);
                };
                let (algorithm, _payload) = signatory.to_bytes();
                if algorithm != Algorithm::BlsNormal {
                    return Err(LaneRelayError::AggregateSignatureInvalid);
                }
                let Some(pop) = consensus_key_pop_for_public_key(world, signatory) else {
                    return Err(LaneRelayError::AggregateSignatureInvalid);
                };
                public_keys.push(signatory.clone());
                pops.push(pop);
            }
        }
        Ok((public_keys, pops))
    }

    fn verify_lane_relay_qc(
        &self,
        envelope: &LaneRelayEnvelope,
        committee: &[AccountId],
    ) -> Result<(), LaneRelayError> {
        let qc = envelope.qc.as_ref().ok_or(LaneRelayError::MissingQc)?;
        let world = self.world.view();
        let (public_keys, pops) =
            Self::lane_relay_qc_signers(&world, committee, &qc.aggregate.signers_bitmap)?;
        if public_keys.is_empty() {
            return Err(LaneRelayError::AggregateSignatureInvalid);
        }
        let (status_mode_tag, _, _, _) = crate::sumeragi::status::mode_tags();
        let fallback_mode = if world.sumeragi_npos_parameters().is_some() {
            ConsensusMode::Npos
        } else if status_mode_tag == crate::sumeragi::consensus::NPOS_TAG {
            ConsensusMode::Npos
        } else {
            ConsensusMode::Permissioned
        };
        let derived_mode = crate::sumeragi::effective_consensus_mode_for_height_from_world(
            &world,
            qc.height,
            fallback_mode,
        );
        let derived_mode_tag = match derived_mode {
            ConsensusMode::Permissioned => crate::sumeragi::consensus::PERMISSIONED_TAG,
            ConsensusMode::Npos => crate::sumeragi::consensus::NPOS_TAG,
        };
        let mode_tag = if qc.mode_tag.is_empty() {
            derived_mode_tag
        } else {
            qc.mode_tag.as_str()
        };
        let vote = crate::sumeragi::consensus::Vote {
            phase: qc.phase,
            block_hash: qc.subject_block_hash,
            parent_state_root: qc.parent_state_root,
            post_state_root: qc.post_state_root,
            height: qc.height,
            view: qc.view,
            epoch: qc.epoch,
            highest_qc: None,
            signer: 0,
            bls_sig: Vec::new(),
        };
        let preimage = crate::sumeragi::consensus::vote_preimage(&self.chain_id, mode_tag, &vote);
        let key_refs: Vec<&PublicKey> = public_keys.iter().collect();
        let pop_refs: Vec<&[u8]> = pops.iter().map(Vec::as_slice).collect();
        iroha_crypto::bls_normal_verify_preaggregated_same_message(
            &preimage,
            &qc.aggregate.bls_aggregate_signature,
            &key_refs,
            &pop_refs,
        )
        .map_err(|_| LaneRelayError::AggregateSignatureInvalid)?;
        Ok(())
    }

    /// Record a lane relay envelope in the in-memory store after validation.
    ///
    /// # Errors
    /// Returns a [`LaneRelayError`] when the envelope fails verification.
    #[allow(clippy::too_many_lines)]
    pub fn record_lane_relay(
        &self,
        envelope: &LaneRelayEnvelope,
    ) -> core::result::Result<LaneRelayInsert, LaneRelayError> {
        let nexus = self.nexus_snapshot();
        if !nexus.enabled {
            return Err(LaneRelayError::NexusDisabled);
        }
        let expected_dataspace = nexus
            .lane_config
            .entry(envelope.lane_id)
            .ok_or(LaneRelayError::UnknownLane(envelope.lane_id))?
            .dataspace_id;
        if expected_dataspace != envelope.dataspace_id {
            return Err(LaneRelayError::DataspaceMismatch {
                expected: expected_dataspace,
                actual: envelope.dataspace_id,
            });
        }

        let fault_tolerance = nexus
            .dataspace_catalog
            .entries()
            .iter()
            .find(|entry| entry.id == envelope.dataspace_id)
            .map(|entry| entry.fault_tolerance)
            .ok_or(LaneRelayError::InvalidValidatorSet {
                validator_count: 0,
                min_quorum: 0,
            })?;
        let committee_size = fault_tolerance
            .checked_mul(3)
            .and_then(|value| value.checked_add(1))
            .ok_or(LaneRelayError::InvalidValidatorSet {
                validator_count: u32::MAX,
                min_quorum: 0,
            })?;
        let committee_size =
            usize::try_from(committee_size).map_err(|_| LaneRelayError::InvalidValidatorSet {
                validator_count: u32::MAX,
                min_quorum: 0,
            })?;

        let manifest_registry = self.lane_manifests.read().clone();
        let validator_mode = nexus
            .staking
            .validator_mode(envelope.lane_id, &nexus.lane_catalog);
        let mut validator_pool = self.lane_relay_validator_pool(
            envelope.lane_id,
            validator_mode,
            manifest_registry.as_ref(),
            &nexus,
        );
        let min_quorum = crate::sumeragi::network_topology::commit_quorum_from_len(committee_size);
        if validator_pool.len() < committee_size {
            #[cfg(feature = "telemetry")]
            let mut override_outcome = None;
            #[cfg(feature = "telemetry")]
            let mut set_override_outcome = |value: &'static str| {
                override_outcome = Some(value);
            };
            #[cfg(not(feature = "telemetry"))]
            let set_override_outcome = |_: &'static str| {};
            if !nexus.lane_relay_emergency.enabled {
                set_override_outcome("disabled");
            } else if let Some(record) = self
                .world
                .lane_relay_emergency_validators
                .view()
                .get(&envelope.dataspace_id)
                .cloned()
            {
                if record
                    .expires_at_height
                    .is_some_and(|height| envelope.block_height > height)
                {
                    set_override_outcome("expired");
                } else {
                    validator_pool.extend(record.validators);
                    validator_pool.sort();
                    validator_pool.dedup();
                    if validator_pool.len() < committee_size {
                        set_override_outcome("insufficient");
                    } else {
                        set_override_outcome("applied");
                    }
                }
            } else {
                set_override_outcome("missing");
            }

            #[cfg(feature = "telemetry")]
            if let Some(outcome) = override_outcome {
                self.telemetry.record_lane_relay_emergency_override(
                    envelope.lane_id,
                    envelope.dataspace_id,
                    outcome,
                );
            }

            if validator_pool.len() < committee_size {
                return Err(LaneRelayError::InvalidValidatorSet {
                    validator_count: u32::try_from(validator_pool.len()).unwrap_or(u32::MAX),
                    min_quorum: u32::try_from(min_quorum).unwrap_or(u32::MAX),
                });
            }
        }

        let seed = self.lane_relay_committee_seed(
            envelope.dataspace_id,
            envelope.lane_id,
            envelope.block_height,
        );
        let committee =
            Self::lane_relay_committee_from_pool(&validator_pool, committee_size, seed)?;
        let validator_count =
            u32::try_from(committee.len()).map_err(|_| LaneRelayError::InvalidValidatorSet {
                validator_count: u32::MAX,
                min_quorum: 0,
            })?;
        let committee_quorum =
            crate::sumeragi::network_topology::commit_quorum_from_len(committee.len());
        let quorum = LaneRelayQuorumContext::new(
            validator_count,
            u32::try_from(committee_quorum).unwrap_or(validator_count),
        )?;
        envelope.verify_with_quorum(quorum)?;
        self.verify_lane_relay_qc(envelope, &committee)?;
        envelope.verify_fastpq_proof_material()?;

        let inserted = {
            let mut guard = self.lane_relays.write();
            guard.insert(envelope.clone())?
        };

        if matches!(
            inserted,
            LaneRelayInsert::Inserted | LaneRelayInsert::Replaced
        ) {
            #[cfg(feature = "telemetry")]
            {
                let head_height = u64::try_from(self.block_hashes.view().len()).unwrap_or(0);
                self.telemetry.record_lane_relay_finality(
                    envelope.lane_id,
                    envelope.dataspace_id,
                    envelope.block_height,
                    head_height,
                    envelope.rbc_bytes_total,
                );
            }

            crate::sumeragi::status::push_lane_relay_envelope(envelope.clone());
        }
        Ok(inserted)
    }

    /// Synthesise merge-ledger entry candidates from stored lane relays.
    pub(crate) fn merge_entry_candidates_from_lane_relays(
        &self,
    ) -> Vec<crate::merge::MergeLedgerCandidate> {
        let mut lane_keys: Vec<(LaneId, DataSpaceId)> = {
            let nexus = self.nexus_snapshot();
            if !nexus.enabled {
                return Vec::new();
            }
            nexus
                .lane_config
                .entries()
                .iter()
                .map(|entry| (entry.lane_id, entry.dataspace_id))
                .collect()
        };
        lane_keys.sort_by_key(|(lane_id, dataspace_id)| (lane_id.as_u32(), dataspace_id.as_u64()));
        if lane_keys.is_empty() {
            return Vec::new();
        }

        let latest_merge_entry = self.merge_ledger.latest();
        let next_epoch = latest_merge_entry
            .as_ref()
            .map_or(0, |entry| entry.epoch_id)
            .saturating_add(1);
        let previous_view = latest_merge_entry
            .as_ref()
            .map_or(0, |entry| entry.merge_qc.view);
        let previous_snapshots: BTreeMap<(LaneId, DataSpaceId), MergeLaneSnapshot> =
            latest_merge_entry
                .as_ref()
                .map_or_else(BTreeMap::new, |entry| {
                    entry
                        .lane_snapshots
                        .iter()
                        .map(|snapshot| ((snapshot.lane_id, snapshot.dataspace_id), *snapshot))
                        .collect()
                });

        let mut lane_snapshots = Vec::with_capacity(lane_keys.len());
        let mut advanced = latest_merge_entry.is_none();
        let mut max_view = previous_view;

        {
            let relays = self.lane_relays.read();
            for (lane_id, dataspace_id) in &lane_keys {
                let Some(latest_admissible) =
                    relays.latest_merge_admissible_for_lane_dataspace(*lane_id, *dataspace_id)
                else {
                    return Vec::new();
                };
                if latest_admissible.dataspace_id != *dataspace_id {
                    iroha_logger::warn!(
                        lane_id = %lane_id,
                        expected = %dataspace_id,
                        actual = %latest_admissible.dataspace_id,
                        height = latest_admissible.block_height,
                        "skipping merge entry synthesis due to dataspace mismatch"
                    );
                    return Vec::new();
                }

                let key = (*lane_id, *dataspace_id);
                let selected_snapshot = match previous_snapshots.get(&key).copied() {
                    Some(previous)
                        if previous.lane_block_height >= latest_admissible.block_height =>
                    {
                        previous
                    }
                    _ => {
                        advanced = true;
                        MergeLaneSnapshot {
                            lane_id: *lane_id,
                            dataspace_id: *dataspace_id,
                            lane_block_height: latest_admissible.block_height,
                            tip_hash: latest_admissible.block_header.hash(),
                            merge_hint_root: *latest_admissible.settlement_hash,
                        }
                    }
                };

                let snapshot_view = relays
                    .get(*lane_id, *dataspace_id, selected_snapshot.lane_block_height)
                    .map_or(previous_view, |envelope| {
                        envelope.block_header.view_change_index()
                    });
                max_view = max_view.max(snapshot_view);
                lane_snapshots.push(selected_snapshot);
            }
        }

        if !advanced {
            return Vec::new();
        }

        let merge_hint_roots: Vec<Hash> = lane_snapshots
            .iter()
            .map(|snapshot| snapshot.merge_hint_root)
            .collect();
        let global_state_root = crate::merge::reduce_merge_hint_roots(&merge_hint_roots);
        vec![crate::merge::MergeLedgerCandidate {
            epoch_id: next_epoch,
            view: max_view,
            lane_snapshots,
            global_state_root,
        }]
    }

