    /// Append a merge-ledger entry to the in-memory cache and persist it via Kura.
    ///
    /// # Errors
    /// Returns an error if the supplied entry is invalid or persistence fails.
    pub fn commit_merge_entry(
        &self,
        entry: MergeLedgerEntry,
    ) -> core::result::Result<Arc<MergeLedgerEntry>, MergeLedgerCommitError> {
        const STATE_VIEW_LOCK_THRESHOLD: Duration = Duration::from_millis(10);
        if entry.lane_snapshots.is_empty() {
            return Err(MergeLedgerCommitError::EmptyEntry);
        }
        let mut prev_key: Option<(LaneId, DataSpaceId)> = None;
        for snapshot in &entry.lane_snapshots {
            let key = (snapshot.lane_id, snapshot.dataspace_id);
            if let Some(prev) = prev_key
                && key <= prev
            {
                return Err(MergeLedgerCommitError::LaneSnapshotOrderViolation {
                    previous_lane: prev.0,
                    previous_dataspace: prev.1,
                    current_lane: key.0,
                    current_dataspace: key.1,
                });
            }
            prev_key = Some(key);
        }
        self.validate_merge_quorum_certificate(&entry)?;

        let event_entry = entry.clone();
        self.kura.append_merge_entry(&entry)?;

        let stored_entry = {
            let view_lock_wait_start = Instant::now();
            let _view_lock = self.view_lock.write();
            let view_lock_wait = view_lock_wait_start.elapsed();
            let view_lock_hold_start = Instant::now();
            let stored_entry = self.merge_ledger.push(entry);
            self.update_merge_metadata(stored_entry.as_ref());
            let view_lock_hold = view_lock_hold_start.elapsed();
            if view_lock_wait >= STATE_VIEW_LOCK_THRESHOLD
                || view_lock_hold >= STATE_VIEW_LOCK_THRESHOLD
            {
                debug!(
                    view_lock_wait_us = view_lock_wait.as_micros(),
                    view_lock_hold_us = view_lock_hold.as_micros(),
                    "state view_lock write held (merge_ledger commit)"
                );
            }
            stored_entry
        };
        {
            let mut events = self.world.external_event_buf.block();
            events.push(EventBox::Pipeline(PipelineEventBox::from(
                MergeLedgerEvent { entry: event_entry },
            )));
            events.commit();
        }
        #[cfg(feature = "telemetry")]
        {
            self.telemetry
                .record_merge_ledger_entry(stored_entry.epoch_id, &stored_entry.global_state_root);
        }
        Ok(stored_entry)
    }

    fn validate_merge_quorum_certificate(
        &self,
        entry: &MergeLedgerEntry,
    ) -> Result<(), MergeLedgerCommitError> {
        let qc = &entry.merge_qc;
        if qc.epoch_id != entry.epoch_id {
            return Err(MergeLedgerCommitError::MergeQCEpochMismatch {
                entry_epoch: entry.epoch_id,
                qc_epoch: qc.epoch_id,
            });
        }
        let candidate = crate::merge::MergeLedgerCandidate::from(entry);
        let expected = crate::merge::merge_qc_message_digest(&self.chain_id, &candidate);
        if expected != qc.message_digest {
            return Err(MergeLedgerCommitError::MergeQCDigestMismatch {
                expected,
                actual: qc.message_digest,
            });
        }

        let commit_topology = self.commit_topology.view();
        let roster_len = commit_topology.len();
        if roster_len == 0 {
            return Err(MergeLedgerCommitError::MergeQCEmptyRoster);
        }
        let expected_len = roster_len.div_ceil(8);
        if qc.signers_bitmap.len() != expected_len {
            return Err(MergeLedgerCommitError::MergeQCBitmapLengthMismatch {
                expected: expected_len,
                actual: qc.signers_bitmap.len(),
            });
        }

        let mut signers: Vec<usize> = Vec::new();
        for (byte_idx, byte) in qc.signers_bitmap.iter().enumerate() {
            for bit in 0u8..8 {
                if byte & (1u8 << bit) == 0 {
                    continue;
                }
                let idx = byte_idx * 8 + usize::from(bit);
                if idx >= roster_len {
                    return Err(MergeLedgerCommitError::MergeQCSignerOutOfBounds {
                        signer: idx,
                        roster_len,
                    });
                }
                signers.push(idx);
            }
        }

        let required = crate::sumeragi::network_topology::commit_quorum_from_len(roster_len);
        if signers.len() < required {
            return Err(MergeLedgerCommitError::MergeQCInsufficientQuorum {
                observed: signers.len(),
                required,
            });
        }
        if qc.aggregate_signature.is_empty() {
            return Err(MergeLedgerCommitError::MergeQCAggregateSignatureMissing);
        }

        let world = self.world.view();
        let mut public_keys: Vec<&PublicKey> = Vec::with_capacity(signers.len());
        let mut pops = Vec::with_capacity(signers.len());
        for signer in &signers {
            let Some(peer) = commit_topology.get().get(*signer) else {
                return Err(MergeLedgerCommitError::MergeQCSignerOutOfBounds {
                    signer: *signer,
                    roster_len,
                });
            };
            let pk = peer.public_key();
            let Some(pop) = consensus_key_pop_for_public_key(&world, pk) else {
                return Err(MergeLedgerCommitError::MergeQCAggregateSignatureInvalid);
            };
            public_keys.push(pk);
            pops.push(pop);
        }

        let pop_refs: Vec<&[u8]> = pops.iter().map(Vec::as_slice).collect();
        iroha_crypto::bls_normal_verify_preaggregated_same_message(
            qc.message_digest.as_ref(),
            &qc.aggregate_signature,
            &public_keys,
            &pop_refs,
        )
        .map_err(|_| MergeLedgerCommitError::MergeQCAggregateSignatureInvalid)?;

        Ok(())
    }

    fn refresh_merge_metadata_from_latest_entry(&self) {
        if let Some(entry) = self.merge_ledger.latest() {
            self.update_merge_metadata(entry.as_ref());
        } else {
            let should_clear_roots = {
                let current = self.world.merge_hint_roots.view();
                !current.is_empty()
            };
            if should_clear_roots {
                let mut block = self.world.merge_hint_roots.block();
                {
                    let mut tx = block.transaction();
                    tx.clear();
                    tx.apply();
                }
                block.commit();
            }
            let should_clear_global = {
                let current = self.world.merge_global_state_root.view();
                current.is_some()
            };
            if should_clear_global {
                self.replace_merge_global_state_root(None);
            }
        }
    }

    fn update_merge_metadata(&self, entry: &MergeLedgerEntry) {
        let entry_merge_hint_roots = entry.merge_hint_roots();
        let should_update_roots = {
            let current = self.world.merge_hint_roots.view();
            current.as_slice() != entry_merge_hint_roots.as_slice()
        };
        if should_update_roots {
            let mut block = self.world.merge_hint_roots.block();
            {
                let mut tx = block.transaction();
                tx.clear();
                tx.extend(entry_merge_hint_roots.iter().copied());
                tx.apply();
            }
            block.commit();
        }

        let should_update_global = {
            let current = self.world.merge_global_state_root.view();
            current.as_ref() != Some(&entry.global_state_root)
        };
        if should_update_global {
            self.replace_merge_global_state_root(Some(entry.global_state_root));
        }
    }

    fn replace_merge_global_state_root(&self, new_root: Option<Hash>) {
        let mut block = self.world.merge_global_state_root.block();
        {
            let mut tx = block.transaction();
            *tx = new_root;
            tx.apply();
        }
        block.commit();
    }

    /// Access the current cryptography configuration snapshot.
    pub fn crypto(&self) -> Arc<iroha_config::parameters::actual::Crypto> {
        self.crypto.read().clone()
    }

    /// Update cryptography settings using loaded configuration.
    pub fn set_crypto(&self, crypto: iroha_config::parameters::actual::Crypto) {
        Self::apply_crypto_runtime(&crypto);
        self.commit_crypto_snapshot(crypto);
    }

    /// Update the default domain label used when encoding/compressing account addresses.
    ///
    /// # Errors
    /// Returns `DefaultDomainLabelError` if the provided label is not a valid domain name.
    pub fn set_default_account_domain_label(
        &self,
        label: impl Into<String>,
    ) -> Result<(), iroha_data_model::account::address::DefaultDomainLabelError> {
        iroha_data_model::account::address::set_default_domain_name(label.into()).map(|_| ())
    }

    #[cfg(feature = "telemetry")]
    fn commit_crypto_snapshot(&self, crypto: iroha_config::parameters::actual::Crypto) {
        *self.crypto.write() = Arc::new(crypto);
    }

    #[cfg(not(feature = "telemetry"))]
    fn commit_crypto_snapshot(&self, crypto: iroha_config::parameters::actual::Crypto) {
        *self.crypto.write() = Arc::new(crypto);
    }

    #[cfg(feature = "sm")]
    fn apply_crypto_runtime(crypto: &iroha_config::parameters::actual::Crypto) {
        let intrinsic_policy = match crypto.sm_intrinsics {
            iroha_config::parameters::actual::SmIntrinsicsPolicy::Auto => SmIntrinsicPolicy::Auto,
            iroha_config::parameters::actual::SmIntrinsicsPolicy::ForceEnable => {
                SmIntrinsicPolicy::ForceEnable
            }
            iroha_config::parameters::actual::SmIntrinsicsPolicy::ForceDisable => {
                SmIntrinsicPolicy::ForceDisable
            }
        };
        iroha_crypto::sm::set_intrinsic_policy(intrinsic_policy);
        iroha_crypto::sm::Sm2PublicKey::set_default_distid(crypto.sm2_distid_default.clone())
            .expect("sm2_distid_default must be valid");
        #[cfg(feature = "sm-ffi-openssl")]
        iroha_crypto::sm::OpenSslProvider::set_preview_enabled(crypto.enable_sm_openssl_preview);
    }

    #[cfg(not(feature = "sm"))]
    fn apply_crypto_runtime(_crypto: &iroha_config::parameters::actual::Crypto) {
        #[cfg(feature = "sm-ffi-openssl")]
        iroha_crypto::sm::OpenSslProvider::set_preview_enabled(_crypto.enable_sm_openssl_preview);
    }

    /// Update consensus policy parameters sourced from configuration.
    pub fn set_sumeragi_parameters(&mut self, sumeragi: impl Into<self::SumeragiPolicyConfig>) {
        let policy = sumeragi.into();
        let mut params_block = self.world.parameters.block();
        let mut sys = params_block.sumeragi.clone();
        // Keep collector topology (`collectors_k`, `collectors_redundant_send_r`) anchored to
        // on-chain values. Overwriting these from local config causes handshake fingerprint drift
        // after restart because genesis metadata is derived from chain parameters.
        sys.da_enabled = policy.policy_flags.da_enabled();
        sys.key_activation_lead_blocks = policy.key_activation_lead_blocks;
        sys.key_overlap_grace_blocks = policy.key_overlap_grace_blocks;
        sys.key_expiry_grace_blocks = policy.key_expiry_grace_blocks;
        sys.key_require_hsm = policy.policy_flags.key_require_hsm();
        sys.key_allowed_algorithms = policy.key_allowed_algorithms.iter().copied().collect();
        sys.key_allowed_hsm_providers = policy.key_allowed_hsm_providers.iter().cloned().collect();
        params_block.sumeragi = sys;
        params_block.commit();
    }

    /// Update deterministic pacing governor configuration from runtime config.
    pub fn set_sumeragi_pacing_governor(
        &mut self,
        pacing_governor: iroha_config::parameters::actual::SumeragiPacingGovernor,
    ) {
        self.pacing_governor = pacing_governor;
    }

    /// Update pipeline preferences using a loaded configuration.
    pub fn set_pipeline(&mut self, pipeline: iroha_config::parameters::actual::Pipeline) {
        self.pipeline = pipeline;
        self.pipeline_parallelism = PipelineParallelism::new(&self.pipeline);
        self.stateless_validation_cache
            .lock()
            .set_cap(self.pipeline.stateless_cache_cap);
        *self.trigger_ivm_cache.lock() = IvmCache::with_capacity(self.pipeline.cache_size);
        // Configure the IVM global pre-decode cache from pipeline settings.
        ivm::ivm_cache::configure_limits(ivm::ivm_cache::CacheLimits {
            capacity: self.pipeline.cache_size,
            max_bytes: self.pipeline.ivm_cache_max_bytes,
            max_decoded_ops: self.pipeline.ivm_cache_max_decoded_ops,
        });
        ivm::zk::set_prover_threads(self.pipeline.ivm_prover_threads);
    }

