    fn build_state_with_vk_order(order: &[(&str, &str)]) -> State {
        let mut world = World::new();
        for &(name, circuit) in order {
            let id = iroha_data_model::proof::VerifyingKeyId::new("halo2/ipa", name);
            let (schema_hash, commitment) = match name {
                "vk_alpha" => ([0xA1; 32], [0xB1; 32]),
                "vk_beta" => ([0xA2; 32], [0xB2; 32]),
                other => {
                    let mut schema = [0u8; 32];
                    let mut commit = [0u8; 32];
                    let bytes = other.as_bytes();
                    let len = bytes.len().min(32);
                    schema[..len].copy_from_slice(&bytes[..len]);
                    commit[..len].copy_from_slice(&bytes[..len]);
                    (schema, commit)
                }
            };
            let mut record = iroha_data_model::proof::VerifyingKeyRecord::new_with_owner(
                1,
                circuit,
                None,
                "core",
                iroha_data_model::zk::BackendTag::Halo2IpaPasta,
                "pallas",
                schema_hash,
                commitment,
            );
            record.status = iroha_data_model::confidential::ConfidentialStatus::Active;
            record.public_inputs_schema_hash = schema_hash;
            record.gas_schedule_id = Some(format!("sched_{name}"));
            world.verifying_keys.insert(id, record);
        }
        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        State::new_for_testing(world, kura, query_handle)
    }

