    #[test]
    fn enforce_nexus_storage_budget_prunes_spools_before_cold() {
        let temp_dir = tempfile::tempdir().expect("temp dir");
        let store_root = temp_dir.path().join("kura");
        let soranet_spool = temp_dir.path().join("soranet");
        let soravpn_spool = temp_dir.path().join("soravpn");
        let cold_root = temp_dir.path().join("cold");

        std::fs::create_dir_all(&soranet_spool).expect("create soranet spool");
        std::fs::write(soranet_spool.join("b-file.norito"), vec![0u8; 60])
            .expect("write spool file");
        std::fs::write(soranet_spool.join("a-file.norito"), vec![0u8; 60])
            .expect("write spool file");

        let snapshot_dir = cold_root.join("00000000000000000001");
        std::fs::create_dir_all(&snapshot_dir).expect("create snapshot dir");
        std::fs::write(snapshot_dir.join("payload.norito"), vec![0u8; 50])
            .expect("write cold payload");

        let kura_cfg = KuraConfig {
            init_mode: InitMode::Strict,
            store_dir: WithOrigin::inline(store_root),
            max_disk_usage_bytes: iroha_config::parameters::defaults::kura::MAX_DISK_USAGE_BYTES,
            blocks_in_memory: iroha_config::parameters::defaults::kura::BLOCKS_IN_MEMORY,
            debug_output_new_blocks: false,
            merge_ledger_cache_capacity:
                iroha_config::parameters::defaults::kura::MERGE_LEDGER_CACHE_CAPACITY,
            fsync_mode: iroha_config::kura::FsyncMode::Batched,
            fsync_interval: iroha_config::parameters::defaults::kura::FSYNC_INTERVAL,
            block_sync_roster_retention:
                iroha_config::parameters::defaults::kura::BLOCK_SYNC_ROSTER_RETENTION,
            roster_sidecar_retention:
                iroha_config::parameters::defaults::kura::ROSTER_SIDECAR_RETENTION,
        };
        let (kura, _) = Kura::new(&kura_cfg, &RuntimeLaneConfig::default()).expect("init kura");
        let query_handle = LiveQueryStore::start_test();
        let mut state = State::new_for_testing(World::default(), kura, query_handle);

        let mut streaming = state.streaming.clone();
        streaming.soranet.provision_spool_dir = soranet_spool.clone();
        streaming.soravpn.provision_spool_dir = soravpn_spool.clone();
        state.set_streaming(streaming);

        state.set_tiered_backend(&iroha_config::parameters::actual::TieredState {
            enabled: true,
            hot_retained_keys: 0,
            hot_retained_bytes: iroha_config::base::util::Bytes(0),
            hot_retained_grace_snapshots: 0,
            cold_store_root: Some(cold_root.clone()),
            da_store_root: None,
            max_snapshots: 0,
            max_cold_bytes: iroha_config::base::util::Bytes(0),
        });

        let oldest_spool_size = std::fs::metadata(soranet_spool.join("a-file.norito"))
            .expect("stat soranet spool file")
            .len();
        let kura_used = state.kura.disk_usage_bytes().expect("measure kura bytes");
        let soranet_used = dir_size(&soranet_spool).expect("measure soranet spool");
        let soravpn_used = dir_size(&soravpn_spool).expect("measure soravpn spool");
        let cold_used = {
            let backend = state.tiered_backend.lock();
            backend
                .cold_store_bytes()
                .expect("measure cold store bytes")
                .unwrap_or(0)
        };
        let total_used = kura_used
            .saturating_add(cold_used)
            .saturating_add(soranet_used)
            .saturating_add(soravpn_used);
        // Leave a deficit smaller than one spool entry so only the oldest entry is evicted.
        let desired_excess = oldest_spool_size.saturating_sub(1).max(1);
        let max_disk_usage = total_used.saturating_sub(desired_excess);

        let nexus = iroha_config::parameters::actual::Nexus {
            enabled: true,
            storage: iroha_config::parameters::actual::NexusStorage {
                max_disk_usage_bytes: iroha_config::base::util::Bytes(max_disk_usage),
                budget_enforce_interval_blocks: 0,
                ..Default::default()
            },
            ..Default::default()
        };
        state.set_nexus(nexus).expect("apply nexus config");

        state.enforce_nexus_storage_budget(1);

        assert!(
            !soranet_spool.join("a-file.norito").exists(),
            "oldest spool entry should be evicted"
        );
        assert!(
            soranet_spool.join("b-file.norito").exists(),
            "newer spool entry should remain"
        );
        assert!(snapshot_dir.exists(), "cold snapshot should remain");
    }

    #[test]
    fn enforce_nexus_storage_budget_respects_interval_blocks() {
        let temp_dir = tempfile::tempdir().expect("temp dir");
        let store_root = temp_dir.path().join("kura");
        let soranet_spool = temp_dir.path().join("soranet");

        std::fs::create_dir_all(&soranet_spool).expect("create soranet spool");
        let spool_file = soranet_spool.join("a-file.norito");
        std::fs::write(&spool_file, vec![0u8; 60]).expect("write spool file");

        let kura_cfg = KuraConfig {
            init_mode: InitMode::Strict,
            store_dir: WithOrigin::inline(store_root),
            max_disk_usage_bytes: iroha_config::parameters::defaults::kura::MAX_DISK_USAGE_BYTES,
            blocks_in_memory: iroha_config::parameters::defaults::kura::BLOCKS_IN_MEMORY,
            debug_output_new_blocks: false,
            merge_ledger_cache_capacity:
                iroha_config::parameters::defaults::kura::MERGE_LEDGER_CACHE_CAPACITY,
            fsync_mode: iroha_config::kura::FsyncMode::Batched,
            fsync_interval: iroha_config::parameters::defaults::kura::FSYNC_INTERVAL,
            block_sync_roster_retention:
                iroha_config::parameters::defaults::kura::BLOCK_SYNC_ROSTER_RETENTION,
            roster_sidecar_retention:
                iroha_config::parameters::defaults::kura::ROSTER_SIDECAR_RETENTION,
        };
        let (kura, _) = Kura::new(&kura_cfg, &RuntimeLaneConfig::default()).expect("init kura");
        let query_handle = LiveQueryStore::start_test();
        let mut state = State::new_for_testing(World::default(), kura, query_handle);

        let mut streaming = state.streaming.clone();
        streaming.soranet.provision_spool_dir = soranet_spool.clone();
        state.set_streaming(streaming);

        let kura_used = state.kura.disk_usage_bytes().expect("measure kura bytes");
        let soranet_used = dir_size(&soranet_spool).expect("measure soranet spool");
        let total_used = kura_used.saturating_add(soranet_used);
        let interval_blocks = 10;

        let nexus_ok = iroha_config::parameters::actual::Nexus {
            enabled: true,
            storage: iroha_config::parameters::actual::NexusStorage {
                max_disk_usage_bytes: iroha_config::base::util::Bytes(total_used),
                budget_enforce_interval_blocks: interval_blocks,
                ..Default::default()
            },
            ..Default::default()
        };
        state.set_nexus(nexus_ok).expect("apply nexus config");
        state.enforce_nexus_storage_budget(1);
        assert!(
            spool_file.exists(),
            "spool entry should remain under budget"
        );

        let max_disk_usage = total_used.saturating_sub(1).max(1);
        {
            let mut nexus = state.nexus.write();
            nexus.storage.max_disk_usage_bytes = iroha_config::base::util::Bytes(max_disk_usage);
        }
        state.enforce_nexus_storage_budget(2);
        assert!(spool_file.exists(), "spool eviction should be deferred");

        state.enforce_nexus_storage_budget(11);
        assert!(
            !spool_file.exists(),
            "spool entry should be evicted once interval passes"
        );
    }

    #[test]
    fn lane_topology_diff_marks_alias_changes_for_relabel() {
        let lane_count = nonzero!(1_u32);
        let initial_catalog = LaneCatalog::new(
            lane_count,
            vec![LaneConfig {
                alias: "Alpha Lane".to_string(),
                ..LaneConfig::default()
            }],
        )
        .expect("initial catalog");
        let updated_catalog = LaneCatalog::new(
            lane_count,
            vec![LaneConfig {
                alias: "Payments Lane".to_string(),
                ..LaneConfig::default()
            }],
        )
        .expect("updated catalog");

        let previous = RuntimeLaneConfig::from_catalog(&initial_catalog);
        let current = RuntimeLaneConfig::from_catalog(&updated_catalog);

        let diff = super::lane_topology_diff(&previous, &current);
        assert!(diff.added.is_empty(), "alias change should not add lanes");
        assert!(
            diff.retired.is_empty(),
            "alias change should not retire lanes"
        );
        assert_eq!(diff.relabelled.len(), 1, "lane should be relabelled");
        assert_eq!(diff.relabelled[0].0.alias, "Alpha Lane");
        assert_eq!(diff.relabelled[0].1.alias, "Payments Lane");
    }

