    fn install_lane_manifest_registry(
        state: &State,
        lanes: &[(LaneId, DataSpaceId, Vec<AccountId>)],
    ) {
        let mut statuses = BTreeMap::new();
        for (lane_id, dataspace_id, validators) in lanes {
            let rules = GovernanceRules {
                validators: validators.clone(),
                ..GovernanceRules::default()
            };
            let status = LaneManifestStatus {
                lane: *lane_id,
                alias: format!("lane-{}", lane_id.as_u32()),
                dataspace: *dataspace_id,
                visibility: LaneVisibility::Public,
                storage: LaneStorageProfile::FullReplica,
                governance: Some("parliament".to_string()),
                manifest_path: Some(std::path::PathBuf::from("/tmp/manifest.json")),
                governance_rules: Some(rules),
                privacy_commitments: Vec::new(),
            };
            statuses.insert(*lane_id, status);
        }
        let registry = Arc::new(LaneManifestRegistry::from_statuses(statuses));
        state.install_lane_manifests(&registry);
    }

    fn bls_account_in(_domain: &str) -> (AccountId, KeyPair) {
        let keypair = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
        let account_id = AccountId::new(keypair.public_key().clone());
        (account_id, keypair)
    }

    fn bls_accounts_in(domain: &str, count: usize) -> (Vec<AccountId>, Vec<KeyPair>) {
        let mut accounts = Vec::with_capacity(count);
        let mut keypairs = Vec::with_capacity(count);
        for _ in 0..count {
            let (account_id, keypair) = bls_account_in(domain);
            accounts.push(account_id);
            keypairs.push(keypair);
        }
        (accounts, keypairs)
    }

    fn seed_consensus_keys_with_pops(state: &State, keypairs: &[KeyPair]) {
        let mut world_block = state.world.block();
        for keypair in keypairs {
            let pop = iroha_crypto::bls_normal_pop_prove(keypair.private_key())
                .expect("generate pop for consensus key");
            let id = derive_validator_key_id(keypair.public_key());
            let record = ConsensusKeyRecord {
                id: id.clone(),
                public_key: keypair.public_key().clone(),
                pop: Some(pop),
                activation_height: 0,
                expiry_height: None,
                hsm: None,
                replaces: None,
                status: ConsensusKeyStatus::Active,
            };
            world_block
                .consensus_keys
                .insert(id.clone(), record.clone());
            let pk = record.public_key.to_string();
            let mut by_pk = world_block
                .consensus_keys_by_pk
                .get(&pk)
                .cloned()
                .unwrap_or_default();
            if !by_pk.contains(&record.id) {
                by_pk.push(record.id.clone());
                world_block.consensus_keys_by_pk.insert(pk, by_pk);
            }
        }
        world_block.commit();
    }

    fn commit_qc_with_signers(
        header: &BlockHeader,
        parent_state_root: Hash,
        post_state_root: Hash,
        signers: &[&KeyPair],
        signers_bitmap: Vec<u8>,
    ) -> Qc {
        let validator_set: Vec<_> = signers
            .iter()
            .map(|keypair| PeerId::new(keypair.public_key().clone()))
            .collect();
        let mut qc = Qc {
            phase: crate::sumeragi::consensus::Phase::Commit,
            subject_block_hash: header.hash(),
            parent_state_root,
            post_state_root,
            height: header.height().get(),
            view: 0,
            epoch: 0,
            mode_tag: crate::sumeragi::consensus::PERMISSIONED_TAG.to_string(),
            highest_qc: None,
            validator_set_hash: HashOf::new(&validator_set),
            validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
            validator_set,
            aggregate: crate::sumeragi::consensus::QcAggregate {
                signers_bitmap: Vec::new(),
                bls_aggregate_signature: Vec::new(),
            },
        };
        let vote = crate::sumeragi::consensus::Vote {
            phase: qc.phase,
            block_hash: qc.subject_block_hash,
            parent_state_root: qc.parent_state_root,
            post_state_root: qc.post_state_root,
            height: qc.height,
            view: qc.view,
            epoch: qc.epoch,
            highest_qc: None,
            signer: 0,
            bls_sig: Vec::new(),
        };
        let preimage = crate::sumeragi::consensus::vote_preimage(
            &super::DEFAULT_TEST_CHAIN_ID,
            crate::sumeragi::consensus::PERMISSIONED_TAG,
            &vote,
        );
        let signatures: Vec<Vec<u8>> = signers
            .iter()
            .map(|keypair| {
                Signature::new(keypair.private_key(), &preimage)
                    .payload()
                    .to_vec()
            })
            .collect();
        let sig_refs: Vec<&[u8]> = signatures.iter().map(Vec::as_slice).collect();
        let aggregate_signature = iroha_crypto::bls_normal_aggregate_signatures(&sig_refs)
            .expect("aggregate commit QC signatures");
        qc.aggregate = crate::sumeragi::consensus::QcAggregate {
            signers_bitmap,
            bls_aggregate_signature: aggregate_signature,
        };
        qc
    }

    fn signer_bitmap(signers: &[usize], roster_len: usize) -> Vec<u8> {
        let mut bitmap = vec![0u8; roster_len.div_ceil(8)];
        for signer in signers {
            let byte_idx = signer / 8;
            let bit = signer % 8;
            if let Some(byte) = bitmap.get_mut(byte_idx) {
                *byte |= 1u8 << bit;
            }
        }
        bitmap
    }

    fn full_signer_bitmap(roster_len: usize) -> Vec<u8> {
        let indices: Vec<usize> = (0..roster_len).collect();
        signer_bitmap(&indices, roster_len)
    }

    fn sample_lane_relay_envelope(
        height: u64,
        lane_id: LaneId,
        signers: &[&KeyPair],
        signers_bitmap: Vec<u8>,
    ) -> LaneRelayEnvelope {
        sample_lane_relay_envelope_with_view(height, lane_id, 0, signers, signers_bitmap)
    }

    fn sample_lane_relay_envelope_with_view(
        height: u64,
        lane_id: LaneId,
        view: u64,
        signers: &[&KeyPair],
        signers_bitmap: Vec<u8>,
    ) -> LaneRelayEnvelope {
        let header = BlockHeader::new(
            NonZeroU64::new(height).expect("non-zero height"),
            None,
            None,
            None,
            1_700_000_000_000,
            view,
        );
        let parent_state_root = Hash::new([0xBC; 4]);
        let post_state_root = Hash::new([0xAB; 4]);
        let qc = commit_qc_with_signers(
            &header,
            parent_state_root,
            post_state_root,
            signers,
            signers_bitmap,
        );
        let settlement = LaneBlockCommitment {
            block_height: height,
            lane_id,
            dataspace_id: DataSpaceId::GLOBAL,
            tx_count: 1,
            total_local_micro: 1,
            total_xor_due_micro: 1,
            total_xor_after_haircut_micro: 1,
            total_xor_variance_micro: 0,
            swap_metadata: None,
            receipts: vec![LaneSettlementReceipt {
                source_id: [0xAA; 32],
                local_amount_micro: 1,
                xor_due_micro: 1,
                xor_after_haircut_micro: 1,
                xor_variance_micro: 0,
                timestamp_ms: 1_700_000_000_000,
            }],
        };
        let envelope =
            LaneRelayEnvelope::new(header, Some(qc), None, settlement, 0).expect("valid envelope");
        let fastpq_proof = sample_fastpq_proof_material(&envelope, view);
        envelope.with_fastpq_proof_material(Some(fastpq_proof))
    }

    fn sample_fastpq_proof_material(
        envelope: &LaneRelayEnvelope,
        view: u64,
    ) -> LaneFastpqProofMaterial {
        let verified_at_height = Some(envelope.block_height.saturating_add(view));
        LaneFastpqProofMaterial {
            proof_digest: envelope.expected_fastpq_proof_digest(verified_at_height),
            verified_at_height,
        }
    }

    #[test]
    fn record_lane_relay_persists_and_deduplicates() {
        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let state = State::new_for_testing(World::default(), kura, query_handle);
        state.nexus.write().enabled = true;
        let (validator_ids, validator_keypairs) = bls_accounts_in("validators", 4);
        seed_consensus_keys_with_pops(&state, &validator_keypairs);
        let signers: Vec<&KeyPair> = validator_keypairs.iter().collect();
        let signers_bitmap = full_signer_bitmap(validator_keypairs.len());
        install_lane_manifest_registry(
            &state,
            &[(LaneId::new(0), DataSpaceId::GLOBAL, validator_ids.clone())],
        );
        configure_commit_topology(&state, 1);

        let envelope =
            sample_lane_relay_envelope(1, LaneId::new(0), &signers, signers_bitmap.clone());
        let first = state
            .record_lane_relay(&envelope)
            .expect("first relay stored");
        assert_eq!(first, LaneRelayInsert::Inserted);
        let second = state
            .record_lane_relay(&envelope)
            .expect("duplicate relay returns status");
        assert_eq!(second, LaneRelayInsert::Duplicate);

        let snapshot = state.lane_relay_snapshot();
        assert_eq!(snapshot.len(), 1);
        assert_eq!(snapshot[0].block_height, 1);
        assert_eq!(snapshot[0].lane_id, LaneId::new(0));
    }

