    #[test]
    #[allow(clippy::too_many_lines)]
    fn record_lane_relay_accepts_emergency_override_under_quorum() {
        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let (base_1, base_1_kp) = bls_account_in("wonderland");
        let (base_2, base_2_kp) = bls_account_in("wonderland");
        let (extra_1, extra_1_kp) = bls_account_in("wonderland");
        let (extra_2, extra_2_kp) = bls_account_in("wonderland");
        let domain: DomainId = "wonderland".parse().expect("domain id");
        let multisig_members = (0..5)
            .map(|_| {
                let kp = KeyPair::random_with_algorithm(Algorithm::Ed25519);
                MultisigMember::new(kp.public_key().clone(), 1).expect("multisig member")
            })
            .collect();
        let multisig_policy = MultisigPolicy::new(3, multisig_members).expect("multisig policy");
        let emergency_authority = AccountId::new_multisig(multisig_policy);
        let world = World::with(
            [Domain::new(domain.clone()).build(&ALICE_ID)],
            [
                new_sample_account(&ALICE_ID).build(&ALICE_ID),
                new_account_in_domain(&emergency_authority, &domain).build(&ALICE_ID),
                new_account_in_domain(&base_1, &domain).build(&ALICE_ID),
                new_account_in_domain(&base_2, &domain).build(&ALICE_ID),
                new_account_in_domain(&extra_1, &domain).build(&ALICE_ID),
                new_account_in_domain(&extra_2, &domain).build(&ALICE_ID),
            ],
            [],
        );
        let mut state = State::new_for_testing(world, kura, query_handle);
        let nexus = iroha_config::parameters::actual::Nexus {
            enabled: true,
            lane_relay_emergency: iroha_config::parameters::actual::LaneRelayEmergency {
                enabled: true,
                ..Default::default()
            },
            dataspace_catalog: DataSpaceCatalog::new(vec![DataSpaceMetadata {
                id: DataSpaceId::GLOBAL,
                alias: "universal".to_string(),
                description: None,
                fault_tolerance: 1,
            }])
            .expect("dataspace catalog"),
            ..Default::default()
        };
        state.set_nexus(nexus).expect("apply nexus config");
        install_lane_manifest_registry(
            &state,
            &[(
                LaneId::new(0),
                DataSpaceId::GLOBAL,
                vec![base_1.clone(), base_2.clone()],
            )],
        );
        seed_consensus_keys_with_pops(
            &state,
            &[
                base_1_kp.clone(),
                base_2_kp.clone(),
                extra_1_kp.clone(),
                extra_2_kp.clone(),
            ],
        );

        let header = BlockHeader::new(nonzero!(1_u64), None, None, None, 0, 0);
        let mut block = state.block(header);
        let mut stx = block.transaction();
        let permission =
            iroha_data_model::permission::Permission::new("CanManagePeers".into(), Json::new(()));
        stx.world
            .account_permissions
            .insert(emergency_authority.clone(), BTreeSet::from([permission]));
        SetLaneRelayEmergencyValidators {
            dataspace_id: DataSpaceId::GLOBAL,
            validators: vec![extra_1.clone(), extra_2.clone()],
            expires_at_height: None,
            metadata: Metadata::default(),
        }
        .execute(&emergency_authority, &mut stx)
        .expect("set emergency validators");
        stx.apply();
        block.commit().expect("commit emergency override block");
        assert!(
            state
                .world
                .lane_relay_emergency_validators
                .view()
                .get(&DataSpaceId::GLOBAL)
                .is_some(),
            "override should be stored in world"
        );

        let height = 1;
        let header = BlockHeader::new(
            NonZeroU64::new(height).expect("nonzero height"),
            None,
            None,
            None,
            0,
            0,
        );
        let parent_state_root = Hash::new([0xBC; 4]);
        let post_state_root = Hash::new([0xAB; 4]);
        let mut validator_pool = vec![
            base_1.clone(),
            base_2.clone(),
            extra_1.clone(),
            extra_2.clone(),
        ];
        validator_pool.sort();
        validator_pool.dedup();
        let seed = state.lane_relay_committee_seed(DataSpaceId::GLOBAL, LaneId::new(0), height);
        let committee =
            State::lane_relay_committee_from_pool(&validator_pool, 4, seed).expect("committee");
        let keypairs: BTreeMap<AccountId, KeyPair> = [
            (base_1.clone(), base_1_kp.clone()),
            (base_2.clone(), base_2_kp.clone()),
            (extra_1.clone(), extra_1_kp.clone()),
            (extra_2.clone(), extra_2_kp.clone()),
        ]
        .into_iter()
        .collect();
        let signer_indices = [0usize, 1, 2];
        let signer_keys: Vec<&KeyPair> = signer_indices
            .iter()
            .map(|idx| keypairs.get(&committee[*idx]).expect("signer key"))
            .collect();
        let signers_bitmap = signer_bitmap(&signer_indices, committee.len());
        let qc = commit_qc_with_signers(
            &header,
            parent_state_root,
            post_state_root,
            &signer_keys,
            signers_bitmap,
        );
        let settlement = LaneBlockCommitment {
            block_height: height,
            lane_id: LaneId::new(0),
            dataspace_id: DataSpaceId::GLOBAL,
            tx_count: 1,
            total_local_micro: 1,
            total_xor_due_micro: 1,
            total_xor_after_haircut_micro: 1,
            total_xor_variance_micro: 0,
            swap_metadata: None,
            receipts: vec![LaneSettlementReceipt {
                source_id: [0xAA; 32],
                local_amount_micro: 1,
                xor_due_micro: 1,
                xor_after_haircut_micro: 1,
                xor_variance_micro: 0,
                timestamp_ms: 1_700_000_000_000,
            }],
        };
        let envelope = LaneRelayEnvelope::new(header, Some(qc), None, settlement, 0)
            .expect("lane relay envelope");
        let fastpq_proof = sample_fastpq_proof_material(&envelope, 0);
        let envelope = envelope.with_fastpq_proof_material(Some(fastpq_proof));
        let inserted = state
            .record_lane_relay(&envelope)
            .expect("relay accepted with emergency override");
        assert_eq!(inserted, LaneRelayInsert::Inserted);
    }

