    #[test]
    fn merge_candidate_carries_forward_unchanged_lane_snapshot() {
        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let mut state = State::new_for_testing(World::default(), kura, query_handle);
        let (validator_ids, validator_keypairs) = bls_accounts_in("validators", 4);
        seed_consensus_keys_with_pops(&state, &validator_keypairs);
        let signers: Vec<&KeyPair> = validator_keypairs.iter().collect();
        let signers_bitmap = full_signer_bitmap(validator_keypairs.len());
        let lane_catalog = LaneCatalog::new(
            nonzero!(2_u32),
            vec![
                LaneConfig::default(),
                LaneConfig {
                    id: LaneId::new(1),
                    alias: "beta".to_string(),
                    dataspace_id: DataSpaceId::GLOBAL,
                    ..LaneConfig::default()
                },
            ],
        )
        .expect("two-lane catalog");
        let nexus = iroha_config::parameters::actual::Nexus {
            enabled: true,
            lane_catalog,
            ..iroha_config::parameters::actual::Nexus::default()
        };
        state
            .set_nexus(nexus)
            .expect("apply two-lane Nexus catalog");

        install_lane_manifest_registry(
            &state,
            &[
                (LaneId::new(0), DataSpaceId::GLOBAL, validator_ids.clone()),
                (LaneId::new(1), DataSpaceId::GLOBAL, validator_ids.clone()),
            ],
        );
        let keypairs = configure_commit_topology(&state, 1);

        let lane0_h1 =
            sample_lane_relay_envelope(1, LaneId::new(0), &signers, signers_bitmap.clone());
        let lane1_h1 =
            sample_lane_relay_envelope(1, LaneId::new(1), &signers, signers_bitmap.clone());
        state
            .record_lane_relay(&lane0_h1)
            .expect("lane0 height1 accepted");
        state
            .record_lane_relay(&lane1_h1)
            .expect("lane1 height1 accepted");

        let first_candidate = state
            .merge_entry_candidates_from_lane_relays()
            .into_iter()
            .next()
            .expect("initial merge candidate");
        let first_qc = merge_qc_for_candidate(&state, &first_candidate, &keypairs, &[0]);
        state
            .commit_merge_entry(merge_entry_from_candidate(first_candidate, first_qc))
            .expect("commit initial merge entry");

        let lane0_h2 = sample_lane_relay_envelope(2, LaneId::new(0), &signers, signers_bitmap);
        state
            .record_lane_relay(&lane0_h2)
            .expect("lane0 height2 accepted");

        let second_candidate = state
            .merge_entry_candidates_from_lane_relays()
            .into_iter()
            .next()
            .expect("rolling merge candidate");
        assert_eq!(second_candidate.epoch_id, 2);
        let lane0_snapshot = second_candidate
            .lane_snapshots
            .iter()
            .find(|snapshot| snapshot.lane_id == LaneId::new(0))
            .expect("lane0 snapshot");
        let lane1_snapshot = second_candidate
            .lane_snapshots
            .iter()
            .find(|snapshot| snapshot.lane_id == LaneId::new(1))
            .expect("lane1 snapshot");
        assert_eq!(lane0_snapshot.lane_block_height, 2);
        assert_eq!(lane0_snapshot.tip_hash, lane0_h2.block_header.hash());
        assert_eq!(lane1_snapshot.lane_block_height, 1);
        assert_eq!(lane1_snapshot.tip_hash, lane1_h1.block_header.hash());
    }

    #[test]
    fn da_pin_intents_hydrate_from_kura_block_log() {
        let temp_dir = tempfile::tempdir().expect("temp dir");
        let store_root = temp_dir.path().join("kura");
        let lane_count = nonzero!(1_u32);

        let catalog =
            LaneCatalog::new(lane_count, vec![LaneConfig::default()]).expect("lane catalog");
        let lane_config = RuntimeLaneConfig::from_catalog(&catalog);
        let lane = lane_config.primary().lane_id;
        let kura_cfg = KuraConfig {
            init_mode: InitMode::Strict,
            store_dir: WithOrigin::inline(store_root),
            max_disk_usage_bytes: iroha_config::parameters::defaults::kura::MAX_DISK_USAGE_BYTES,
            blocks_in_memory: iroha_config::parameters::defaults::kura::BLOCKS_IN_MEMORY,
            debug_output_new_blocks: false,
            merge_ledger_cache_capacity:
                iroha_config::parameters::defaults::kura::MERGE_LEDGER_CACHE_CAPACITY,
            fsync_mode: iroha_config::kura::FsyncMode::Batched,
            fsync_interval: iroha_config::parameters::defaults::kura::FSYNC_INTERVAL,

            block_sync_roster_retention:
                iroha_config::parameters::defaults::kura::BLOCK_SYNC_ROSTER_RETENTION,
            roster_sidecar_retention:
                iroha_config::parameters::defaults::kura::ROSTER_SIDECAR_RETENTION,
        };
        let (kura, _) = Kura::new(&kura_cfg, &lane_config).expect("init kura");
        let query_handle = LiveQueryStore::start_test();
        let mut state = State::new_for_testing(World::default(), Arc::clone(&kura), query_handle);
        state
            .set_nexus(iroha_config::parameters::actual::Nexus {
                lane_catalog: catalog,
                lane_config,
                ..Default::default()
            })
            .expect("apply Nexus catalog for DA pin replay test");

        let mut intent = DaPinIntent::new(
            lane,
            7,
            3,
            StorageTicketId::new([0xAA; 32]),
            iroha_data_model::sorafs::pin_registry::ManifestDigest::new([0xBB; 32]),
        );
        intent.alias = Some("alias-one".to_string());

        let bundle = DaPinIntentBundle::new(vec![intent.clone()]);
        let keypair = KeyPair::random();
        let new_block = BlockBuilder::new(vec![dummy_accepted_transaction()])
            .chain(0, None)
            .with_da_pin_intents(Some(bundle))
            .sign(keypair.private_key())
            .unpack(|_| {});
        let signed_block: SignedBlock = new_block.into();
        kura.store_block(Arc::new(signed_block.clone()))
            .expect("store block");

        let mut block_hashes = state.block_hashes.block();
        block_hashes.push(signed_block.hash());
        block_hashes.commit_for_tests();

        let store = state.da_pin_intents();
        let collected: Vec<_> = store.all_sorted().cloned().collect();
        assert_eq!(collected.len(), 1);
        assert_eq!(collected[0].intent, intent);
        assert_eq!(
            collected[0].location.block_height,
            signed_block.header().height().get()
        );
        assert_eq!(collected[0].location.index_in_bundle, 0);
        drop(store);
        assert_eq!(state.da_pin_intents().all_sorted().count(), 1);
    }

    #[test]
    fn da_shard_cursors_guard_regressions() {
        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let state = State::new_for_testing(World::default(), kura, query_handle);
        state
            .ensure_da_indexes_hydrated()
            .expect("hydrate DA indexes before advancing");

        let advance = iroha_data_model::da::commitment::DaCommitmentRecord::new(
            LaneId::new(0),
            4,
            2,
            BlobDigest::new([0xAA; 32]),
            iroha_data_model::sorafs::pin_registry::ManifestDigest::new([0xBB; 32]),
            DaProofScheme::MerkleSha256,
            Hash::prehashed([0xCC; 32]),
            Some(KzgCommitment::new([0xDD; 48])),
            None,
            RetentionClass::default(),
            StorageTicketId::new([0xEE; 32]),
            Signature::from_bytes(&[0x11; 64]),
        );
        let regress = iroha_data_model::da::commitment::DaCommitmentRecord::new(
            LaneId::new(0),
            4,
            1,
            BlobDigest::new([0xAA; 32]),
            iroha_data_model::sorafs::pin_registry::ManifestDigest::new([0xCC; 32]),
            DaProofScheme::MerkleSha256,
            Hash::prehashed([0xDD; 32]),
            Some(KzgCommitment::new([0xEE; 48])),
            None,
            RetentionClass::default(),
            StorageTicketId::new([0xFF; 32]),
            Signature::from_bytes(&[0x22; 64]),
        );

        state
            .advance_da_shard_cursors_from_bundle(3, std::slice::from_ref(&advance))
            .expect("initial advance should succeed");
        {
            let cursors = state.da_shard_cursor_index();
            let cursor = cursors.get(0).expect("cursor present");
            assert_eq!(cursor.epoch, 4);
            assert_eq!(cursor.sequence, 2);
            assert_eq!(cursor.last_block_height, 3);
        }

        // Regression should be ignored and leave cursor unchanged.
        let err = state
            .advance_da_shard_cursors_from_bundle(4, std::slice::from_ref(&regress))
            .expect_err("regression should be rejected");
        assert!(matches!(err, DaShardCursorError::Regression { shard_id, .. } if shard_id == 0));
        let cursors = state.da_shard_cursor_index();
        let cursor = cursors.get(0).expect("cursor present after regression");
        assert_eq!(cursor.epoch, 4);
        assert_eq!(cursor.sequence, 2);
        assert_eq!(cursor.last_block_height, 3);
    }

