    #[test]
    fn hydrate_da_indexes_rejects_cursor_regression() {
        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let state = State::new_for_testing(World::default(), Arc::clone(&kura), query_handle);
        let keypair = KeyPair::random();

        let make_record = |sequence: u64| {
            DaCommitmentRecord::new(
                LaneId::new(0),
                1,
                sequence,
                BlobDigest::new([0xAA; 32]),
                iroha_data_model::sorafs::pin_registry::ManifestDigest::new([0xBB; 32]),
                DaProofScheme::MerkleSha256,
                Hash::prehashed([0xCC; 32]),
                Some(KzgCommitment::new([0xDD; 48])),
                None,
                RetentionClass::default(),
                StorageTicketId::new([0xEE; 32]),
                Signature::from_bytes(&[0x11; 64]),
            )
        };

        let first_bundle = DaCommitmentBundle::new(vec![make_record(1)]);
        let first_block = BlockBuilder::new(vec![dummy_accepted_transaction()])
            .chain(0, None)
            .with_da_commitments(Some(first_bundle))
            .sign(keypair.private_key())
            .unpack(|_| {});
        let signed_first: SignedBlock = first_block.into();
        kura.store_block(Arc::new(signed_first.clone()))
            .expect("store block");
        {
            let mut hashes = state.block_hashes.block();
            hashes.push(signed_first.hash());
            hashes.commit_for_tests();
        }

        let second_bundle = DaCommitmentBundle::new(vec![make_record(0)]);
        let second_block = BlockBuilder::new(vec![dummy_accepted_transaction()])
            .chain(0, Some(&signed_first))
            .with_da_commitments(Some(second_bundle))
            .sign(keypair.private_key())
            .unpack(|_| {});
        let signed_second: SignedBlock = second_block.into();
        kura.store_block(Arc::new(signed_second.clone()))
            .expect("store block");
        {
            let mut hashes = state.block_hashes.block();
            hashes.push(signed_second.hash());
            hashes.commit_for_tests();
        }

        let err = state
            .ensure_da_indexes_hydrated()
            .expect_err("hydration should fail on regression");
        match err {
            DaShardCursorError::Regression {
                shard_id,
                lane_id,
                observed_sequence,
                current_sequence,
                ..
            } => {
                assert_eq!(shard_id, 0);
                assert_eq!(lane_id, LaneId::new(0));
                assert_eq!(observed_sequence, 0);
                assert_eq!(current_sequence, 1);
                let height_str = signed_second.header().height().get().to_string();
                assert!(
                    err.to_string().contains(&height_str),
                    "expected error message to include height {height_str}"
                );
            }
            other => panic!("unexpected error: {other:?}"),
        }
    }

