    #[test]
    fn da_shard_cursor_journal_drops_on_reshard() {
        let temp_dir = tempfile::tempdir().expect("temp dir");
        let store_root = temp_dir.path().join("kura");
        let mut metadata = BTreeMap::new();
        metadata.insert("da_shard_id".to_string(), "1".to_string());
        let initial_catalog = LaneCatalog::new(
            nonzero!(1_u32),
            vec![LaneConfig {
                metadata: metadata.clone(),
                ..LaneConfig::default()
            }],
        )
        .expect("lane catalog");
        let initial_config = RuntimeLaneConfig::from_catalog(&initial_catalog);

        let kura_cfg = KuraConfig {
            init_mode: InitMode::Strict,
            store_dir: WithOrigin::inline(store_root),
            max_disk_usage_bytes: iroha_config::parameters::defaults::kura::MAX_DISK_USAGE_BYTES,
            blocks_in_memory: iroha_config::parameters::defaults::kura::BLOCKS_IN_MEMORY,
            debug_output_new_blocks: false,
            merge_ledger_cache_capacity:
                iroha_config::parameters::defaults::kura::MERGE_LEDGER_CACHE_CAPACITY,
            fsync_mode: iroha_config::kura::FsyncMode::Batched,
            fsync_interval: iroha_config::parameters::defaults::kura::FSYNC_INTERVAL,

            block_sync_roster_retention:
                iroha_config::parameters::defaults::kura::BLOCK_SYNC_ROSTER_RETENTION,
            roster_sidecar_retention:
                iroha_config::parameters::defaults::kura::ROSTER_SIDECAR_RETENTION,
        };
        let (kura, _) = Kura::new(&kura_cfg, &initial_config).expect("init kura");
        let query_handle = LiveQueryStore::start_test();
        let mut state = State::new_for_testing(World::default(), Arc::clone(&kura), query_handle);
        state
            .set_nexus(iroha_config::parameters::actual::Nexus {
                lane_catalog: initial_catalog,
                lane_config: initial_config.clone(),
                ..Default::default()
            })
            .expect("apply Nexus catalog before relabel test");

        let record = DaCommitmentRecord::new(
            LaneId::new(0),
            5,
            7,
            BlobDigest::new([0x10; 32]),
            iroha_data_model::sorafs::pin_registry::ManifestDigest::new([0x20; 32]),
            DaProofScheme::MerkleSha256,
            Hash::prehashed([0x30; 32]),
            Some(KzgCommitment::new([0x40; 48])),
            None,
            RetentionClass::default(),
            StorageTicketId::new([0x50; 32]),
            Signature::from_bytes(&[0x60; 64]),
        );

        state
            .advance_da_shard_cursors_from_bundle(2, std::slice::from_ref(&record))
            .expect("advance cursor");
        state.persist_da_shard_cursor_journal();

        let mut updated_metadata = metadata;
        updated_metadata.insert("da_shard_id".to_string(), "3".to_string());
        let updated_catalog = LaneCatalog::new(
            nonzero!(1_u32),
            vec![LaneConfig {
                metadata: updated_metadata,
                ..LaneConfig::default()
            }],
        )
        .expect("updated catalog");
        let updated_config = RuntimeLaneConfig::from_catalog(&updated_catalog);

        state
            .set_nexus(iroha_config::parameters::actual::Nexus {
                lane_catalog: updated_catalog,
                lane_config: updated_config.clone(),
                ..Default::default()
            })
            .expect("apply relabelled Nexus catalog");

        let cursors = state.da_shard_cursor_index();
        assert!(
            cursors.get(1).is_none(),
            "old shard cursor should be dropped"
        );
        drop(cursors);

        let path = state.da_shard_cursor_journal_path();
        let journal =
            DaShardCursorJournal::load(&updated_config, &path).expect("load updated journal");
        assert!(
            journal.cursor_for_lane(record.lane_id).is_none(),
            "lane cursor should be cleared after reshard"
        );
    }

    #[test]
    #[allow(clippy::too_many_lines)]
    fn block_and_revert_rewinds_da_indexes() {
        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let mut state = State::new_for_testing(World::default(), Arc::clone(&kura), query_handle);

        let lane_count = nonzero!(1_u32);
        let catalog =
            LaneCatalog::new(lane_count, vec![LaneConfig::default()]).expect("lane catalog");
        let lane_config = RuntimeLaneConfig::from_catalog(&catalog);
        state
            .set_nexus(iroha_config::parameters::actual::Nexus {
                lane_catalog: catalog,
                lane_config,
                ..Default::default()
            })
            .expect("apply Nexus catalog for telemetry test");

        let keypair = KeyPair::random();
        let make_record = |sequence: u64| {
            DaCommitmentRecord::new(
                LaneId::new(0),
                1,
                sequence,
                BlobDigest::new([0xAA; 32]),
                iroha_data_model::sorafs::pin_registry::ManifestDigest::new([0xBB; 32]),
                DaProofScheme::MerkleSha256,
                Hash::prehashed([0xCC; 32]),
                Some(KzgCommitment::new([0xDD; 48])),
                None,
                RetentionClass::default(),
                StorageTicketId::new([0xEE; 32]),
                Signature::from_bytes(&[0x11; 64]),
            )
        };

        let first_bundle = DaCommitmentBundle::new(vec![make_record(1)]);
        let first_block = BlockBuilder::new(vec![dummy_accepted_transaction()])
            .chain(0, None)
            .with_da_commitments(Some(first_bundle.clone()))
            .sign(keypair.private_key())
            .unpack(|_| {});
        let signed_first: SignedBlock = first_block.into();
        kura.store_block(Arc::new(signed_first.clone()))
            .expect("store first block");
        {
            let mut hashes = state.block_hashes.block();
            hashes.push(signed_first.hash());
            hashes.commit_for_tests();
        }

        let pin_intent = iroha_data_model::da::pin_intent::DaPinIntent {
            lane_id: LaneId::new(0),
            epoch: 1,
            sequence: 2,
            storage_ticket: StorageTicketId::new([0xFF; 32]),
            manifest_hash: iroha_data_model::sorafs::pin_registry::ManifestDigest::new([0xAA; 32]),
            alias: Some("rewind-alias".to_string()),
            owner: None,
        };
        let pin_bundle =
            iroha_data_model::da::pin_intent::DaPinIntentBundle::new(vec![pin_intent.clone()]);
        let second_bundle = DaCommitmentBundle::new(vec![make_record(2)]);
        let second_block = BlockBuilder::new(vec![dummy_accepted_transaction()])
            .chain(0, Some(&signed_first))
            .with_da_commitments(Some(second_bundle.clone()))
            .with_da_pin_intents(Some(pin_bundle))
            .sign(keypair.private_key())
            .unpack(|_| {});
        let signed_second: SignedBlock = second_block.into();
        kura.store_block(Arc::new(signed_second.clone()))
            .expect("store second block");
        {
            let mut hashes = state.block_hashes.block();
            hashes.push(signed_second.hash());
            hashes.commit_for_tests();
        }

        state
            .ensure_da_indexes_hydrated()
            .expect("initial hydration should succeed");
        {
            let cursors = state.da_shard_cursor_index();
            let cursor = cursors.get(0).expect("cursor present at height 2");
            assert_eq!(cursor.sequence, 2);
            assert_eq!(cursor.last_block_height, 2);
        }
        {
            let pins = state.da_pin_intents();
            assert!(
                pins.get_by_alias("rewind-alias").is_some(),
                "pin intent should be present before rewind"
            );
        }

        let rollback = state.block_and_revert(signed_second.header());
        drop(rollback);

        {
            let cursors = state.da_shard_cursor_index();
            let cursor = cursors.get(0).expect("cursor present after rewind");
            assert_eq!(cursor.sequence, 1);
            assert_eq!(cursor.last_block_height, 1);
        }
        let pins = state.da_pin_intents();
        assert!(
            pins.get_by_alias("rewind-alias").is_none(),
            "pin intent from reverted block should be dropped"
        );
        let commitments = state.da_commitments.read();
        assert!(
            commitments.bundle_at(2).is_none(),
            "tail commitment bundle should be removed on rewind"
        );
    }

    #[cfg(feature = "telemetry")]
    #[test]
    fn da_shard_cursor_missing_cursor_records_telemetry() {
        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let metrics = Arc::new(Metrics::default());
        let telemetry = StateTelemetry::new(metrics.clone(), true);
        let mut state = State::with_telemetry(World::default(), kura, query_handle, telemetry);
        let mut sumeragi = state.world.parameters.view().get().sumeragi().clone();
        sumeragi.da_enabled = true;
        state.set_sumeragi_parameters(&sumeragi);

        let lane_count = nonzero!(1_u32);
        let catalog =
            LaneCatalog::new(lane_count, vec![LaneConfig::default()]).expect("lane catalog");
        let lane_config = RuntimeLaneConfig::from_catalog(&catalog);
        state
            .set_nexus(iroha_config::parameters::actual::Nexus {
                lane_catalog: catalog,
                lane_config,
                ..Default::default()
            })
            .expect("apply Nexus catalog for telemetry validation");

        let keypair = KeyPair::random();
        let block: SignedBlock = BlockBuilder::new(vec![dummy_accepted_transaction()])
            .chain(0, None)
            .sign(keypair.private_key())
            .unpack(|_| {})
            .into();
        let mut state_block = state.block(block.header());
        state_block.touched_lanes.insert(LaneId::new(0));

        let err = state_block
            .validate_da_shard_cursors(&block)
            .expect_err("missing cursor should fail validation");
        assert!(matches!(
            err,
            BlockValidationError::DaShardCursor(DaShardCursorError::MissingCursor { .. })
        ));

        let counter = metrics
            .da_shard_cursor_events_total
            .with_label_values(&["missing_cursor", "0", "0"])
            .get();
        assert_eq!(counter, 1);
        let height = metrics
            .da_shard_cursor_height
            .with_label_values(&["0", "0"])
            .get();
        assert_eq!(
            height,
            i64::try_from(block.header().height().get()).expect("height fits in i64")
        );
        let lag = metrics
            .da_shard_cursor_lag_blocks
            .with_label_values(&["0", "0"])
            .get();
        assert_eq!(
            lag,
            i64::try_from(block.header().height().get()).expect("height fits in i64")
        );
    }

