    #[test]
    fn state_block_axt_policy_snapshot_reads_block_scope() {
        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let state = State::new_for_testing(World::new(), kura, query_handle);

        let header = BlockHeader::new(nonzero!(1_u64), None, None, None, 0, 0);
        let mut block = state.block(header);

        let dsid = DataSpaceId::new(13);
        let entry = AxtPolicyEntry {
            manifest_root: [0x66; 32],
            target_lane: LaneId::new(2),
            min_handle_era: 5,
            min_sub_nonce: 4,
            current_slot: 99,
        };

        block.world.axt_policies.insert(dsid, entry);

        let expected_slot = block.block_hashes().len() as u64;
        let snapshot = block.axt_policy_snapshot();
        let binding = snapshot
            .entries
            .iter()
            .find(|binding| binding.dsid == dsid)
            .expect("policy from block scope available");

        assert_eq!(binding.policy.manifest_root, entry.manifest_root);
        assert_eq!(binding.policy.target_lane, entry.target_lane);
        assert_eq!(binding.policy.min_handle_era, entry.min_handle_era);
        assert_eq!(binding.policy.min_sub_nonce, entry.min_sub_nonce);
        assert_eq!(binding.policy.current_slot, expected_slot);
        let expected_version = AxtPolicySnapshot::compute_version(&snapshot.entries);
        assert_eq!(snapshot.version, expected_version);
    }

    #[test]
    fn axt_replay_ledger_overlay_applies() {
        let dsid = DataSpaceId::new(41);
        let lane = LaneId::new(0);
        let lane_catalog = LaneCatalog::new(
            nonzero!(1_u32),
            vec![LaneConfig {
                id: lane,
                dataspace_id: dsid,
                alias: "primary".to_owned(),
                description: None,
                visibility: iroha_data_model::nexus::LaneVisibility::Public,
                lane_type: None,
                governance: None,
                settlement: None,
                storage: iroha_data_model::nexus::LaneStorageProfile::FullReplica,
                proof_scheme: DaProofScheme::default(),
                metadata: BTreeMap::new(),
            }],
        )
        .expect("lane catalog");
        let mut nexus = iroha_config::parameters::actual::Nexus {
            lane_catalog: lane_catalog.clone(),
            lane_config: iroha_config::parameters::actual::LaneConfig::from_catalog(&lane_catalog),
            dataspace_catalog: dataspace_catalog_for_lane_catalog(&lane_catalog),
            ..Default::default()
        };
        nexus.axt.slot_length_ms = NonZeroU64::new(1).expect("slot length");
        nexus.axt.replay_retention_slots = NonZeroU64::new(2).expect("retention");

        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let mut state = State::new_for_testing(World::new(), kura, query_handle);
        state
            .set_nexus(nexus)
            .expect("apply Nexus catalog for replay ledger pruning test");

        let header = BlockHeader::new(nonzero!(1_u64), None, None, None, 1, 0);
        let mut block = state.block(header);
        let mut stx = block.transaction();
        stx.current_lane_id = Some(lane);

        let key = AxtHandleReplayKey::from_parts([0xAA; 32], 3, 7, lane);
        let record = AxtReplayRecord {
            dataspace: dsid,
            used_slot: 1,
            retain_until_slot: 4,
        };
        stx.world.axt_replay_ledger.insert(key, record);
        stx.apply();

        assert_eq!(
            block.world.axt_replay_ledger.get(&key).copied(),
            Some(record)
        );
    }

