    #[cfg(feature = "telemetry")]
    #[test]
    fn axt_policy_snapshot_metrics_record_cache_hit() {
        let metrics = Arc::new(Metrics::default());
        let telemetry = StateTelemetry::new(metrics.clone(), true);
        let world = World::new();
        let dsid = DataSpaceId::new(11);
        let policy = AxtPolicyEntry {
            manifest_root: [0x33; 32],
            target_lane: LaneId::new(4),
            min_handle_era: 6,
            min_sub_nonce: 2,
            current_slot: 1,
        };

        {
            let mut block = world.block();
            block.axt_policies.insert(dsid, policy);
            block.commit();
        }

        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let state = State::with_telemetry(world, kura, query_handle, telemetry);
        let snapshot = state.view().axt_policy_snapshot();

        let expected = if snapshot.version != 0 {
            snapshot.version
        } else {
            AxtPolicySnapshot::compute_version(&snapshot.entries)
        };

        assert_eq!(
            metrics
                .axt_policy_snapshot_cache_events_total
                .with_label_values(&["hit"])
                .get(),
            1
        );
        assert_eq!(metrics.axt_policy_snapshot_version.get(), expected);
    }

