    #[test]
    fn recording_axt_envelope_advances_policy_counters() {
        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let mut state = State::new_for_testing(World::new(), kura, query_handle);

        let dsid = DataSpaceId::new(33);
        let lane = LaneId::new(2);
        state.set_axt_policy(
            dsid,
            AxtPolicyEntry {
                manifest_root: [0xAA; 32],
                target_lane: lane,
                min_handle_era: 1,
                min_sub_nonce: 1,
                current_slot: 0,
            },
        );

        let header = BlockHeader::new(nonzero!(1_u64), None, None, None, 0, 0);
        let mut block = state.block(header);
        let mut stx = block.transaction();

        let binding = AxtBinding::new([0xAB; 32]);
        let handle = iroha_data_model::nexus::AssetHandle {
            scope: vec!["transfer".into()],
            subject: HandleSubject {
                account: ALICE_ID.to_string(),
                origin_dsid: Some(dsid),
            },
            budget: HandleBudget {
                remaining: 10,
                per_use: Some(10),
            },
            handle_era: 4,
            sub_nonce: 7,
            group_binding: GroupBinding {
                composability_group_id: vec![0; 32],
                epoch_id: 1,
            },
            target_lane: lane,
            axt_binding: binding,
            manifest_view_root: [0xAA; 32],
            expiry_slot: 50,
            max_clock_skew_ms: Some(0),
        };
        let envelope = AxtEnvelopeRecord {
            binding,
            lane,
            descriptor: AxtDescriptor {
                dsids: vec![dsid],
                touches: Vec::new(),
            },
            touches: Vec::new(),
            proofs: Vec::new(),
            handles: vec![AxtHandleFragment {
                handle: handle.clone(),
                intent: RemoteSpendIntent {
                    asset_dsid: dsid,
                    op: SpendOp {
                        kind: "transfer".into(),
                        from: ALICE_ID.to_string(),
                        to: BOB_ID.to_string(),
                        amount: "5".into(),
                    },
                },
                proof: None,
                amount: 5,
                amount_commitment: None,
            }],
            commit_height: Some(1),
        };

        stx.record_axt_envelope(envelope);
        stx.apply();

        let updated = block
            .world
            .axt_policies
            .get(&dsid)
            .expect("policy persisted");
        assert_eq!(updated.min_handle_era, handle.handle_era);
        assert_eq!(updated.min_sub_nonce, handle.sub_nonce.saturating_add(1));
        let expected_slot = block
            .axt_policy_snapshot()
            .entries
            .first()
            .map_or(0, |entry| entry.policy.current_slot);
        assert_eq!(updated.current_slot, expected_slot);
    }

    #[test]
    #[allow(clippy::too_many_lines)]
    fn axt_replay_ledger_records_and_prunes() {
        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let mut state = State::new_for_testing(World::new(), kura, query_handle);
        {
            let nexus = state.nexus.get_mut();
            nexus.axt.slot_length_ms = NonZeroU64::new(1).expect("slot length");
            nexus.axt.replay_retention_slots = NonZeroU64::new(2).expect("retention");
        }

        let dsid = DataSpaceId::new(51);
        let lane = LaneId::new(0);
        let binding = AxtBinding::new([0xBA; 32]);
        state.set_axt_policy(
            dsid,
            AxtPolicyEntry {
                manifest_root: [0xCC; 32],
                target_lane: lane,
                min_handle_era: 1,
                min_sub_nonce: 1,
                current_slot: 0,
            },
        );

        let handle = iroha_data_model::nexus::AssetHandle {
            scope: vec!["transfer".into()],
            subject: iroha_data_model::nexus::HandleSubject {
                account: ALICE_ID.to_string(),
                origin_dsid: Some(dsid),
            },
            budget: iroha_data_model::nexus::HandleBudget {
                remaining: 10,
                per_use: Some(10),
            },
            handle_era: 3,
            sub_nonce: 7,
            group_binding: iroha_data_model::nexus::GroupBinding {
                composability_group_id: vec![0; 32],
                epoch_id: 1,
            },
            target_lane: lane,
            axt_binding: binding,
            manifest_view_root: [0xCC; 32],
            expiry_slot: 2,
            max_clock_skew_ms: Some(0),
        };
        let envelope = AxtEnvelopeRecord {
            binding,
            lane,
            descriptor: AxtDescriptor {
                dsids: vec![dsid],
                touches: Vec::new(),
            },
            touches: Vec::new(),
            proofs: Vec::new(),
            handles: vec![AxtHandleFragment {
                handle: handle.clone(),
                intent: RemoteSpendIntent {
                    asset_dsid: dsid,
                    op: SpendOp {
                        kind: "transfer".into(),
                        from: ALICE_ID.to_string(),
                        to: BOB_ID.to_string(),
                        amount: "5".into(),
                    },
                },
                proof: None,
                amount: 5,
                amount_commitment: None,
            }],
            commit_height: Some(1),
        };

        let header = BlockHeader::new(nonzero!(1_u64), None, None, None, 1, 0);
        let mut block = state.block(header);
        let mut stx = block.transaction();
        stx.current_lane_id = Some(lane);
        stx.record_axt_envelope(envelope);
        stx.apply();
        #[cfg(test)]
        eprintln!("after first apply");

        let key = AxtHandleReplayKey::from_handle(&handle);
        let entry = block
            .world
            .axt_replay_ledger
            .get(&key)
            .expect("replay entry recorded");
        assert_eq!(entry.used_slot, 1);
        assert_eq!(entry.retain_until_slot, 3, "retention horizon applies");
        #[cfg(test)]
        eprintln!(
            "ledger after first apply len={} entry={:?}",
            block.world.axt_replay_ledger.iter().count(),
            entry
        );
        drop(block);

        // Advance to a far-future slot and ensure stale entries are pruned before recording.
        let new_handle = iroha_data_model::nexus::AssetHandle {
            expiry_slot: 20,
            sub_nonce: 8,
            ..handle
        };
        let future_header = BlockHeader::new(nonzero!(2_u64), None, None, None, 10, 0);
        #[cfg(test)]
        eprintln!("starting second block");
        let mut block = state.block(future_header);
        #[cfg(test)]
        eprintln!("second block created");
        let mut stx = block.transaction();
        #[cfg(test)]
        eprintln!("second transaction created");
        stx.current_lane_id = Some(lane);
        #[cfg(test)]
        eprintln!("recording second envelope");
        stx.record_axt_envelope(AxtEnvelopeRecord {
            handles: vec![AxtHandleFragment {
                handle: new_handle.clone(),
                intent: RemoteSpendIntent {
                    asset_dsid: dsid,
                    op: SpendOp {
                        kind: "transfer".into(),
                        from: ALICE_ID.to_string(),
                        to: BOB_ID.to_string(),
                        amount: "4".into(),
                    },
                },
                proof: None,
                amount: 4,
                amount_commitment: None,
            }],
            binding,
            lane,
            descriptor: AxtDescriptor {
                dsids: vec![dsid],
                touches: Vec::new(),
            },
            touches: Vec::new(),
            proofs: Vec::new(),
            commit_height: Some(2),
        });
        stx.apply();
        #[cfg(test)]
        eprintln!(
            "after second apply len={} stale_pruned={}",
            block.world.axt_replay_ledger.iter().count(),
            block.world.axt_replay_ledger.get(&key).is_none()
        );

        assert!(
            block.world.axt_replay_ledger.get(&key).is_none(),
            "stale replay entry should be pruned"
        );
        let new_key = AxtHandleReplayKey::from_handle(&new_handle);
        let new_entry = block
            .world
            .axt_replay_ledger
            .get(&new_key)
            .expect("new entry recorded");
        assert_eq!(new_entry.used_slot, 10);
        assert!(new_entry.retain_until_slot >= 12);
    }

    #[test]
    #[allow(clippy::too_many_lines)]
    fn axt_replay_ledger_persisted_from_block_rejects_reuse_on_validation() {
        use iroha_data_model::nexus::{LaneStorageProfile, LaneVisibility};
        use iroha_primitives::time::TimeSource;

        fn build_block_with_envelope(
            envelope: AxtEnvelopeRecord,
            snapshot: AxtPolicySnapshot,
            time_source: TimeSource,
            prev_block: Option<&SignedBlock>,
        ) -> SignedBlock {
            let builder = BlockBuilder::new_with_time_source(Vec::new(), time_source);
            let signer = KeyPair::random();
            let mut block: SignedBlock = builder
                .chain(0, prev_block)
                .sign(signer.private_key())
                .unpack(|_| {})
                .into();
            let entry_hashes: Vec<HashOf<TransactionEntrypoint>> = Vec::new();
            let results: Vec<TransactionResultInner> = Vec::new();
            block.set_transaction_results_with_transcripts(
                Vec::new(),
                &entry_hashes,
                results,
                BTreeMap::new(),
                vec![envelope],
                Some(snapshot),
            );
            block
        }

        fn validate_and_apply_block(
            state: &mut State,
            block: SignedBlock,
            envelope: AxtEnvelopeRecord,
            snapshot: AxtPolicySnapshot,
        ) -> (CommittedBlock, Vec<AxtHandleReplayKey>) {
            let mut state_block = state.block(block.header());
            let valid = ValidBlock::validate_unchecked(block, &mut state_block).unpack(|_| {});
            let mut committed = valid.commit_unchecked().unpack(|_| {});
            let entry_hashes: Vec<HashOf<TransactionEntrypoint>> = Vec::new();
            let results: Vec<TransactionResultInner> = Vec::new();
            committed.as_mut().set_transaction_results_with_transcripts(
                Vec::new(),
                &entry_hashes,
                results,
                BTreeMap::new(),
                vec![envelope],
                Some(snapshot),
            );
            let env_len = committed
                .as_ref()
                .axt_envelopes()
                .map_or(0, <[iroha_data_model::nexus::AxtEnvelopeRecord]>::len);
            assert!(env_len > 0, "committed block missing AXT envelopes");
            let _ = state_block.apply_without_execution(&committed, Vec::new());
            let ledger_keys: Vec<_> = state_block
                .world
                .axt_replay_ledger
                .iter()
                .map(|(key, _)| *key)
                .collect();
            let ledger_count = ledger_keys.len();
            assert!(
                ledger_count > 0,
                "ledger should record entries after apply_without_execution (count={ledger_count})"
            );
            state_block.commit().expect("state commit");
            (committed, ledger_keys)
        }

        let authority: AccountId = AccountId::new(
            "ed012059C8A4DA1EBB5380F74ABA51F502714652FDCCE9611FAFB9904E4A3C4D382774"
                .parse()
                .expect("public key"),
        );
        let merchant_id = gen_account_in("wonderland").0;
        let dsid = DataSpaceId::new(81);
        let lane = LaneId::new(0);
        let manifest_root = [0x77; 32];
        let lane_catalog = LaneCatalog::new(
            nonzero!(1_u32),
            vec![LaneConfig {
                id: lane,
                dataspace_id: dsid,
                alias: "primary".to_owned(),
                description: None,
                visibility: LaneVisibility::Public,
                lane_type: None,
                governance: None,
                settlement: None,
                storage: LaneStorageProfile::FullReplica,
                proof_scheme: DaProofScheme::default(),
                metadata: BTreeMap::new(),
            }],
        )
        .expect("lane catalog");
        let mut nexus = iroha_config::parameters::actual::Nexus {
            lane_catalog: lane_catalog.clone(),
            lane_config: iroha_config::parameters::actual::LaneConfig::from_catalog(&lane_catalog),
            ..Default::default()
        };
        nexus.axt.slot_length_ms = NonZeroU64::new(10).expect("slot length");
        nexus.axt.replay_retention_slots = NonZeroU64::new(4).expect("retention");

        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let mut state = State::new_for_testing(World::new(), kura, query_handle);
        *state.nexus.get_mut() = nexus;
        state.set_axt_policy(
            dsid,
            AxtPolicyEntry {
                manifest_root,
                target_lane: lane,
                min_handle_era: 1,
                min_sub_nonce: 1,
                current_slot: 0,
            },
        );

        let descriptor = AxtDescriptor {
            dsids: vec![dsid],
            touches: vec![AxtTouchSpec {
                dsid,
                read: Vec::new(),
                write: Vec::new(),
            }],
        };
        let binding = descriptor.binding().expect("descriptor binding");
        let touch_fragment = AxtTouchFragment {
            dsid,
            manifest: TouchManifest {
                read: Vec::new(),
                write: Vec::new(),
            },
        };
        let proof_fragment = AxtProofFragment {
            dsid,
            proof: ProofBlob {
                payload: manifest_root.to_vec(),
                expiry_slot: Some(5),
            },
        };
        let handle_fragment = AxtHandleFragment {
            handle: AssetHandle {
                scope: vec!["transfer".into()],
                subject: HandleSubject {
                    account: authority.to_string(),
                    origin_dsid: Some(dsid),
                },
                budget: HandleBudget {
                    remaining: 10,
                    per_use: Some(10),
                },
                handle_era: 1,
                sub_nonce: 1,
                group_binding: GroupBinding {
                    composability_group_id: vec![0; 32],
                    epoch_id: 1,
                },
                target_lane: lane,
                axt_binding: binding,
                manifest_view_root: manifest_root,
                expiry_slot: 5,
                max_clock_skew_ms: Some(0),
            },
            intent: RemoteSpendIntent {
                asset_dsid: dsid,
                op: SpendOp {
                    kind: "transfer".into(),
                    from: authority.to_string(),
                    to: merchant_id.to_string(),
                    amount: "5".into(),
                },
            },
            proof: None,
            amount: 5,
            amount_commitment: None,
        };
        let envelope = AxtEnvelopeRecord {
            binding,
            lane,
            descriptor,
            touches: vec![touch_fragment],
            proofs: vec![proof_fragment],
            handles: vec![handle_fragment.clone()],
            commit_height: Some(1),
        };
        let snapshot = state.axt_policy_snapshot();
        let (_handle, time_source) = TimeSource::new_mock(Duration::from_millis(0));

        let first_block = build_block_with_envelope(
            envelope.clone(),
            snapshot.clone(),
            time_source.clone(),
            None,
        );
        let (committed_first, ledger_keys) =
            validate_and_apply_block(&mut state, first_block, envelope.clone(), snapshot.clone());

        let replay_key = AxtHandleReplayKey::from_handle(&handle_fragment.handle);
        assert!(
            ledger_keys.contains(&replay_key),
            "replay ledger should persist committed handle usage (keys={ledger_keys:?})"
        );
        let persisted_view = state.view();
        assert!(
            persisted_view
                .world()
                .axt_replay_ledger()
                .get(&replay_key)
                .is_some(),
            "replay ledger should persist committed handle usage"
        );
        drop(persisted_view);

        state.set_axt_policy(
            dsid,
            AxtPolicyEntry {
                manifest_root,
                target_lane: lane,
                min_handle_era: 1,
                min_sub_nonce: 1,
                current_slot: 0,
            },
        );

        let replay_block = build_block_with_envelope(
            envelope,
            snapshot,
            time_source,
            Some(committed_first.as_ref()),
        );
        let replay_state_block = state.block(replay_block.header());
        let err = validate_axt_envelopes(&replay_block, &replay_state_block).unwrap_err();
        match err {
            BlockValidationError::AxtEnvelopeValidationFailed(details) => {
                assert_eq!(details.reason, AxtRejectReason::ReplayCache);
                assert_eq!(details.dataspace, Some(dsid));
                assert_eq!(details.lane, Some(lane));
            }
            other => panic!("unexpected validation error: {other:?}"),
        }
    }

