    #[test]
    fn space_directory_manifest_expiry_rebuilds_bindings_and_emits_event() {
        let uaid = UniversalAccountId::from_hash(Hash::new(b"uaid::expiry"));
        let dataspace = DataSpaceId::new(11);

        let domain_id: DomainId = "wonderland".parse().expect("domain id");
        let keypair = KeyPair::random();
        let account_id = AccountId::new(keypair.public_key().clone());
        let account = new_account_in_domain(&account_id, &domain_id)
            .with_uaid(Some(uaid))
            .build(&account_id);
        let domain = Domain::new(domain_id).build(&account_id);

        let mut world = World::with([domain], [account], []);
        let manifest = AssetPermissionManifest {
            version: ManifestVersion::default(),
            uaid,
            dataspace,
            issued_ms: 0,
            activation_epoch: 5,
            expiry_epoch: Some(7),
            entries: Vec::new(),
        };
        let mut record = SpaceDirectoryManifestRecord::new(manifest);
        record.lifecycle.mark_activated(5);
        let mut set = SpaceDirectoryManifestSet::default();
        set.upsert(record);
        world
            .space_directory_manifests_mut_for_testing()
            .insert(uaid, set);

        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let state = State::new_for_testing(world, kura, query_handle);

        let header = BlockHeader::new(nonzero!(1_u64), None, None, None, 0, 0);
        let mut block = state.block(header);
        let mut stx = block.transaction();

        stx.world.rebuild_space_directory_bindings(uaid);
        assert!(
            stx.world.uaid_dataspaces().get(&uaid).is_some(),
            "bindings should be populated while manifest is active"
        );

        let expired_count = stx.world.expire_due_space_directory_manifests(
            7,
            &stx.nexus.lane_config,
            stx.axt_current_slot(),
        );
        assert_eq!(expired_count, 1, "expected one manifest to expire");

        assert!(
            stx.world.uaid_dataspaces().get(&uaid).is_none(),
            "bindings must be rebuilt after expiry"
        );

        let events = stx.world.take_external_events();
        assert!(
            events.iter().any(|event| {
                if let EventBox::Data(ev) = event {
                    if let data_pre::DataEvent::SpaceDirectory(space_event) = ev.as_ref() {
                        return matches!(
                            space_event,
                            SpaceDirectoryEvent::ManifestExpired(payload)
                                if payload.uaid == uaid && payload.dataspace == dataspace
                        );
                    }
                }
                false
            }),
            "expected manifest expiry event"
        );

        let manifest_set = stx
            .world
            .space_directory_manifests()
            .get(&uaid)
            .expect("manifest set to exist");
        let stored = manifest_set
            .get(&dataspace)
            .expect("manifest record to remain");
        assert_eq!(stored.lifecycle.expired_epoch, Some(7));
        assert!(!stored.is_active());

        // Subsequent epochs should not emit duplicate events.
        stx.world.take_external_events();
        let repeat_expired = stx.world.expire_due_space_directory_manifests(
            10,
            &stx.nexus.lane_config,
            stx.axt_current_slot(),
        );
        assert_eq!(repeat_expired, 0);
        assert!(stx.world.take_external_events().is_empty());
    }

    #[test]
    fn space_directory_manifest_revocation_refreshes_bindings_and_policy() {
        let uaid = UniversalAccountId::from_hash(Hash::new(b"uaid::revoke"));
        let dataspace = DataSpaceId::new(13);
        let lane_id = LaneId::new(9);
        let lane_catalog = LaneCatalog::new(
            nonzero!(10_u32),
            vec![LaneConfig {
                id: lane_id,
                dataspace_id: dataspace,
                alias: "lane9".into(),
                description: None,
                visibility: iroha_data_model::nexus::LaneVisibility::Public,
                lane_type: None,
                governance: None,
                settlement: None,
                storage: iroha_data_model::nexus::LaneStorageProfile::FullReplica,
                proof_scheme: DaProofScheme::default(),
                metadata: BTreeMap::new(),
            }],
        )
        .expect("lane catalog");
        let lane_config = RuntimeLaneConfig::from_catalog(&lane_catalog);

        let domain_id: DomainId = "wonderland".parse().expect("domain id");
        let keypair = KeyPair::random();
        let account_id = AccountId::new(keypair.public_key().clone());
        let account = new_account_in_domain(&account_id, &domain_id)
            .with_uaid(Some(uaid))
            .build(&account_id);
        let domain = Domain::new(domain_id).build(&account_id);

        let mut world = World::with([domain], [account], []);
        let manifest = AssetPermissionManifest {
            version: ManifestVersion::default(),
            uaid,
            dataspace,
            issued_ms: 0,
            activation_epoch: 1,
            expiry_epoch: Some(5),
            entries: Vec::new(),
        };
        let mut record = SpaceDirectoryManifestRecord::new(manifest);
        record.lifecycle.mark_activated(1);
        let manifest_hash = record.manifest_hash;
        let mut set = SpaceDirectoryManifestSet::default();
        set.upsert(record);
        world
            .space_directory_manifests_mut_for_testing()
            .insert(uaid, set);

        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let mut state = State::new_for_testing(world, kura, query_handle);
        {
            let nexus = state.nexus.get_mut();
            nexus.lane_config = lane_config;
        }

        let creation_time_ms = 17;
        let header = BlockHeader::new(nonzero!(1_u64), None, None, None, creation_time_ms, 0);
        let mut block = state.block(header);
        let mut stx = block.transaction();

        let snapshot = stx
            .rebuild_space_directory_bindings(uaid)
            .expect("policy snapshot to exist");
        let entry = snapshot
            .entries
            .first()
            .expect("snapshot to contain dataspace entry");
        let mut expected_root = [0u8; 32];
        expected_root.copy_from_slice(manifest_hash.as_ref());
        assert_eq!(entry.dsid, dataspace);
        assert_eq!(entry.policy.manifest_root, expected_root);
        assert_eq!(entry.policy.target_lane, lane_id);
        assert_eq!(entry.policy.current_slot, stx.axt_current_slot());
        assert!(
            stx.world.axt_policies().get(&dataspace).is_some(),
            "policy should be cached while manifest is active"
        );

        let revoked =
            SpaceDirectoryEvent::ManifestRevoked(data_pre::SpaceDirectoryManifestRevoked {
                dataspace,
                uaid,
                manifest_hash,
                revoked_epoch: 3,
                reason: Some("test revoke".into()),
            });
        stx.world.handle_space_directory_event(&revoked);

        assert!(
            stx.world.uaid_dataspaces().get(&uaid).is_none(),
            "bindings must be cleared after revocation"
        );
        assert!(
            stx.world.axt_policies().get(&dataspace).is_none(),
            "policy cache must drop revoked manifests"
        );
    }

    #[test]
    #[allow(clippy::too_many_lines)]
    fn space_directory_manifest_rotation_updates_policy_cache() {
        let uaid = UniversalAccountId::from_hash(Hash::new(b"uaid::rotate"));
        let dataspace = DataSpaceId::new(17);
        let lane_id = LaneId::new(4);
        let lane_catalog = LaneCatalog::new(
            nonzero!(5_u32),
            vec![LaneConfig {
                id: lane_id,
                dataspace_id: dataspace,
                alias: "lane4".into(),
                description: None,
                visibility: iroha_data_model::nexus::LaneVisibility::Public,
                lane_type: None,
                governance: None,
                settlement: None,
                storage: iroha_data_model::nexus::LaneStorageProfile::FullReplica,
                proof_scheme: DaProofScheme::default(),
                metadata: BTreeMap::new(),
            }],
        )
        .expect("lane catalog");
        let lane_config = RuntimeLaneConfig::from_catalog(&lane_catalog);

        let domain_id: DomainId = "rotate".parse().expect("domain id");
        let keypair = KeyPair::random();
        let account_id = AccountId::new(keypair.public_key().clone());
        let account = new_account_in_domain(&account_id, &domain_id)
            .with_uaid(Some(uaid))
            .build(&account_id);
        let domain = Domain::new(domain_id).build(&account_id);

        let mut world = World::with([domain], [account], []);
        let manifest_current = AssetPermissionManifest {
            version: ManifestVersion::default(),
            uaid,
            dataspace,
            issued_ms: 0,
            activation_epoch: 1,
            expiry_epoch: Some(6),
            entries: Vec::new(),
        };
        let mut record_current = SpaceDirectoryManifestRecord::new(manifest_current);
        record_current.lifecycle.mark_activated(1);
        let mut set = SpaceDirectoryManifestSet::default();
        set.upsert(record_current.clone());
        world
            .space_directory_manifests_mut_for_testing()
            .insert(uaid, set);

        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let mut state = State::new_for_testing(world, kura, query_handle);
        {
            let nexus = state.nexus.get_mut();
            nexus.lane_config = lane_config.clone();
        }

        let snapshot_current = state
            .refresh_axt_policies_from_directory()
            .expect("policy snapshot");
        let first_entry = snapshot_current
            .entries
            .iter()
            .find(|entry| entry.dsid == dataspace)
            .expect("dataspace entry present")
            .policy;
        let mut expected_root_current = [0u8; 32];
        expected_root_current.copy_from_slice(record_current.manifest_hash.as_ref());
        assert_eq!(first_entry.manifest_root, expected_root_current);
        assert_eq!(first_entry.min_handle_era, 1);
        assert_eq!(first_entry.target_lane, lane_id);

        let manifest_v2 = AssetPermissionManifest {
            version: ManifestVersion::default(),
            uaid,
            dataspace,
            issued_ms: 5,
            activation_epoch: 4,
            expiry_epoch: Some(10),
            entries: Vec::new(),
        };
        let mut record_v2 = SpaceDirectoryManifestRecord::new(manifest_v2);
        record_v2.lifecycle.mark_activated(4);
        {
            let registry = state.world.space_directory_manifests_mut_for_testing();
            let mut block = registry.block();
            let mut tx = block.transaction();
            let mut set = tx
                .view()
                .get(&uaid)
                .cloned()
                .expect("manifest registry present");
            set.upsert(record_v2.clone());
            tx.insert(uaid, set);
            tx.apply();
            block.commit();
        }

        let snapshot_v2 = state
            .refresh_axt_policies_from_directory()
            .expect("policy snapshot");
        let rotated_entry = snapshot_v2
            .entries
            .iter()
            .find(|entry| entry.dsid == dataspace)
            .expect("dataspace entry present after rotation")
            .policy;
        let mut expected_root_v2 = [0u8; 32];
        expected_root_v2.copy_from_slice(record_v2.manifest_hash.as_ref());
        assert_eq!(rotated_entry.manifest_root, expected_root_v2);
        assert_eq!(rotated_entry.min_handle_era, 4);
        assert_eq!(rotated_entry.target_lane, lane_id);

        let policies_view = state.world.axt_policies.view();
        let cached = policies_view
            .get(&dataspace)
            .expect("policy cached after rotation");
        assert_eq!(cached.manifest_root, expected_root_v2);
        assert_eq!(cached.min_handle_era, 4);
    }

    #[test]
    fn space_directory_zero_manifest_hash_is_ignored() {
        let uaid = UniversalAccountId::from_hash(Hash::new(b"uaid::zero-manifest"));
        let dataspace = DataSpaceId::new(19);
        let lane_id = LaneId::new(5);
        let lane_catalog = LaneCatalog::new(
            nonzero!(6_u32),
            vec![LaneConfig {
                id: lane_id,
                dataspace_id: dataspace,
                alias: "lane5".into(),
                description: None,
                visibility: iroha_data_model::nexus::LaneVisibility::Public,
                lane_type: None,
                governance: None,
                settlement: None,
                storage: iroha_data_model::nexus::LaneStorageProfile::FullReplica,
                proof_scheme: DaProofScheme::default(),
                metadata: BTreeMap::new(),
            }],
        )
        .expect("lane catalog");
        let lane_config = RuntimeLaneConfig::from_catalog(&lane_catalog);

        let domain_id: DomainId = "zero-hash".parse().expect("domain id");
        let keypair = KeyPair::random();
        let account_id = AccountId::new(keypair.public_key().clone());
        let account = new_account_in_domain(&account_id, &domain_id)
            .with_uaid(Some(uaid))
            .build(&account_id);
        let domain = Domain::new(domain_id).build(&account_id);

        let mut world = World::with([domain], [account], []);
        let manifest = AssetPermissionManifest {
            version: ManifestVersion::default(),
            uaid,
            dataspace,
            issued_ms: 0,
            activation_epoch: 1,
            expiry_epoch: Some(4),
            entries: Vec::new(),
        };
        let mut record = SpaceDirectoryManifestRecord::new(manifest);
        record.lifecycle.mark_activated(1);
        // Corrupt the manifest hash to simulate a stale/invalid manifest payload.
        record.manifest_hash = Hash::prehashed([0; Hash::LENGTH]);
        let digest = record.manifest_hash.as_ref();
        assert!(
            digest[..Hash::LENGTH - 1].iter().all(|byte| *byte == 0)
                && digest[Hash::LENGTH - 1] == 1,
            "test setup must install a zeroed manifest hash sentinel"
        );
        let mut set = SpaceDirectoryManifestSet::default();
        set.upsert(record);
        world
            .space_directory_manifests_mut_for_testing()
            .insert(uaid, set);

        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let mut state = State::new_for_testing(world, kura, query_handle);
        {
            let nexus = state.nexus.get_mut();
            nexus.lane_config = lane_config;
        }

        let header = BlockHeader::new(nonzero!(1_u64), None, None, None, 0, 0);
        let mut block = state.block(header);
        let mut stx = block.transaction();

        stx.world.rebuild_space_directory_bindings(uaid);
        let snapshot = stx.refresh_axt_policies_from_directory();

        assert!(
            stx.world.uaid_dataspaces().get(&uaid).is_none(),
            "zero-hash manifests must not create UAID bindings"
        );
        assert!(
            stx.world.axt_policies().get(&dataspace).is_none(),
            "zero-hash manifests must not populate policy cache entries"
        );
        assert!(
            snapshot.is_none(),
            "zero-hash manifests should not produce a policy snapshot"
        );
    }

