    #[allow(clippy::too_many_lines)]
    #[test]
    fn detached_merge_matches_sequential_state_and_events() {
        use iroha_data_model::{
            isi::{Mint, RemoveKeyValue, SetKeyValue},
            prelude::*,
        };
        use iroha_primitives::{json::Json, numeric::Numeric};
        use iroha_test_samples::ALICE_ID;

        fn build_world() -> (World, DomainId, AssetDefinitionId, AssetId, AccountId) {
            let domain_id: DomainId = "wonderland".parse().expect("domain id");
            let domain = Domain::new(domain_id.clone()).build(&ALICE_ID);
            let account = new_sample_account(&ALICE_ID).build(&ALICE_ID);
            let asset_def_id: AssetDefinitionId = iroha_data_model::asset::AssetDefinitionId::new(
                "wonderland".parse().unwrap(),
                "rose".parse().unwrap(),
            );
            let asset_def = {
                let __asset_definition_id = asset_def_id.clone();
                AssetDefinition::new(__asset_definition_id.clone(), NumericSpec::default())
                    .with_name(__asset_definition_id.name().to_string())
            }
            .build(&ALICE_ID);
            let asset_id = AssetId::of(asset_def_id.clone(), ALICE_ID.clone());
            let asset = Asset::new(asset_id.clone(), Numeric::new(0, 0));

            let world = World::with_assets([domain], [account], [asset_def], [asset], []);
            (world, domain_id, asset_def_id, asset_id, ALICE_ID.clone())
        }

        let header = BlockHeader::new(nonzero!(1_u64), None, None, None, 0, 0);

        // Sequential application (reference)
        let (world_seq, domain_id, asset_def_id, asset_id, authority) = build_world();
        let account_key: Name = "account-note".parse().expect("account name");
        let domain_key: Name = "domain-quota".parse().expect("domain name");
        let asset_def_key: Name = "ad-note".parse().expect("asset def name");
        let kura_seq = Kura::blank_kura_for_testing();
        let query_seq = LiveQueryStore::start_test();
        #[cfg(feature = "telemetry")]
        let state_seq = State::with_telemetry(
            world_seq,
            kura_seq,
            query_seq,
            crate::telemetry::StateTelemetry::default(),
        );
        #[cfg(not(feature = "telemetry"))]
        let state_seq = State::new(world_seq, kura_seq, query_seq);
        let mut block_seq = state_seq.block(header);
        {
            let mut stx = block_seq.transaction();
            Mint::asset_numeric(5_u32, asset_id.clone())
                .execute(&authority, &mut stx)
                .expect("mint");
            SetKeyValue::account(authority.clone(), account_key.clone(), Json::new(1u32))
                .execute(&authority, &mut stx)
                .expect("account kv insert");
            RemoveKeyValue::account(authority.clone(), account_key.clone())
                .execute(&authority, &mut stx)
                .expect("account kv removal");
            SetKeyValue::domain(domain_id.clone(), domain_key.clone(), Json::new(7u32))
                .execute(&authority, &mut stx)
                .expect("domain kv insert");
            SetKeyValue::asset_definition(
                asset_def_id.clone(),
                asset_def_key.clone(),
                Json::new("memo"),
            )
            .execute(&authority, &mut stx)
            .expect("asset definition kv insert");
            stx.apply();
        }
        let events_seq = block_seq.world.take_external_events();
        block_seq.commit().expect("commit sequential block");

        // Detached delta merge
        let (world_det, _, _, _, _) = build_world();
        let kura_det = Kura::blank_kura_for_testing();
        let query_det = LiveQueryStore::start_test();
        #[cfg(feature = "telemetry")]
        let state_det = State::with_telemetry(
            world_det,
            kura_det,
            query_det,
            crate::telemetry::StateTelemetry::default(),
        );
        #[cfg(not(feature = "telemetry"))]
        let state_det = State::new(world_det, kura_det, query_det);
        let mut block_det = state_det.block(header);
        let mut delta = DetachedStateTransactionDelta::default();
        let mint_amount = Numeric::new(5, 0);
        delta.add_asset_add(asset_id.clone(), mint_amount.clone());
        delta.add_total_add(asset_def_id.clone(), mint_amount.clone());
        delta.set_account_kv(authority.clone(), account_key.clone(), Json::new(1u32));
        delta.remove_account_kv(authority.clone(), account_key.clone());
        delta.set_domain_kv(domain_id.clone(), domain_key.clone(), Json::new(7u32));
        delta.set_asset_def_kv(
            asset_def_id.clone(),
            asset_def_key.clone(),
            Json::new("memo"),
        );
        let _ = delta
            .merge_into(&mut block_det, &authority)
            .expect("delta merge succeeds");
        let events_det = block_det.world.take_external_events();
        block_det.commit().expect("commit detached block");

        // Compare events emitted by both paths
        assert_eq!(
            events_seq, events_det,
            "event sequences from sequential and detached paths must match"
        );

        // Compare resulting state snapshots
        let view_seq = state_seq.view();
        let view_det = state_det.view();

        let balance_seq = view_seq
            .world()
            .assets()
            .get(&asset_id)
            .map(|v| v.clone().into_inner())
            .expect("asset exists after sequential");
        let balance_det = view_det
            .world()
            .assets()
            .get(&asset_id)
            .map(|v| v.clone().into_inner())
            .expect("asset exists after detached merge");
        assert_eq!(balance_seq, balance_det, "balances must match");

        let account_seq = view_seq
            .world()
            .accounts()
            .get(&authority)
            .expect("account exists sequential");
        let account_det = view_det
            .world()
            .accounts()
            .get(&authority)
            .expect("account exists detached");
        assert!(
            account_seq.metadata().is_empty(),
            "sequential metadata removed via remove kv"
        );
        assert!(
            account_det.metadata().is_empty(),
            "detached metadata removed via remove kv"
        );

        let domain_seq = view_seq
            .world()
            .domains()
            .get(&domain_id)
            .expect("domain exists sequential");
        let domain_det = view_det
            .world()
            .domains()
            .get(&domain_id)
            .expect("domain exists detached");
        assert_eq!(
            domain_seq.metadata.get(&domain_key).cloned(),
            domain_det.metadata.get(&domain_key).cloned(),
            "domain metadata must match"
        );

        let asset_def_seq = view_seq
            .world()
            .asset_definitions()
            .get(&asset_def_id)
            .expect("asset def exists sequential");
        let asset_def_det = view_det
            .world()
            .asset_definitions()
            .get(&asset_def_id)
            .expect("asset def exists detached");
        assert_eq!(
            asset_def_seq.metadata().get(&asset_def_key).cloned(),
            asset_def_det.metadata().get(&asset_def_key).cloned(),
            "asset definition metadata must match"
        );
    }

    #[test]
    fn capture_exec_witness_stashes_reads_and_writes() {
        use iroha_data_model::{asset::AssetDefinitionId, asset::AssetId, block::BlockHeader};

        let world = World::default();
        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let state = State::new(world, kura, query_handle);
        let header = BlockHeader::new(nonzero!(1_u64), None, None, None, 0, 0);
        let mut state_block = state.block(header);

        let _guard = crate::sumeragi::witness::exec_witness_guard();
        crate::sumeragi::witness::start_block();
        let asset_def_id =
            AssetDefinitionId::new("wonderland".parse().unwrap(), "rose".parse().unwrap());
        let asset_id = AssetId::new(asset_def_id, ALICE_ID.clone());
        crate::sumeragi::witness::record_write_asset(
            &asset_id,
            &iroha_primitives::numeric::Numeric::from(42u32),
        );

        state_block.capture_exec_witness();
        let witness = state_block.take_exec_witness().expect("witness captured");
        assert_eq!(witness.writes.len(), 1);
        assert!(state_block.take_exec_witness().is_none());
    }

