    #[test]
    fn time_trigger_failure_populates_entrypoint_instructions() -> Result<()> {
        let kura = Kura::blank_kura_for_testing();
        let query = LiveQueryStore::start_test();
        let state = State::new(World::default(), kura, query);

        let header = BlockHeader::new(NonZeroU64::new(1).unwrap(), None, None, None, 0, 0);
        let mut state_block = state.block(header);

        {
            let mut stx = state_block.transaction();
            let domain_id: DomainId = "wonderland".parse()?;
            Register::domain(Domain::new(domain_id.clone()))
                .execute(&SAMPLE_GENESIS_ACCOUNT_ID, &mut stx)?;
            Register::account(new_sample_account(&ALICE_ID))
                .execute(&SAMPLE_GENESIS_ACCOUNT_ID, &mut stx)?;
            Register::asset_definition({
                let __asset_definition_id = iroha_data_model::asset::AssetDefinitionId::new(
                    "wonderland".parse()?,
                    "rose".parse()?,
                );
                AssetDefinition::numeric(__asset_definition_id.clone())
                    .with_name(__asset_definition_id.name().to_string())
            })
            .execute(&SAMPLE_GENESIS_ACCOUNT_ID, &mut stx)?;
            stx.apply();
        }

        let trigger_id: TriggerId = "failing_time_trigger".parse()?;
        let asset_def_id: AssetDefinitionId =
            iroha_data_model::asset::AssetDefinitionId::new("wonderland".parse()?, "rose".parse()?);
        let alice_asset = AssetId::new(asset_def_id.clone(), ALICE_ID.clone());
        let failing_instruction: InstructionBox =
            Transfer::asset_numeric(alice_asset, 1_u32, BOB_ID.clone()).into();
        let trigger = Trigger::new(
            trigger_id.clone(),
            Action::new(
                vec![failing_instruction.clone()],
                Repeats::Exactly(1),
                ALICE_ID.clone(),
                TimeEventFilter(ExecutionTime::Schedule(Schedule {
                    start_ms: 0,
                    period_ms: Some(1_000),
                })),
            ),
        );

        {
            let mut stx = state_block.transaction();
            Register::trigger(trigger).execute(&ALICE_ID, &mut stx)?;
            stx.apply();
        }

        let time_event = state_block.create_time_event(&header);
        let action = {
            state_block
                .world
                .triggers()
                .time_triggers()
                .get(&trigger_id)
                .expect("time trigger registered")
                .clone()
        };

        let (entrypoint, result) =
            state_block.execute_time_trigger(&trigger_id, &action, &time_event, 0);

        assert!(result.is_err(), "expected trigger execution to fail");
        let expected_step = ExecutionStep(ConstVec::from(vec![failing_instruction]));
        assert_eq!(entrypoint.instructions, expected_step);
        assert_eq!(entrypoint.id, trigger_id);
        assert_eq!(entrypoint.authority, *ALICE_ID);

        Ok(())
    }

    #[test]
    fn time_trigger_nft_seq_base_strides_by_256() {
        let base0 = StateBlock::time_trigger_nft_seq_base(42, 0);
        let base1 = StateBlock::time_trigger_nft_seq_base(42, 1);
        let base2 = StateBlock::time_trigger_nft_seq_base(42, 2);
        assert_eq!(base1, base0.saturating_add(256));
        assert_eq!(base2, base1.saturating_add(256));

        let next_block = StateBlock::time_trigger_nft_seq_base(43, 0);
        assert!(next_block > base2);
    }

