    #[test]
    fn block_sweeps_expired_governance_locks_and_records_height() {
        let kura = Kura::blank_kura_for_testing();
        let query = LiveQueryStore::start_test();
        let state = State::new_for_testing(World::default(), kura, query);

        let referendum_id = "0xdeadbeef".to_owned();
        let voter = (*ALICE_ID).clone();

        {
            let mut world_block = state.world.block();
            let mut locks = GovernanceLocksForReferendum::default();
            locks.locks.insert(
                voter.clone(),
                GovernanceLockRecord {
                    owner: voter.clone(),
                    amount: 42,
                    slashed: 0,
                    expiry_height: 5,
                    direction: 0,
                    duration_blocks: 0,
                },
            );
            world_block
                .governance_locks
                .insert(referendum_id.clone(), locks);
            *world_block.governance_last_unlock_sweep_height.get_mut() = 1;
            world_block.commit();
        }

        let header = BlockHeader::new(nonzero!(10_u64), None, None, None, 0, 0);
        let block = state.block(header);

        let recorded_height = *block.world.governance_last_unlock_sweep_height;
        assert_eq!(
            recorded_height, 10,
            "sweep height must match current block height"
        );
        let locks_after = block
            .world
            .governance_locks
            .get(&referendum_id)
            .expect("referendum entry should remain present");
        assert!(
            locks_after.locks.is_empty(),
            "expired locks must be removed during sweep"
        );
    }

    #[test]
    fn transaction_failure_rolls_back_asset_world_and_trigger_changes() {
        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let state = State::new(World::default(), kura, query_handle);

        let header = BlockHeader::new(NonZeroU64::new(1).unwrap(), None, None, None, 0, 0);
        let mut state_block = state.block(header);
        let mut stx = state_block.transaction();

        let domain_id: DomainId = "wonderland".parse().unwrap();
        Register::domain(Domain::new(domain_id.clone()))
            .execute(&ALICE_ID, &mut stx)
            .unwrap();
        Register::account(new_sample_account(&ALICE_ID))
            .execute(&ALICE_ID, &mut stx)
            .unwrap();
        let asset_def_id: AssetDefinitionId = iroha_data_model::asset::AssetDefinitionId::new(
            "wonderland".parse().unwrap(),
            "rose".parse().unwrap(),
        );
        Register::asset_definition({
            let __asset_definition_id = asset_def_id.clone();
            AssetDefinition::numeric(__asset_definition_id.clone())
                .with_name(__asset_definition_id.name().to_string())
        })
        .execute(&ALICE_ID, &mut stx)
        .unwrap();

        stx.apply();
        state_block.commit().unwrap();

        let asset_id = AssetId::new(asset_def_id.clone(), ALICE_ID.clone());
        let key: Name = "temp".parse().unwrap();
        let trigger_id: TriggerId = "rollback_guard".parse().unwrap();

        {
            let header = BlockHeader::new(NonZeroU64::new(2).unwrap(), None, None, None, 0, 0);
            let mut state_block = state.block(header);
            {
                let mut stx = state_block.transaction();
                Mint::asset_numeric(1_u32, asset_id.clone())
                    .execute(&ALICE_ID, &mut stx)
                    .unwrap();
                SetKeyValue::account(
                    ALICE_ID.clone(),
                    key.clone(),
                    Json::from(norito::json!("temp")),
                )
                .execute(&ALICE_ID, &mut stx)
                .unwrap();
                let trigger_action = Action::new(
                    vec![InstructionBox::from(Burn::asset_numeric(
                        1_u32,
                        asset_id.clone(),
                    ))],
                    Repeats::Exactly(1),
                    ALICE_ID.clone(),
                    ExecuteTriggerEventFilter::new()
                        .for_trigger(trigger_id.clone())
                        .under_authority(ALICE_ID.clone()),
                );
                Register::trigger(Trigger::new(trigger_id.clone(), trigger_action))
                    .execute(&ALICE_ID, &mut stx)
                    .unwrap();
                let duplicate = Register::asset_definition({
                    let __asset_definition_id = asset_def_id.clone();
                    AssetDefinition::numeric(__asset_definition_id.clone())
                        .with_name(__asset_definition_id.name().to_string())
                })
                .execute(&ALICE_ID, &mut stx);
                assert!(
                    duplicate.is_err(),
                    "expected duplicate asset definition to fail"
                );
            }
        }

        let view = state.view();
        assert!(
            view.world.asset(&asset_id).is_err(),
            "asset mint should not persist after transaction failure"
        );
        let metadata = view
            .world
            .map_account(&ALICE_ID, |account| {
                account.value().metadata().get(&key).cloned()
            })
            .unwrap();
        assert!(
            metadata.is_none(),
            "account metadata change should rollback on failure"
        );
        assert!(
            view.world.triggers().ids().get(&trigger_id).is_none(),
            "trigger registration should rollback on failure"
        );
    }

    #[test]
    fn execute_called_trigger_failure_rolls_back_state() {
        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let state = State::new(World::default(), kura, query_handle);

        let trigger_id: TriggerId = "rollback_trigger".parse().unwrap();
        let asset_definition_id: AssetDefinitionId =
            iroha_data_model::asset::AssetDefinitionId::new(
                "wonderland".parse().unwrap(),
                "xor".parse().unwrap(),
            );

        // Commit initial domain, account, and the by-call trigger.
        let block = new_dummy_block_with_payload(|header| {
            header.set_height(NonZeroU64::new(1).unwrap());
        });
        {
            let mut state_block = state.block(block.as_ref().header());
            let mut stx = state_block.transaction();
            Register::domain(Domain::new("wonderland".parse().unwrap()))
                .execute(&ALICE_ID, &mut stx)
                .unwrap();
            Register::account(new_sample_account(&ALICE_ID))
                .execute(&ALICE_ID, &mut stx)
                .unwrap();

            let create_asset = Register::asset_definition({
                let __asset_definition_id = asset_definition_id.clone();
                AssetDefinition::numeric(__asset_definition_id.clone())
                    .with_name(__asset_definition_id.name().to_string())
            });
            let fail_isi = Unregister::domain("dummy".parse().unwrap());
            let instructions: [InstructionBox; 2] = [create_asset.into(), fail_isi.into()];
            let trigger = Trigger::new(
                trigger_id.clone(),
                Action::new(
                    instructions,
                    Repeats::Indefinitely,
                    ALICE_ID.clone(),
                    ExecuteTriggerEventFilter::new()
                        .for_trigger(trigger_id.clone())
                        .under_authority(ALICE_ID.clone()),
                ),
            );
            Register::trigger(trigger)
                .execute(&ALICE_ID, &mut stx)
                .unwrap();

            stx.apply();
            state_block.commit().unwrap();
        }

        // Execute the trigger and expect rejection; state changes must rollback.
        let block = new_dummy_block_with_payload(|header| {
            header.set_height(NonZeroU64::new(2).unwrap());
        });
        {
            let mut state_block = state.block(block.as_ref().header());
            let mut stx = state_block.transaction();
            let event = ExecuteTriggerEvent {
                trigger_id: trigger_id.clone(),
                authority: ALICE_ID.clone(),
                args: Json::default(),
            };
            let err = stx
                .execute_called_trigger(&trigger_id, &event)
                .expect_err("trigger should fail to execute");
            match err {
                TransactionRejectionReason::Validation(
                    ValidationFail::InstructionFailed(InstructionExecutionError::Find(
                        FindError::Domain(_),
                    ))
                    | ValidationFail::NotPermitted(_),
                ) => {}
                other => panic!("unexpected rejection: {other:?}"),
            }
        }

        let view = state.view();
        assert!(
            view.world.asset_definition(&asset_definition_id).is_err(),
            "asset definition created by a failing trigger must not persist",
        );
    }

    #[test]
    fn execute_called_trigger_accepts_staged_mint_like_json_args() {
        use iroha_data_model::{
            events::execute_trigger::{ExecuteTriggerEvent, ExecuteTriggerEventFilter},
            transaction::{Executable, IvmBytecode},
            trigger::{
                Trigger,
                action::{Action, Repeats},
            },
        };
        use ivm::KotodamaCompiler;

        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let state = State::new(World::default(), kura, query_handle);

        let trigger_id: TriggerId = "staged_mint_like".parse().unwrap();
        let src = r#"
            seiyaku StagedMintRequest {
              state int MintRequestNextSequence;
              state MintRequestSequenceById: Map<Name, int>;
              state MintRequestSequences: Map<int, int>;
              state MintRequestRequestIds: Map<int, Name>;
              state MintRequestFiIds: Map<int, Name>;
              state MintRequestFiAuthorities: Map<int, AccountId>;
              state MintRequestToAccounts: Map<int, AccountId>;
              state MintRequestAmounts: Map<int, int>;
              state MintRequestRequestedBy: Map<int, Json>;
              state MintRequestStates: Map<int, int>;
              state MintRequestCreatedAt: Map<int, int>;
              state MintRequestExpiresAt: Map<int, int>;
              state MintRequestFinalizedAt: Map<int, int>;
              state MintRequestCanceledAt: Map<int, int>;

              fn update_record(sequence: int,
                               request_id: Name,
                               fi_id: Name,
                               fi_multisig_account_id: AccountId,
                               to_account_id: AccountId,
                               amount_i64: int,
                               requested_by_actor_id: Json,
                               state_code: int,
                               created_at_ms: int,
                               expires_at_ms: int,
                               finalized_at_ms: int,
                               canceled_at_ms: int) {
                MintRequestSequences[sequence] = sequence;
                MintRequestRequestIds[sequence] = request_id;
                MintRequestFiIds[sequence] = fi_id;
                MintRequestFiAuthorities[sequence] = fi_multisig_account_id;
                MintRequestToAccounts[sequence] = to_account_id;
                MintRequestAmounts[sequence] = amount_i64;
                MintRequestRequestedBy[sequence] = requested_by_actor_id;
                MintRequestStates[sequence] = state_code;
                MintRequestCreatedAt[sequence] = created_at_ms;
                MintRequestExpiresAt[sequence] = expires_at_ms;
                MintRequestFinalizedAt[sequence] = finalized_at_ms;
                MintRequestCanceledAt[sequence] = canceled_at_ms;
              }

              #[access(read="*", write="*")]
              kotoage fn run() {
                let ev = trigger_event();
                let action_key = name("action");
                let request_id_key = name("request_id");
                let fi_id_key = name("fi_id");
                let to_account_id_key = name("to_account_id");
                let amount_i64_key = name("amount_i64");
                let requested_by_actor_id_key = name("requested_by_actor_id");
                let created_at_ms_key = name("created_at_ms");
                let expires_at_ms_key = name("expires_at_ms");

                let action = json_get_name(ev, action_key);

                if (action == name("create")) {
                  let request_id = json_get_name(ev, request_id_key);
                  assert(!contains(MintRequestSequenceById, request_id), "mint request already exists");

                  let sequence = MintRequestNextSequence + 1;
                  let fi_id = json_get_name(ev, fi_id_key);
                  let to_account_id = json_get_account_id(ev, to_account_id_key);
                  let amount_i64 = json_get_int(ev, amount_i64_key);
                  let requested_by_actor_id = json_get_json(ev, requested_by_actor_id_key);
                  let created_at_ms = json_get_int(ev, created_at_ms_key);
                  let expires_at_ms = json_get_int(ev, expires_at_ms_key);

                  MintRequestNextSequence = sequence;
                  MintRequestSequenceById[request_id] = sequence;
                  update_record(sequence,
                                request_id,
                                fi_id,
                                to_account_id,
                                to_account_id,
                                amount_i64,
                                requested_by_actor_id,
                                0,
                                created_at_ms,
                                expires_at_ms,
                                0,
                                0);
                  return;
                }

                assert(false, "unsupported staged mint action");
              }
            }
        "#;
        let program = KotodamaCompiler::new()
            .compile_source(&src)
            .expect("compile staged-mint-like contract");
        let bytecode = IvmBytecode::from_compiled(program);

        let block1 = new_dummy_block_with_payload(|header| {
            header.set_height(NonZeroU64::new(1).unwrap());
            header.creation_time_ms = 1;
        });
        {
            let mut state_block = state.block(block1.as_ref().header());
            let mut stx = state_block.transaction();

            Register::domain(Domain::new("wonderland".parse().unwrap()))
                .execute(&ALICE_ID, &mut stx)
                .unwrap();
            Register::account(new_sample_account(&ALICE_ID))
                .execute(&ALICE_ID, &mut stx)
                .unwrap();
            Register::account(new_sample_account(&BOB_ID))
                .execute(&ALICE_ID, &mut stx)
                .unwrap();
            Grant::account_permission(
                Permission::new("staged_mint_request_run".into(), Json::new(())),
                ALICE_ID.clone(),
            )
            .execute(&ALICE_ID, &mut stx)
            .unwrap();

            let trigger = Trigger::new(
                trigger_id.clone(),
                Action::new(
                    Executable::Ivm(bytecode),
                    Repeats::Indefinitely,
                    ALICE_ID.clone(),
                    ExecuteTriggerEventFilter::new()
                        .for_trigger(trigger_id.clone())
                        .under_authority(ALICE_ID.clone()),
                ),
            );
            Register::trigger(trigger)
                .execute(&ALICE_ID, &mut stx)
                .unwrap();

            stx.apply();
            state_block.commit().unwrap();
        }

        let block2 = new_dummy_block_with_payload(|header| {
            header.set_height(NonZeroU64::new(2).unwrap());
            header.creation_time_ms = 2;
        });
        {
            let mut state_block = state.block(block2.as_ref().header());
            let mut stx = state_block.transaction();
            let opaque_asset_id = AssetDefinitionId::from_uuid_bytes([
                0x2e, 0x3d, 0x34, 0xbe, 0xb8, 0xa8, 0x42, 0x39, 0xb3, 0xd9, 0x59, 0x07, 0x70, 0xf1,
                0x18, 0x9e,
            ])
            .expect("opaque asset definition id");
            let args_json = format!(
                r#"{{"action":"create","request_id":"cd38ea58-bc66-4844-921f-22af49b6cf3d","asset_id":"{}","asset_definition_blob_hex":"","fi_id":"hbl","to_account_id":"{}","amount_i64":53378,"requested_by_actor_id":"operator1@hbl","created_at_ms":1773904751245,"expires_at_ms":1773905351245}}"#,
                opaque_asset_id,
                (*BOB_ID).to_string()
            );
            let event = ExecuteTriggerEvent {
                trigger_id: trigger_id.clone(),
                authority: ALICE_ID.clone(),
                args: Json::from_string_unchecked(args_json),
            };
            eprintln!("before execute_called_trigger");
            stx.execute_called_trigger(&trigger_id, &event)
                .expect("staged-mint-like trigger should accept live create args");
            eprintln!("after execute_called_trigger");
            stx.apply();
            state_block.commit().unwrap();
        }
    }

    #[allow(clippy::too_many_lines)]
    #[test]
    fn execute_data_trigger_supports_alias_resolve_and_json_amount_transfer() {
        use iroha_data_model::{
            account::rekey::AccountLabel,
            events::data::prelude as data_pre,
            permission::Permission,
            transaction::{Executable, IvmBytecode},
            trigger::{
                Trigger,
                action::{Action, Repeats},
            },
        };
        use iroha_primitives::json::Json;
        use iroha_primitives::numeric::Numeric;
        use ivm::KotodamaCompiler;

        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let state = State::new(World::default(), kura, query_handle);

        let domain_id: DomainId = "wonderland".parse().unwrap();
        let rose_def_id: AssetDefinitionId = iroha_data_model::asset::AssetDefinitionId::new(
            domain_id.clone(),
            "rose".parse().unwrap(),
        );
        let gold_def_id: AssetDefinitionId = iroha_data_model::asset::AssetDefinitionId::new(
            domain_id.clone(),
            "gold".parse().unwrap(),
        );
        let gold_source = AssetId::new(gold_def_id.clone(), ALICE_ID.clone());
        let gold_target = AssetId::new(gold_def_id.clone(), BOB_ID.clone());
        let rose_source = AssetId::new(rose_def_id.clone(), ALICE_ID.clone());
        let rose_target = AssetId::new(rose_def_id.clone(), BOB_ID.clone());
        let trigger_id: TriggerId = "alias_json_transfer".parse().unwrap();
        let banking_label =
            AccountLabel::new(domain_id.clone(), "banking".parse().expect("banking label"));

        let src = r#"
            seiyaku AliasTransfer {
              #[access(read="*", write="*")]
              kotoage fn run() permission(alias_transfer_run) {
                let ev = trigger_event();
                if (json_get_name(ev, name("kind")) != name("asset_change")) {
                  return;
                }
                if (json_get_name(ev, name("op")) != name("added")) {
                  return;
                }
                let dst_domain = json_get_name(ev, name("account_domain"));
                let dst = json_get_account_id(ev, name("account_id"));
                let amount = json_get_int(ev, name("amount_i64"));
                if (amount <= 0) {
                  return;
                }
                let src = resolve_account_alias("banking@wonderland.universal");
                let payout = amount * 76;
                if (dst_domain != name("wonderland")) {
                  return;
                }
                transfer_asset(dst, src, asset_definition("__ROSE_ASSET_DEFINITION_ID__"), amount);
                transfer_asset(src, dst, asset_definition("__GOLD_ASSET_DEFINITION_ID__"), payout);
              }
            }
        "#
        .replace("__ROSE_ASSET_DEFINITION_ID__", &rose_def_id.to_string())
        .replace("__GOLD_ASSET_DEFINITION_ID__", &gold_def_id.to_string());
        let program = KotodamaCompiler::new()
            .compile_source(&src)
            .expect("compile alias transfer contract");
        let bytecode = IvmBytecode::from_compiled(program);

        let block1 = new_dummy_block_with_payload(|header| {
            header.set_height(NonZeroU64::new(1).unwrap());
            header.creation_time_ms = 1;
        });
        {
            let mut state_block = state.block(block1.as_ref().header());
            let mut stx = state_block.transaction();

            Register::domain(Domain::new(domain_id.clone()))
                .execute(&ALICE_ID, &mut stx)
                .unwrap();
            Register::account(new_sample_account(&ALICE_ID))
                .execute(&ALICE_ID, &mut stx)
                .unwrap();
            Register::account(new_sample_account(&BOB_ID))
                .execute(&ALICE_ID, &mut stx)
                .unwrap();
            Register::asset_definition({
                let __asset_definition_id = rose_def_id.clone();
                AssetDefinition::numeric(__asset_definition_id.clone())
                    .with_name(__asset_definition_id.name().to_string())
            })
            .execute(&ALICE_ID, &mut stx)
            .unwrap();
            Register::asset_definition({
                let __asset_definition_id = gold_def_id.clone();
                AssetDefinition::numeric(__asset_definition_id.clone())
                    .with_name(__asset_definition_id.name().to_string())
            })
            .execute(&ALICE_ID, &mut stx)
            .unwrap();
            Mint::asset_numeric(1_000_u32, gold_source.clone())
                .execute(&ALICE_ID, &mut stx)
                .unwrap();
            Grant::account_permission(
                Permission::new("alias_transfer_run".into(), Json::new(())),
                ALICE_ID.clone(),
            )
            .execute(&ALICE_ID, &mut stx)
            .unwrap();
            Grant::account_permission(
                Permission::from(
                    iroha_executor_data_model::permission::account::CanManageAccountAlias {
                        scope: iroha_executor_data_model::permission::account::AccountAliasPermissionScope::Dataspace(
                            iroha_data_model::nexus::DataSpaceId::GLOBAL,
                        ),
                    },
                ),
                ALICE_ID.clone(),
            )
            .execute(&ALICE_ID, &mut stx)
            .unwrap();
            Grant::account_permission(
                Permission::from(
                    iroha_executor_data_model::permission::account::CanManageAccountAlias {
                        scope: iroha_executor_data_model::permission::account::AccountAliasPermissionScope::Domain(
                            domain_id.clone(),
                        ),
                    },
                ),
                ALICE_ID.clone(),
            )
            .execute(&ALICE_ID, &mut stx)
            .unwrap();
            Grant::account_permission(
                Permission::from(
                    iroha_executor_data_model::permission::account::CanResolveAccountAlias {
                        scope: iroha_executor_data_model::permission::account::AccountAliasPermissionScope::Dataspace(
                            iroha_data_model::nexus::DataSpaceId::GLOBAL,
                        ),
                    },
                ),
                ALICE_ID.clone(),
            )
            .execute(&ALICE_ID, &mut stx)
            .unwrap();
            Grant::account_permission(
                Permission::from(
                    iroha_executor_data_model::permission::account::CanResolveAccountAlias {
                        scope: iroha_executor_data_model::permission::account::AccountAliasPermissionScope::Domain(
                            domain_id.clone(),
                        ),
                    },
                ),
                ALICE_ID.clone(),
            )
            .execute(&ALICE_ID, &mut stx)
            .unwrap();
            iroha_data_model::isi::domain_link::SetAccountLabel {
                account: ALICE_ID.clone(),
                label: banking_label.clone(),
            }
            .execute(&ALICE_ID, &mut stx)
            .unwrap();

            let trigger = Trigger::new(
                trigger_id.clone(),
                Action::new(
                    Executable::Ivm(bytecode),
                    Repeats::Indefinitely,
                    ALICE_ID.clone(),
                    data_pre::DataEventFilter::Asset(
                        data_pre::AssetEventFilter::new()
                            .for_events(data_pre::AssetEventSet::Added)
                            .for_asset(rose_target.clone()),
                    ),
                ),
            );
            Register::trigger(trigger)
                .execute(&ALICE_ID, &mut stx)
                .unwrap();

            stx.apply();
            state_block.commit().unwrap();
        }

        let block2 = new_dummy_block_with_payload(|header| {
            header.set_height(NonZeroU64::new(2).unwrap());
            header.creation_time_ms = 2;
        });
        {
            let mut state_block = state.block(block2.as_ref().header());
            let mut stx = state_block.transaction();

            Mint::asset_numeric(5_u32, rose_target.clone())
                .execute(&ALICE_ID, &mut stx)
                .unwrap();

            let steps = stx
                .execute_data_triggers_dfs(&ALICE_ID)
                .expect("data trigger should execute transfer path");
            assert_eq!(steps.len(), 1, "expected one data trigger execution");

            stx.apply();
            state_block.commit().unwrap();
        }

        let view = state.view();
        let bob_gold = view
            .world
            .asset(&gold_target)
            .expect("trigger should credit gold to bob");
        assert_eq!(&**bob_gold.value(), &Numeric::from(380_u32));
        let alice_gold = view
            .world
            .asset(&gold_source)
            .expect("trigger should debit gold from the reserve");
        assert_eq!(&**alice_gold.value(), &Numeric::from(620_u32));
        let alice_rose = view
            .world
            .asset(&rose_source)
            .expect("trigger should collect rose into the reserve");
        assert_eq!(&**alice_rose.value(), &Numeric::from(5_u32));
    }

    #[test]
    fn detached_execute_called_trigger_failure_rolls_back_state() {
        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let state = State::new(World::default(), kura, query_handle);

        let trigger_id: TriggerId = "rollback_trigger_detached".parse().unwrap();
        let asset_definition_id: AssetDefinitionId =
            iroha_data_model::asset::AssetDefinitionId::new(
                "wonderland".parse().unwrap(),
                "xor".parse().unwrap(),
            );

        // Commit initial domain, account, and the by-call trigger.
        let block = new_dummy_block_with_payload(|header| {
            header.set_height(NonZeroU64::new(1).unwrap());
        });
        {
            let mut state_block = state.block(block.as_ref().header());
            let mut stx = state_block.transaction();
            Register::domain(Domain::new("wonderland".parse().unwrap()))
                .execute(&ALICE_ID, &mut stx)
                .unwrap();
            Register::account(new_sample_account(&ALICE_ID))
                .execute(&ALICE_ID, &mut stx)
                .unwrap();

            let create_asset = Register::asset_definition({
                let __asset_definition_id = asset_definition_id.clone();
                AssetDefinition::numeric(__asset_definition_id.clone())
                    .with_name(__asset_definition_id.name().to_string())
            });
            let fail_isi = Unregister::domain("dummy".parse().unwrap());
            let instructions: [InstructionBox; 2] = [create_asset.into(), fail_isi.into()];
            let trigger = Trigger::new(
                trigger_id.clone(),
                Action::new(
                    instructions,
                    Repeats::Indefinitely,
                    ALICE_ID.clone(),
                    ExecuteTriggerEventFilter::new()
                        .for_trigger(trigger_id.clone())
                        .under_authority(ALICE_ID.clone()),
                ),
            );
            Register::trigger(trigger)
                .execute(&ALICE_ID, &mut stx)
                .unwrap();

            stx.apply();
            state_block.commit().unwrap();
        }

        // Build a detached delta that records the by-call trigger execution.
        let mut delta = DetachedStateTransactionDelta::default();
        let event = ExecuteTriggerEvent {
            trigger_id: trigger_id.clone(),
            authority: ALICE_ID.clone(),
            args: Json::default(),
        };
        delta.execute_trigger_by_call(event);

        // Merge the detached delta and expect rejection; state changes must rollback.
        let block = new_dummy_block_with_payload(|header| {
            header.set_height(NonZeroU64::new(2).unwrap());
        });
        {
            let mut state_block = state.block(block.as_ref().header());
            let result = delta.merge_into(&mut state_block, &ALICE_ID);
            assert!(
                result.is_err(),
                "detached trigger execution should fail and reject the transaction"
            );
        }

        let view = state.view();
        assert!(
            view.world.asset_definition(&asset_definition_id).is_err(),
            "asset definition created by a failing detached trigger must not persist",
        );
    }

    fn build_executor_verdict_program(
        verdict: &Result<(), iroha_data_model::ValidationFail>,
    ) -> Vec<u8> {
        use std::mem::size_of;

        use ivm::{ProgramMetadata, encoding, instruction};
        use norito::codec::Encode as _;

        const LITERAL_HEADER_LEN: usize = 4 + 12;

        let verdict_bytes = verdict.encode();
        let len_size = size_of::<usize>();
        let total_len = len_size
            .checked_add(verdict_bytes.len())
            .expect("encoded blob fits in usize");
        let total_len_u64 = u64::try_from(total_len).expect("encoded blob fits in u64");
        let mut data = total_len_u64.to_le_bytes()[..len_size].to_vec();
        data.extend_from_slice(&verdict_bytes);
        let padded_len = (data.len() + 7) & !7;
        data.resize(padded_len, 0);
        let chunk_count = data.len() / 8;

        let meta = ProgramMetadata {
            version_major: 1,
            version_minor: 0,
            mode: 0,
            vector_length: 0,
            max_cycles: 1_000_000,
            abi_version: 1,
        };
        let mut program = meta.encode();
        program.extend_from_slice(b"LTLB");
        program.extend_from_slice(&(0u32).to_le_bytes());
        program.extend_from_slice(&(0u32).to_le_bytes());
        program.extend_from_slice(
            &(u32::try_from(data.len()).expect("literal length fits")).to_le_bytes(),
        );
        program.extend_from_slice(&data);

        let mut emit = |word: u32| program.extend_from_slice(&word.to_le_bytes());
        emit(encoding::wide::encode_rr(
            instruction::wide::arithmetic::ADD,
            20,
            10,
            0,
        ));
        emit(encoding::wide::encode_rr(
            instruction::wide::arithmetic::ADD,
            21,
            10,
            0,
        ));

        let data_addr = i8::try_from(LITERAL_HEADER_LEN).expect("literal header fits i8");
        emit(encoding::wide::encode_ri(
            instruction::wide::arithmetic::ADDI,
            22,
            0,
            data_addr,
        ));

        for _ in 0..chunk_count {
            emit(encoding::wide::encode_load(
                instruction::wide::memory::LOAD64,
                23,
                22,
                0,
            ));
            emit(encoding::wide::encode_store(
                instruction::wide::memory::STORE64,
                21,
                23,
                0,
            ));
            emit(encoding::wide::encode_ri(
                instruction::wide::arithmetic::ADDI,
                22,
                22,
                8,
            ));
            emit(encoding::wide::encode_ri(
                instruction::wide::arithmetic::ADDI,
                21,
                21,
                8,
            ));
        }

        emit(encoding::wide::encode_rr(
            instruction::wide::arithmetic::ADD,
            10,
            20,
            0,
        ));
        emit(encoding::wide::encode_halt());
        program
    }

    #[test]
    fn execute_called_trigger_respects_executor_validation() {
        use iroha_data_model::{
            ChainId, Level,
            events::execute_trigger::{ExecuteTriggerEvent, ExecuteTriggerEventFilter},
            executor as data_model_executor,
            isi::Log,
            transaction::executable::IvmBytecode,
            trigger::TriggerId,
        };

        let verdict = Err(iroha_data_model::ValidationFail::NotPermitted(
            "executor denied".to_owned(),
        ));
        let bytecode = build_executor_verdict_program(&verdict);
        let raw = data_model_executor::Executor::new(IvmBytecode::from_compiled(bytecode));
        let executor = crate::executor::Executor::UserProvided(
            crate::executor::LoadedExecutor::load(raw).expect("load executor"),
        );

        let domain: Domain = Domain::new("wonderland".parse().unwrap()).build(&ALICE_ID);
        let account = new_sample_account(&ALICE_ID).build(&ALICE_ID);
        let world = World::with([domain], [account], []);
        let mut executor_block = world.executor.block();
        *executor_block.get_mut() = executor;
        executor_block.commit();

        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let state = State::new_with_chain(world, kura, query_handle, ChainId::from("test-chain"));

        let trigger_id: TriggerId = "executor_guarded_trigger".parse().unwrap();
        let trigger = Trigger::new(
            trigger_id.clone(),
            Action::new(
                vec![InstructionBox::from(Log::new(
                    Level::INFO,
                    "trigger log".to_owned(),
                ))],
                Repeats::Indefinitely,
                ALICE_ID.clone(),
                ExecuteTriggerEventFilter::new()
                    .for_trigger(trigger_id.clone())
                    .under_authority(ALICE_ID.clone()),
            ),
        );

        let header = BlockHeader::new(NonZeroU64::new(1).unwrap(), None, None, None, 0, 0);
        let mut state_block = state.block(header);
        {
            let mut stx = state_block.transaction();
            Register::trigger(trigger)
                .execute(&ALICE_ID, &mut stx)
                .unwrap();
            stx.apply();
        }
        state_block.commit().unwrap();

        let header = BlockHeader::new(NonZeroU64::new(2).unwrap(), None, None, None, 0, 0);
        let mut state_block = state.block(header);
        let mut stx = state_block.transaction();
        let event = ExecuteTriggerEvent {
            trigger_id: trigger_id.clone(),
            authority: ALICE_ID.clone(),
            args: Json::default(),
        };
        let err = stx
            .execute_called_trigger(&trigger_id, &event)
            .expect_err("trigger should be rejected by executor");
        match err {
            TransactionRejectionReason::Validation(
                iroha_data_model::ValidationFail::NotPermitted(msg),
            ) => {
                assert!(
                    msg.contains("executor denied"),
                    "unexpected rejection message: {msg}"
                );
            }
            other => panic!("unexpected rejection: {other:?}"),
        }
    }

    #[test]
    fn block_rejects_failing_execute_trigger_and_rolls_back() {
        use std::borrow::Cow;

        use iroha_test_samples::ALICE_KEYPAIR;

        use crate::{block::BlockBuilder, tx::AcceptedTransaction};

        // Seed the world with a domain and ALICE account to author the trigger.
        let domain: Domain = Domain::new("wonderland".parse().unwrap()).build(&ALICE_ID);
        let account = new_sample_account(&ALICE_ID).build(&ALICE_ID);
        let world = World::with([domain], [account], []);

        let kura = Kura::blank_kura_for_testing();
        let query_handle = LiveQueryStore::start_test();
        let mut state = State::new(world, kura, query_handle);
        state.chain_id = ChainId::from("chain");

        let trigger_id: TriggerId = "rollback_trigger_block".parse().unwrap();
        let asset_definition_id: AssetDefinitionId =
            iroha_data_model::asset::AssetDefinitionId::new(
                "wonderland".parse().unwrap(),
                "xor".parse().unwrap(),
            );

        // Tx 1: register the by-call trigger that will fail when executed.
        let create_asset = Register::asset_definition({
            let __asset_definition_id = asset_definition_id.clone();
            AssetDefinition::numeric(__asset_definition_id.clone())
                .with_name(__asset_definition_id.name().to_string())
        });
        let fail_isi = Unregister::domain("dummy".parse().unwrap());
        let instructions: [InstructionBox; 2] = [create_asset.into(), fail_isi.into()];
        let register_trigger = Register::trigger(Trigger::new(
            trigger_id.clone(),
            Action::new(
                instructions,
                Repeats::Indefinitely,
                ALICE_ID.clone(),
                ExecuteTriggerEventFilter::new()
                    .for_trigger(trigger_id.clone())
                    .under_authority(ALICE_ID.clone()),
            ),
        ));
        let register_tx = TransactionBuilder::new(ChainId::from("chain"), ALICE_ID.clone())
            .with_instructions([register_trigger])
            .sign(ALICE_KEYPAIR.private_key());

        // Build and validate a block containing the registration transaction.
        let block = BlockBuilder::new(vec![AcceptedTransaction::new_unchecked(Cow::Owned(
            register_tx,
        ))])
        .chain(0, None)
        .sign(ALICE_KEYPAIR.private_key())
        .unpack(|_| {});

        let mut state_block = state.block(block.header());
        let valid = ValidBlock::validate_unchecked(block.into(), &mut state_block).unpack(|_| {});
        let reg_err = valid.as_ref().error(0).cloned();
        assert!(
            reg_err.is_none(),
            "trigger registration should succeed (reg_err={reg_err:?})"
        );

        // Commit the block effects and ensure no state leaked from the rejected transaction.
        let committed = valid.commit_unchecked().unpack(|_| {});
        let _ = state_block.apply_without_execution(&committed, Vec::new());
        state_block.commit().unwrap();
        let prev_block = committed;

        // Tx 2: attempt to execute the failing trigger by call in the next block.
        let exec_tx = TransactionBuilder::new(ChainId::from("chain"), ALICE_ID.clone())
            .with_instructions([InstructionBox::from(ExecuteTrigger::new(
                trigger_id.clone(),
            ))])
            .sign(ALICE_KEYPAIR.private_key());

        let block = BlockBuilder::new(vec![AcceptedTransaction::new_unchecked(Cow::Owned(
            exec_tx,
        ))])
        .chain(0, Some(prev_block.as_ref()))
        .sign(ALICE_KEYPAIR.private_key())
        .unpack(|_| {});

        let mut state_block = state.block(block.header());
        let valid = ValidBlock::validate_unchecked(block.into(), &mut state_block).unpack(|_| {});
        let exec_err = valid.as_ref().error(0).cloned();

        let committed = valid.commit_unchecked().unpack(|_| {});
        let _ = state_block.apply_without_execution(&committed, Vec::new());
        state_block.commit().unwrap();

        let view = state.view();
        let asset_exists = view.world.asset_definition(&asset_definition_id).is_ok();
        let trigger_present = view.world.triggers().ids().get(&trigger_id).is_some();

        assert!(
            exec_err.is_some(),
            "execute-trigger transaction should be rejected when trigger fails (asset_exists={asset_exists}, trigger_present={trigger_present}, reg_err={reg_err:?}, got {exec_err:?})"
        );
        if let Some(reason) = exec_err {
            match reason {
                TransactionRejectionReason::Validation(
                    ValidationFail::InstructionFailed(InstructionExecutionError::Find(
                        FindError::Domain(_),
                    ))
                    | ValidationFail::NotPermitted(_),
                ) => {}
                other => {
                    panic!("unexpected rejection reason: {other:?}");
                }
            }
        }
        assert!(
            !asset_exists,
            "asset definition created by a failing trigger must not persist after block application",
        );
    }

    #[test]
    fn confidential_digest_respects_activation_height() {
        use iroha_data_model::{
            confidential::ConfidentialStatus,
            proof::{VerifyingKeyId, VerifyingKeyRecord},
            zk::BackendTag,
        };

        let mut world = World::new();
        let id = VerifyingKeyId::new("halo2/ipa", "vk_activation");
        let mut record = VerifyingKeyRecord::new_with_owner(
            1,
            "circuit_activation",
            None,
            "core",
            BackendTag::Halo2IpaPasta,
            "pallas",
            [0x11; 32],
            [0x22; 32],
        );
        record.status = ConfidentialStatus::Proposed;
        record.activation_height = Some(5);
        record.gas_schedule_id = Some("sched_activation".into());
        record.public_inputs_schema_hash = [0x33; 32];
        world.verifying_keys.insert(id.clone(), record.clone());
        world
            .verifying_keys_by_circuit
            .insert((record.circuit_id.clone(), record.version), id.clone());

        let kura = Kura::blank_kura_for_testing();
        let query = LiveQueryStore::start_test();
        let mut state = State::new(world, kura, query);
        state.zk.registry_max_delta_per_block = 10;

        let view = state.view();
        let digest_before = compute_confidential_feature_digest(view.world(), &view.zk, 4);
        assert_eq!(digest_before.vk_set_hash, None);

        let digest_at_activation = compute_confidential_feature_digest(view.world(), &view.zk, 5);
        assert!(digest_at_activation.vk_set_hash.is_some());
    }

    #[test]
    fn confidential_registry_delta_cap_limits_transitions() {
        use iroha_data_model::{
            confidential::ConfidentialStatus,
            proof::{VerifyingKeyId, VerifyingKeyRecord},
            zk::BackendTag,
        };

        let mut world = World::new();
        let ids = [
            VerifyingKeyId::new("halo2/ipa", "vk_alpha"),
            VerifyingKeyId::new("halo2/ipa", "vk_beta"),
        ];
        for (idx, id) in ids.iter().enumerate() {
            let mut record = VerifyingKeyRecord::new_with_owner(
                1,
                format!("circuit_{idx}"),
                None,
                "core",
                BackendTag::Halo2IpaPasta,
                "pallas",
                [0x40 + u8::try_from(idx).expect("vk index fits in u8"); 32],
                [0x50 + u8::try_from(idx).expect("vk index fits in u8"); 32],
            );
            record.status = ConfidentialStatus::Proposed;
            record.activation_height = Some(2);
            record.gas_schedule_id = Some(format!("sched_{idx}"));
            record.public_inputs_schema_hash =
                [0x60 + u8::try_from(idx).expect("vk index fits in u8"); 32];
            world.verifying_keys.insert(id.clone(), record.clone());
            world
                .verifying_keys_by_circuit
                .insert((record.circuit_id.clone(), record.version), id.clone());
        }

        let kura = Kura::blank_kura_for_testing();
        let query = LiveQueryStore::start_test();
        let mut state = State::new(world, kura, query);
        state.zk.registry_max_delta_per_block = 1;

        let header = BlockHeader::new(NonZeroU64::new(2).unwrap(), None, None, None, 0, 0);
        let block = state.block(header);

        let alpha_status = block
            .world
            .verifying_keys
            .get(&ids[0])
            .map(|rec| rec.status)
            .expect("alpha vk present");
        let beta_status = block
            .world
            .verifying_keys
            .get(&ids[1])
            .map(|rec| rec.status)
            .expect("beta vk present");

        assert_eq!(alpha_status, ConfidentialStatus::Active);
        assert_eq!(beta_status, ConfidentialStatus::Proposed);
    }

    fn assemble_ivm_header(code: &[u8]) -> Vec<u8> {
        let mut blob = Vec::with_capacity(16 + code.len());
        blob.extend_from_slice(b"IVM\0");
        blob.push(1); // version major
        blob.push(0); // version minor
        blob.push(0); // mode flags
        blob.push(0); // vector length
        blob.extend_from_slice(&0u64.to_le_bytes()); // max_cycles = 0 (unspecified)
        blob.push(1); // abi_version = 1
        blob.extend_from_slice(code);
        blob
    }

    /// Used to inject faulty payload for testing
    fn new_dummy_block_with_payload(f: impl FnOnce(&mut BlockHeader)) -> CommittedBlock {
        let (leader_public_key, leader_private_key) =
            iroha_crypto::KeyPair::random_with_algorithm(iroha_crypto::Algorithm::BlsNormal)
                .into_parts();
        let peer_id = PeerId::new(leader_public_key);
        let topology = Topology::new(vec![peer_id]);

        ValidBlock::new_dummy_and_modify_header(&leader_private_key, f)
            .commit(&topology)
            .unpack(|_| {})
            .unwrap()
    }

    fn dummy_merge_qc() -> MergeQuorumCertificate {
        MergeQuorumCertificate::new(0, 0, vec![0x01], vec![0xAA], iroha_crypto::Hash::new(b"qc"))
    }

    fn merge_candidate_with_lanes(epoch: u64, count: usize) -> crate::merge::MergeLedgerCandidate {
        let mut lane_snapshots = Vec::with_capacity(count);
        for idx in 0..count {
            let tip = u8::try_from(idx).expect("lane index fits in u8");
            let hint = tip.strict_add(1);
            lane_snapshots.push(MergeLaneSnapshot {
                lane_id: LaneId::new(u32::try_from(idx).expect("lane index fits in u32")),
                dataspace_id: DataSpaceId::new(u64::try_from(idx + 1).expect("dsid fits in u64")),
                lane_block_height: epoch.saturating_add(u64::try_from(idx).expect("height fits")),
                tip_hash: HashOf::from_untyped_unchecked(iroha_crypto::Hash::new([tip])),
                merge_hint_root: iroha_crypto::Hash::new([hint]),
            });
        }
        let merge_hint_roots: Vec<Hash> = lane_snapshots
            .iter()
            .map(|snapshot| snapshot.merge_hint_root)
            .collect();
        let global_state_root = crate::merge::reduce_merge_hint_roots(&merge_hint_roots);
        crate::merge::MergeLedgerCandidate {
            epoch_id: epoch,
            view: 0,
            lane_snapshots,
            global_state_root,
        }
    }

    fn merge_entry_from_candidate(
        candidate: crate::merge::MergeLedgerCandidate,
        merge_qc: MergeQuorumCertificate,
    ) -> MergeLedgerEntry {
        candidate.into_entry(merge_qc)
    }

    fn configure_commit_topology(state: &State, count: usize) -> Vec<KeyPair> {
        let mut peers = Vec::with_capacity(count);
        let mut keypairs = Vec::with_capacity(count);
        for _ in 0..count {
            let keypair = KeyPair::random_with_algorithm(iroha_crypto::Algorithm::BlsNormal);
            peers.push(PeerId::new(keypair.public_key().clone()));
            keypairs.push(keypair);
        }
        let mut topo = state.commit_topology.block();
        topo.clear();
        for peer in peers {
            topo.push(peer);
        }
        topo.commit();
        seed_consensus_keys_with_pops(state, &keypairs);
        keypairs
    }

    #[test]
    fn apply_without_execution_updates_commit_topology_from_world_peers() {
        let kura = Kura::blank_kura_for_testing();
        let query = LiveQueryStore::start_test();
        let state = State::new_for_testing(World::default(), kura, query);

        let keypairs = configure_commit_topology(&state, 4);
        let base_topology: Vec<_> = keypairs
            .iter()
            .map(|kp| PeerId::new(kp.public_key().clone()))
            .collect();
        let new_peer = PeerId::new(
            KeyPair::random_with_algorithm(Algorithm::BlsNormal)
                .public_key()
                .clone(),
        );

        let block = BlockBuilder::new(vec![dummy_accepted_transaction()])
            .chain(0, None)
            .sign(keypairs[0].private_key())
            .unpack(|_| {});
        let signed_block: SignedBlock = block.into();
        let mut state_block = state.block(signed_block.header());

        {
            let mut peers = state_block.world.peers_mut_for_testing().transaction();
            peers.clear();
            peers.extend(base_topology.clone());
            peers.push(new_peer.clone());
            peers.apply();
        }

        let valid = ValidBlock::validate_unchecked(signed_block, &mut state_block).unpack(|_| {});
        let committed = valid.commit_unchecked().unpack(|_| {});
        let prev_hash = committed.as_ref().hash();
        let _ = state_block.apply_without_execution(&committed, base_topology.clone());
        state_block.commit().expect("commit state block");

        let mut expected_topology = Topology::new(base_topology.clone());
        let mut world_peers = base_topology.clone();
        world_peers.push(new_peer);
        expected_topology.block_committed(world_peers, prev_hash);
        let expected = expected_topology.as_ref().to_vec();

        let view = state.view();
        let actual: Vec<_> = view.commit_topology().iter().cloned().collect();
        assert_eq!(actual, expected);
        let prev: Vec<_> = view.prev_commit_topology().iter().cloned().collect();
        assert_eq!(prev, base_topology);
    }

