    fn merge_signers_bitmap(
        signers: &BTreeSet<iroha_data_model::block::consensus::ValidatorIndex>,
        roster_len: usize,
    ) -> Vec<u8> {
        if roster_len == 0 {
            return Vec::new();
        }
        let mut bitmap = vec![0u8; roster_len.div_ceil(8)];
        for signer in signers {
            let Ok(idx) = usize::try_from(*signer) else {
                continue;
            };
            if idx >= roster_len {
                continue;
            }
            let byte = idx / 8;
            let bit = idx % 8;
            bitmap[byte] |= 1u8 << bit;
        }
        bitmap
    }

    fn merge_qc_for_candidate(
        state: &State,
        candidate: &crate::merge::MergeLedgerCandidate,
        keypairs: &[KeyPair],
        signers: &[usize],
    ) -> MergeQuorumCertificate {
        let message_digest = crate::merge::merge_qc_message_digest(&state.chain_id, candidate);
        let mut signers_set = BTreeSet::new();
        let mut signature_payloads = Vec::with_capacity(signers.len());
        for idx in signers {
            let idx_u32 = u32::try_from(*idx).expect("signer index fits in u32");
            signers_set.insert(idx_u32);
            let signature = Signature::new(keypairs[*idx].private_key(), message_digest.as_ref());
            signature_payloads.push(signature.payload().to_vec());
        }
        let signature_refs: Vec<&[u8]> = signature_payloads.iter().map(Vec::as_slice).collect();
        let aggregate_signature = iroha_crypto::bls_normal_aggregate_signatures(&signature_refs)
            .expect("aggregate merge signatures");
        let signers_bitmap = merge_signers_bitmap(&signers_set, keypairs.len());
        MergeQuorumCertificate::new(
            candidate.view,
            candidate.epoch_id,
            signers_bitmap,
            aggregate_signature,
            message_digest,
        )
    }

    #[test]
    fn commit_merge_entry_rejects_empty_entry() {
        let kura = Kura::blank_kura_for_testing();
        let query = LiveQueryStore::start_test();
        let state = State::new(World::default(), kura, query);

        let entry = MergeLedgerEntry {
            epoch_id: 1,
            lane_snapshots: Vec::new(),
            global_state_root: iroha_crypto::Hash::new(b"root"),
            merge_qc: dummy_merge_qc(),
        };

        let err = state
            .commit_merge_entry(entry)
            .expect_err("empty merge entry must be rejected");
        assert!(matches!(err, MergeLedgerCommitError::EmptyEntry));
    }

    #[test]
    fn commit_merge_entry_rejects_unsorted_lane_snapshots() {
        let kura = Kura::blank_kura_for_testing();
        let query = LiveQueryStore::start_test();
        let state = State::new(World::default(), kura, query);

        let candidate = merge_candidate_with_lanes(1, 2);
        let mut entry = merge_entry_from_candidate(candidate, dummy_merge_qc());
        entry.lane_snapshots.reverse();

        let err = state
            .commit_merge_entry(entry)
            .expect_err("unsorted lane snapshots must be rejected");
        assert!(matches!(
            err,
            MergeLedgerCommitError::LaneSnapshotOrderViolation { .. }
        ));
    }

